/* ============================================================
   Strings of Hope — Music Theory course
   A six-unit curriculum adapted from
   "Music Theory for the 21st-Century Classroom" by Robert Hutchinson
   (University of Puget Sound, GFDL), "Understanding Basic Music Theory" by
   Catherine Schmidt-Jones (CC BY-SA 4.0), and "Open Music Theory," v.2
   (ed. Gotham, Gullings, Hamm, Hughes, Jarvis, Lavengood & Peterson; CC BY-SA 4.0).

   Every lesson carries a `harp` note mapping the concept to the LEVER HARP.
   Every chapter carries a `quiz` (check-your-understanding Q&A).
   Foundational lessons carry a `staff` (VexFlow EasyScore notation).
   ============================================================ */

const THEORY_SOURCE = 'Adapted from “Music Theory for the 21st-Century Classroom” by Robert Hutchinson (GFDL) and “Understanding Basic Music Theory” by Catherine Schmidt-Jones (CC BY-SA 4.0).';

/* visual:'keyboard' draws a one-octave keyboard. staff:{clef,key,notes} draws notation.
   harp: the lever-harp mapping. action:{label,view} links to a tool. quiz:[{q,a}] per chapter. */
const THEORY_COURSE = [
  /* ===================== SEMESTER 1 — FUNDAMENTALS ===================== */
  { sem:1, title:'Fundamentals', sub:'Reading & writing music', chapters:[
    { n:1, title:'Basic Concepts', quiz:[
        {q:'How many letter names does the musical alphabet use before repeating?', a:'Seven — A B C D E F G — then it starts again an octave higher.'},
        {q:'What does a sharp (♯) do to a pitch, and how does a lever harp produce one?', a:'It raises the pitch a half step. On a lever harp you engage that string’s lever, which shortens it a half step.'},
        {q:'Name the two names for the black key between C and D.', a:'C♯ and D♭ — they are enharmonic (same sound, different spelling).'},
      ], lessons:[
      { h:'Pitch & the keyboard', body:'<b>Pitch</b> is how high or low a note sounds. On a piano’s 88 keys, notes to the right sound higher, notes to the left lower. The note names use only seven letters — <b>A B C D E F G</b> — then repeat. That repeating set is the “musical alphabet.”', visual:'keyboard',
        harp:'On your harp the same seven letters climb string by string — longest strings lowest, shortest highest. Most lever harps colour <b>C strings red</b> and <b>F strings blue/black</b> so your eye finds its place instantly, the way a pianist uses the groups of black keys.',
        action:{label:'Tune your harp →', view:'tuner'} },
      { h:'The staff & clefs', body:'Notes are written on a five-line <b>staff</b>. A <b>clef</b> fixes the lines to pitches. <b>Treble clef</b> lines are E-G-B-D-F, spaces F-A-C-E. <b>Bass clef</b> lines are G-B-D-F-A, spaces A-C-E-G. Joined by a brace they make the <b>grand staff</b> of piano music.',
        harp:'Harp music is written on the <b>same grand staff</b> as piano — right hand reads treble, left hand reads bass. Middle C (the red string nearest the middle) is your anchor between the two staves, exactly as it is for a pianist.' },
      { h:'Octave registers', body:'The same letter repeats in higher and lower <b>octaves</b>. We number them: <b>C4</b> is “middle C,” the reference point. The register number changes after B (B4 is followed by C5). On the harp this is your map up and down the strings.',
        harp:'Count octaves by the <b>red C strings</b>: each red string starts a new register. A 34-string lever harp spans about <b>C1 to A6</b> — roughly five octaves — so finding “C4” means finding the right red string, not just any C.' },
      { h:'Accidentals', body:'<b>Accidentals</b> raise or lower a note. <b>♯ sharp</b> raises a half step; <b>♭ flat</b> lowers a half step; <b>𝄪 / 𝄫</b> move a whole step; <b>♮ natural</b> cancels them. Raising a string a half step is exactly what a harp lever does.',
        harp:'This is the <b>defining fact of the lever harp</b>: a lever only ever <b>raises</b> its string a half step. So if a string is tuned to E♭, its lever gives you E♮; tuned to E♮, the lever gives E♯ (=F). You get sharps by flipping up — you never get a flat below the string’s tuned pitch without retuning.',
        action:{label:'See your levers →', view:'levers'} },
      { h:'Enharmonic notes', body:'C♯ and D♭ sound identical but are spelled differently — these are <b>enharmonic</b> notes. Every black key has two names (C♯=D♭, F♯=G♭…), and even white keys can be respelled. Spelling depends on the key you’re in.',
        harp:'A lever gives you the <b>raised</b> spelling. Engaging the F lever physically produces F♯ — but if the music asks for G♭, that very same string and sound is your only option. On a lever harp you choose the <b>pitch</b>; the page chooses the <b>spelling</b>.' },
    ]},
    { n:2, title:'Major Scales & Keys', quiz:[
        {q:'Spell the step pattern of a major scale.', a:'W–W–H–W–W–W–H (whole, whole, half, whole, whole, whole, half).'},
        {q:'In what order are sharps added to key signatures?', a:'F–C–G–D–A–E–B (flats are the reverse: B–E–A–D–G–C–F).'},
        {q:'If your harp is tuned to E♭ major (all levers down), how do you get to B♭ major?', a:'Raise the A strings (engage the A levers). E♭ major has B♭, E♭, A♭; B♭ major has only B♭, E♭ — so you naturalise the A♭→A♮. One lever bank and you’re in B♭, the next key clockwise on the circle of fifths.'},
      ], lessons:[
      { h:'Half steps & whole steps', body:'A <b>half step</b> is the distance to the very next key. A <b>whole step</b> is two half steps. These two distances are the building blocks of every scale.', visual:'keyboard',
        harp:'On the harp a half step isn’t an adjacent string — it’s <b>one string with its lever engaged</b>. Adjacent strings are already a whole or half step apart depending on where you are in the scale, because the strings are tuned diatonically, not chromatically like piano keys.' },
      { h:'The major scale', body:'A <b>major scale</b> is a fixed pattern of steps: <b>W–W–H–W–W–W–H</b>. Think of it as two matching four-note halves (tetrachords) joined by a whole step. Every major scale uses each letter once, in order — so D major is D-E-F♯-G-A-B-C♯.',
        staff:{clef:'treble', key:'C', notes:'C4/8, D4, E4, F4, G4, A4, B4, C5'},
        harp:'Set the right levers and a major scale becomes a <b>glissando</b> — sweep your fingernail across the open strings and the scale rings out. That single gesture is the lever harp’s signature sound, and it only works because you pre-set the key with the levers.' },
      { h:'Major key signatures', body:'Rather than write the same sharps or flats repeatedly, we collect them into a <b>key signature</b>. Sharps are added F-C-G-D-A-E-B; flats in reverse. The <b>circle of fifths</b> orders the keys: clockwise adds a sharp, counter-clockwise adds a flat.',
        harp:'A key signature is a <b>lever recipe</b>. Tuned to E♭ (3 flats), all-levers-down already gives you E♭ major. Each clockwise key on the circle just adds one more lever to engage. Pre-set that recipe before you play and the whole piece sits under your hands.',
        action:{label:'Open the Modes wheel →', view:'modes'} },
    ]},
    { n:3, title:'Minor Scales & Keys', quiz:[
        {q:'What note does harmonic minor raise compared with natural minor, and why?', a:'The 7th — to create a leading tone that pulls strongly up to the tonic for a stronger cadence.'},
        {q:'What is the relative minor of C major?', a:'A minor — it shares the same key signature (no sharps or flats), starting a minor third lower.'},
        {q:'Why is the raised 7th of harmonic minor awkward on a lever harp in a fast passage?', a:'It needs a lever flipped mid-piece by a free hand; many harpists pre-set it or rework the passage, since you can’t change it instantly like a pedal.'},
      ], lessons:[
      { h:'The three minor scales', body:'Minor comes in three flavours. <b>Natural minor</b>: W-H-W-W-H-W-W (the Aeolian sound). <b>Harmonic minor</b> raises the 7th for a stronger pull home (and a dramatic 1½-step leap). <b>Melodic minor</b> raises the 6th and 7th going up, and lowers them coming down.',
        harp:'Natural minor is the harpist’s friend — set the levers once and the whole scale glissandos freely. Harmonic and melodic minor need a <b>lever change mid-scale</b> for that raised 7th (and 6th), so harpists often pre-engage them or choose passages that don’t fight the open strings.' },
      { h:'Relative & parallel minor', body:'Every major key shares its key signature with a <b>relative minor</b> a minor third below (C major ↔ A minor). A <b>parallel minor</b> starts on the same note (C major ↔ C minor) but has its own signature. Relative = same notes, different home; parallel = same home, different notes.',
        harp:'Relative minor is <b>free</b> on the harp — C major and A minor use the identical lever setting, so you can drift between them with no lever changes at all. Switching to the parallel minor (C major → C minor) means re-flatting three strings: a deliberate lever reset, not a casual move.' },
      { h:'Scale-degree names', body:'Each step has a name and a job: 1 <b>tonic</b> (home), 2 supertonic, 3 mediant, 4 <b>subdominant</b>, 5 <b>dominant</b> (the pull home), 6 submediant, 7 <b>leading tone</b> (leans up to tonic). These names drive every chord you build.',
        harp:'Learn to feel these by string colour: your <b>tonic</b> is wherever you call home, the <b>dominant</b> a fifth above (a comfortable hand-span), and the <b>leading tone</b> is usually the string you’ll engage a lever on to sharpen in minor keys.' },
    ]},
    { n:4, title:'Rhythm', quiz:[
        {q:'How many eighth notes equal one whole note?', a:'Eight. (Whole = 2 halves = 4 quarters = 8 eighths = 16 sixteenths.)'},
        {q:'What does the lower number of a time signature tell you?', a:'Which note value gets one beat (4 = quarter note, 8 = eighth note).'},
        {q:'Why must a harpist plan damping into a rhythm?', a:'Strings keep ringing after they’re plucked, so a written rest only becomes silence if you place fingers/palm back on the strings to stop them.'},
      ], lessons:[
      { h:'Durations & the beat', body:'Note values divide time: a <b>whole note</b> = 2 halves = 4 quarters = 8 eighths = 16 sixteenths. A <b>dot</b> adds half of a note’s value. A <b>tie</b> joins two notes into one sustained sound; a <b>rest</b> is measured silence.',
        harp:'A harp string sustains on its own, so a <b>tie</b> is effortless — just don’t replay the string. A <b>rest</b> is the hard part: silence only happens when you <b>damp</b> (touch the ringing strings to stop them). On the harp, rhythm is as much about stopping notes as starting them.' },
      { h:'Time signatures & meter', body:'The <b>time signature</b> tells you beats per measure and which note gets the beat. <b>Simple meters</b> divide the beat in two (4/4); <b>compound meters</b> divide it in three (6/8, felt as two big beats of three). <b>Tuplets</b> like triplets borrow a different division.',
        harp:'Compound meters (6/8, 9/8) and rolling triplets are deeply harp-idiomatic — the lilting arpeggio patterns harps are loved for live naturally in those meters. Use the app’s rhythm engine to internalise the pulse before adding the notes.',
        action:{label:'Feel it with the Rhythm engine →', view:'rhythm'} },
    ]},
    { n:5, title:'Intervals', quiz:[
        {q:'How do you find the numeric size of an interval?', a:'Count letter names inclusively from the lower to the upper note (C up to G = 1-2-3-4-5 = a fifth).'},
        {q:'Which intervals come in “perfect” quality?', a:'Unisons, fourths, fifths, and octaves.'},
        {q:'How comfortably does a perfect fifth sit under one harp hand?', a:'Very comfortably — root and fifth are a natural hand-span apart, the basis of harp “open fifth” accompaniments and rolled chords.'},
      ], lessons:[
      { h:'What is an interval?', body:'An <b>interval</b> is the distance between two notes. Name it by counting letter names inclusively (C up to G = a 5th: C-D-E-F-G), then add a quality.',
        harp:'On the harp you can literally <b>see</b> intervals as string gaps. A third skips one string, a fifth skips three. Harpists learn to “read the gap” with their fingers as much as with their eyes.' },
      { h:'Quality: perfect, major, minor', body:'Unisons, 4ths, 5ths and octaves come as <b>perfect</b>. 2nds, 3rds, 6ths and 7ths come as <b>major</b> or <b>minor</b> (minor is a half step smaller). Build from the major scale of the lower note and every interval up to a scale degree is major or perfect.',
        staff:{clef:'treble', key:'C', notes:'(C4 E4)/h, (C4 G4)/h'},
        harp:'Because your strings are pre-tuned to a key, a “third” on the harp is automatically major or minor depending on <b>where</b> in the scale you play it — no lever needed. The instrument hands you the diatonic qualities for free.' },
      { h:'Augmented, diminished & inversion', body:'Widen a perfect/major interval by a half step → <b>augmented</b>; shrink it → <b>diminished</b>. <b>Inversion</b> flips the two notes: a 3rd inverts to a 6th, perfect stays perfect, major↔minor, aug↔dim (numbers add to 9).',
        harp:'Augmented and diminished intervals usually require a <b>lever</b> to bend one note out of the key — which is why chromatic harmony asks more of a lever harpist than diatonic music. Inversions, by contrast, are free: just move the lower note up an octave to the next same-letter string.' },
    ]},
    { n:6, title:'Triads', quiz:[
        {q:'What two intervals stack to make a major triad? A minor triad?', a:'Major = major 3rd + minor 3rd. Minor = minor 3rd + major 3rd.'},
        {q:'What is a slash chord like C/E?', a:'A C major triad with E (its third) in the bass — i.e. first inversion.'},
        {q:'Why are rolled (arpeggiated) triads so natural on the harp?', a:'The fingers fall on consecutive available strings; rolling them root-up is the harp’s most idiomatic way to voice a chord.'},
      ], lessons:[
      { h:'Building triads', body:'A <b>triad</b> stacks two thirds: root, third, fifth. Four qualities: <b>major</b> (M3+m3), <b>minor</b> (m3+M3), <b>diminished</b> (m3+m3), <b>augmented</b> (M3+M3). These are the harmonic colours under almost every song.',
        staff:{clef:'treble', key:'C', notes:'(C4 E4 G4)/q, (C4 Eb4 G4), (C4 Eb4 Gb4), (C4 E4 G#4)'},
        harp:'A triad is three strings with one skipped between each — a shape your hand memorises. Major and minor triads in your set key need <b>no levers</b>; the diminished and augmented colours usually need one lever to bend the 3rd or 5th.' },
      { h:'Lead-sheet symbols & inversions', body:'Pop and jazz name chords with <b>lead-sheet symbols</b>: C, Cm, C°, C+. When a note other than the root is in the bass it’s <b>inverted</b> — a slash chord (C/E). “Sus” chords replace the third for an open colour.',
        harp:'Inversions are a harpist’s secret to smooth playing: choosing C/E or C/G keeps your hand in one comfortable region instead of leaping. Sus chords (no third) are pure open strings — wonderfully resonant and lever-free.',
        action:{label:'Build chords in Scales →', view:'scales'} },
    ]},
    { n:7, title:'Roman Numerals & Cadences', quiz:[
        {q:'In a major key, which diatonic triads are minor?', a:'ii, iii, and vi (I, IV, V are major; vii° is diminished).'},
        {q:'What two chords make an authentic cadence, and which is the strongest form?', a:'V→I; the Perfect Authentic Cadence (PAC), with both chords in root position and the tonic on top.'},
        {q:'Which cadence is the “amen,” and why does it suit the harp?', a:'The plagal cadence IV→I — both chords usually sit in the open key, so it rings out with no lever changes.'},
      ], lessons:[
      { h:'Diatonic chords & Roman numerals', body:'Build a triad on each scale degree → the key’s seven <b>diatonic chords</b>. Label them with <b>Roman numerals</b> — uppercase major (I, IV, V), lowercase minor (ii, iii, vi), ° diminished (vii°). In major: I ii iii IV V vi vii°.',
        harp:'Once your levers set a key, all seven diatonic chords are available with <b>no further lever changes</b> — you just move your triad shape to different strings. This is why playing “in key” feels effortless on a lever harp and why modulating feels like work.' },
      { h:'Cadences', body:'A <b>cadence</b> is musical punctuation. <b>Authentic</b> (V→I) is a full stop; a <b>PAC</b> is strongest. <b>Half cadence</b> (…→V) is a comma. <b>Plagal</b> (IV→I) is the “amen.” <b>Deceptive</b> (V→vi) surprises. Cadences shape phrases.',
        staff:{clef:'treble', key:'C', notes:'(B3 D4 G4)/h, (C4 E4 G4)/h'},
        harp:'Practise V→I as a <b>rolled</b> cadence: arpeggiate the dominant, then settle into a fuller, lower tonic. The harp’s long sustain makes plagal and authentic cadences glow — let the final tonic ring rather than damping it.' },
    ]},
    { n:8, title:'Seventh Chords', quiz:[
        {q:'What makes the dominant seventh (V7) want to resolve?', a:'Its tritone — between the leading tone and the 7th — pulls inward: leading tone up to tonic, 7th down a step.'},
        {q:'Spell the diatonic seventh chords of C major in order.', a:'Cmaj7, Dm7, Em7, Fmaj7, G7, Am7, Bø7.'},
        {q:'How does a harpist usually voice a four-note seventh chord?', a:'Often by rolling it, or by splitting it between hands (root in the left, the upper three in the right) to keep it playable with four fingers.'},
      ], lessons:[
      { h:'Adding the seventh', body:'Stack one more third on a triad → a <b>seventh chord</b>: richer, more restless. Key types: <b>major 7th</b> (lush), <b>dominant 7th</b> (V7, wants to resolve), <b>minor 7th</b>, <b>half-diminished</b> (ø7), <b>fully diminished</b> (°7). The V7’s tritone drives music home.',
        staff:{clef:'treble', key:'C', notes:'(G3 B3 D4 F4)/w'},
        harp:'Four notes can crowd four fingers, so harpists love to <b>roll</b> seventh chords or omit the fifth (root–3rd–7th still says everything). The half- and fully-diminished sevenths almost always need a lever, since they bend notes outside your set key.' },
      { h:'Diatonic seventh chords', body:'Built on each degree of a major key: Imaj7 ii7 iii7 IVmaj7 V7 vi7 viiø7. The <b>V7</b> is the workhorse — its 3rd is the leading tone and its 7th leans down a step, both resolving into the tonic chord.',
        harp:'In your set key, all seven seventh-chords are lever-free — a whole jazz-coloured palette with no lever changes. Try a <b>ii7–V7–Imaj7</b> entirely on open strings to feel how much colour the harp gives you for free.' },
    ]},
  ]},

  /* ===================== SEMESTER 2 — HARMONY, MELODY & FORM ===================== */
  { sem:2, title:'Harmony, Melody & Form', sub:'How music moves & is shaped', chapters:[
    { n:9, title:'Harmonic Progression & Function', quiz:[
        {q:'Spell the full circle-of-fifths progression in major.', a:'I–IV–vii°–iii–vi–ii–V–I — the bass descends a fifth (or rises a fourth) each step.'},
        {q:'Name Hutchinson’s four harmonic functions.', a:'Tonic, Tonic-prolongation, Pre-dominant, and Dominant.'},
        {q:'Why does the circle-of-fifths progression feel “inevitable” on the harp?', a:'Each chord’s root is a fifth/fourth away — a fixed hand-span — so the left hand walks a repeating, predictable shape down the strings.'},
      ], lessons:[
      { h:'The circle-of-fifths progression', body:'The grand progression of tonal music moves by descending fifths: <b>I–IV–vii°–iii–vi–ii–V–I</b>. A Baroque stalwart (Bach, Handel, Vivaldi), it has a <b>feeling of inevitability</b> because the bass falls a fifth each chord — a <b>harmonic sequence</b>. You hear pieces of it everywhere, from “Fly Me to the Moon” to “I Will Survive.”',
        harp:'This is pure muscle memory on the harp: the left-hand root jumps a fixed <b>fifth-down / fourth-up</b> shape over and over. Set your key with the levers and the whole circle plays without a single lever change — a perfect harp étude.' },
      { h:'Harmonic rhythm', body:'<b>Harmonic rhythm</b> is how long each chord lasts. One chord per bar (whole-note harmonic rhythm) feels spacious; two per bar feels driving. Composers speed it up to build energy, slow it down to settle.',
        harp:'Slow harmonic rhythm is the harp’s natural home — one rich, rolled chord can ring for a whole bar while the melody floats above. When you want momentum, change the chord more often or break it into a faster arpeggiated pattern.' },
      { h:'Shorter progressions: ii–V–I & its cousins', body:'Slices of the circle run countless songs. <b>ii–V–I</b> is the heart of jazz. The four-chord <b>vi–ii–V–I</b> rotates into <b>I–vi–ii–V</b> (the “1950s progression”) and <b>ii–V–I–vi</b> (a jazz “turnaround”). Add iii → iii–vi–ii–V.',
        harp:'These four-chord loops are ideal harp practice: pick one set key, learn the four left-hand root positions, and improvise melodies on the open strings above. No levers, endless music.' },
      { h:'Harmonic function: the four families', body:'Chords sort into <b>functions</b>. <b>Tonic</b> (I): home. <b>Tonic-prolongation</b> (iii, vi): extends the tonic. <b>Pre-dominant</b> (IV, ii): builds tension. <b>Dominant</b> (V, vii°): demands resolution to I. In minor, the <b>subtonic VII</b> has one job — lead to III.',
        harp:'Hear functions as <b>distances from home</b> under your hands: tonic where you rest, pre-dominant a step of departure, dominant the leaning chord that wants to fall back. Try it over a drone in the meditation tool to feel each function’s pull.' },
      { h:'The harmonic flowchart', body:'Hutchinson’s map of motion: <b>Tonic → Tonic-Prolongation → Pre-Dominant → Dominant → Tonic</b>. The simplest journeys are <b>I–V–I</b> (the most elemental of all) and <b>I–ii–V–I / I–IV–V–I</b>. Almost every progression is a path through this flowchart.',
        harp:'Map the flowchart onto string regions once and you can <b>compose at the harp</b> without reading: leave home (pre-dominant), lean (dominant), return (tonic). The instrument becomes a map of harmonic function.' },
      { h:'The famous loops', body:'Two four-chord loops power much of popular music. The <b>“best-seller” progression</b> <b>I–V–vi–IV</b> underlies hundreds of hits. The <b>i–VII–VI–VII</b> loop gives a darker, modal, anthemic feel.',
        harp:'Both loops are lever-free in the right key and gorgeous when rolled. Set E♭ or C, learn the four roots, and you can busk almost any pop song. The i–VII–VI–VII loop is especially harp-friendly in natural-minor tunings.',
        action:{label:'Hear functions over a drone →', view:'meditation'} },
    ]},
    { n:10, title:'Non-Chord Tones', quiz:[
        {q:'How is a passing tone approached and left?', a:'By step in the same direction — it fills the gap between two chord tones.'},
        {q:'How does a suspension differ from a retardation?', a:'Both hold a note over a chord change; a suspension resolves down by step, a retardation resolves up.'},
        {q:'Why are passing and neighbor tones so natural on the harp?', a:'They’re stepwise — adjacent open strings — so they flow without any lever change.'},
      ], lessons:[
      { h:'Notes outside the chord', body:'<b>Non-chord tones</b> (NCTs) are melody notes not in the chord underneath — they create motion and beauty. Each is defined by how you <b>approach</b> and <b>leave</b> it (by step or leap).',
        harp:'On a diatonic harp, most NCTs are simply <b>the next string over</b> — they live inside your set key, so you decorate a melody freely without touching a lever.' },
      { h:'The stepwise family', body:'<b>Passing tones</b> step between two chord tones; <b>neighbor tones</b> step away and back; the <b>double neighbor</b> circles a note from both sides; the <b>incomplete neighbor</b> only steps away or only returns.',
        harp:'These are the building blocks of harp ornamentation — and of glissando runs, which are nothing but a cascade of passing tones across the open strings. Master them and your melodies stop sounding “blocky.”' },
      { h:'Suspensions, leaps & pedals', body:'A <b>suspension</b> holds a note over a chord change, then resolves down (a <b>retardation</b> up). The <b>appoggiatura</b> leaps in and steps out; the <b>escape tone</b> steps in and leaps out; the <b>anticipation</b> arrives early. A <b>pedal point</b> sustains one note while harmony changes around it.',
        harp:'<b>Pedal points are a harp superpower</b>: because strings sustain, you can let a low tonic ring (or repeat a bass string) while the harmony shifts above — a built-in drone. Suspensions, too, exploit the harp’s sustain beautifully: let the held note linger, then resolve.' },
    ]},
    { n:11, title:'Melodic Analysis', quiz:[
        {q:'What is a motive?', a:'The smallest memorable musical idea — a short fingerprint a composer reuses and transforms.'},
        {q:'Name three ways to transform a motive.', a:'Any of: inversion, retrograde, augmentation, diminution, intervallic change, ornamentation, extension, fragmentation.'},
        {q:'How can a harpist transform a motive without any lever changes?', a:'By inversion, retrograde, augmentation/diminution, or moving it to a new octave/string region — all stay within the set key.'},
      ], lessons:[
      { h:'The motive', body:'The <b>motive</b> is the smallest memorable musical idea — a fingerprint a composer reuses and transforms (Beethoven’s four-note “fate” motive). Great melodies are usually one or two motives, varied with imagination.',
        harp:'Find a two- or three-string shape you love and treat it as your motive. Because the harp lays the scale out visually, you can <b>see</b> where to move it next — the instrument is a melody-composition tool.' },
      { h:'Transforming a motive', body:'A motive can be altered by <b>inversion</b> (upside-down), <b>retrograde</b> (backwards), <b>augmentation/diminution</b> (slower/faster), <b>intervallic change</b>, <b>ornamentation</b>, <b>extension</b> and <b>fragmentation</b>.',
        harp:'Inversion on the harp is literally mirroring your finger pattern up the strings instead of down. Augmentation just means letting each string ring longer — effortless given the harp’s sustain.' },
      { h:'Subphrase & phrase', body:'Motives combine into a <b>subphrase</b> (phrase member), and subphrases into a <b>phrase</b> — a complete musical thought ending in a cadence. Hearing this layered structure is the secret to whole-feeling melodies.',
        harp:'Shape phrases with <b>dynamics and damping</b>: let a phrase grow as you climb the strings, then gently damp the bass at the cadence so the next phrase breathes. The harp rewards this kind of shaping.',
        action:{label:'Hear it in the Modes journey →', view:'learn'} },
    ]},
    { n:12, title:'Form in Popular Music', quiz:[
        {q:'What does AABA describe?', a:'A 32-bar song form — two A sections, a contrasting B (the “bridge”), then a return of A.'},
        {q:'Spell the basic 12-bar blues progression.', a:'I–I–I–I / IV–IV–I–I / V–IV–I–I (with variants).'},
        {q:'What does it mean for a section to be harmonically “open,” and how can a harp signal it?', a:'It ends on a dominant, leaning forward; a harpist can leave that V chord ringing undamped to pull the ear into the next section.'},
      ], lessons:[
      { h:'Section-based song forms', body:'Popular songs are built from labelled sections: <b>verse–chorus</b> (the modern default), the 32-bar <b>AABA</b> (the Great American Songbook), and <b>ABAC</b>. Letters mark which music returns and which is new.',
        harp:'Plan your <b>lever setting around the whole form</b>: if the bridge briefly needs an accidental, decide now whether to pre-tune it in, flip a lever between sections, or arrange around it. Form drives your lever strategy.' },
      { h:'The 12-bar blues & open/closed sections', body:'The <b>12-bar blues</b> (I–IV–I–V–IV–I) is one of the most influential forms in all of music. Sections can be harmonically <b>closed</b> (cadence home, settled) or <b>open</b> (end on a dominant, leaning forward) — how a song builds momentum.',
        harp:'The blues’ dominant-seventh colours often need a lever for the bluesy ♭7, but a plain I–IV–V blues sits comfortably on open strings. Use the harp’s sustain on the IV and V to give that lazy, rolling blues feel.' },
    ]},
    { n:13, title:'Phrases in Combination', quiz:[
        {q:'Describe the proportions of a sentence.', a:'Short basic idea, its repetition/variation, then a longer continuation to a cadence — a 1+1+2 feeling of acceleration.'},
        {q:'What two cadences typically end the antecedent and consequent of a period?', a:'Antecedent ends weakly (often a half cadence — the “question”); consequent ends strongly (a PAC — the “answer”).'},
        {q:'What is an elision?', a:'An overlap where the cadence that ends one phrase is also the downbeat that begins the next.'},
      ], lessons:[
      { h:'The sentence', body:'A <b>sentence</b> states a short <b>basic idea</b>, repeats or varies it, then drives through a longer <b>continuation</b> to a cadence. Its 1+1+2 proportion gives a feeling of acceleration toward the goal.',
        harp:'Voice the basic idea sparely (single notes or open fifths), then thicken the continuation with rolled chords and a rising line — the harp’s dynamic and textural range makes that acceleration vivid.' },
      { h:'The period', body:'A <b>period</b> is a question-and-answer pair: an <b>antecedent</b> ending weakly (a half cadence — the “question”), answered by a <b>consequent</b> ending strongly (a PAC). It’s the most balanced shape in tonal music.',
        harp:'Mark the “question” by leaving the dominant <b>ringing, undamped</b>; answer it by settling firmly home and letting the tonic resonate. The harp’s sustain makes the antecedent/consequent dialogue audible.' },
      { h:'Larger combinations', body:'Phrases combine into <b>double periods</b>, <b>asymmetrical periods</b>, <b>phrase groups</b> and <b>phrase chains</b>. An <b>elision</b> overlaps two phrases — one phrase’s cadence is the next phrase’s downbeat — propelling the music forward.',
        harp:'Elisions are thrilling on the harp: don’t damp the cadence — let it become the launch of the next phrase, so the sound never stops flowing. The instrument’s ring is built for this seamless momentum.' },
    ]},
    { n:14, title:'Accompanimental Textures', quiz:[
        {q:'Define homophonic and polyphonic texture.', a:'Homophonic = melody plus chordal accompaniment; polyphonic = independent melodic lines woven together.'},
        {q:'Name two accompaniment patterns.', a:'Any of: chorale/block chords, arpeggiated (broken chords), afterbeats/offbeats, walking bass.'},
        {q:'Which accompaniment texture is most idiomatic to the harp, and why?', a:'Arpeggiated (broken-chord) texture — the fingers naturally roll across consecutive strings, the harp’s signature sound.'},
      ], lessons:[
      { h:'What is texture?', body:'<b>Texture</b> is how the musical lines combine. <b>Monophonic</b> = one line alone; <b>homophonic</b> = melody plus chordal accompaniment; <b>polyphonic</b> = independent melodies woven together (counterpoint).',
        harp:'A harpist can sustain three or four textures at once — bass drone, broken-chord middle, melody on top — because the strings keep ringing. Few instruments do homophony this richly with just two hands.' },
      { h:'Accompaniment patterns', body:'Core patterns: <b>chorale</b> (block chords, hymn-like), <b>arpeggiated</b> (broken chords), <b>block chords</b>, and <b>afterbeats/offbeats</b> (the “oom-pah” lift). Each gives the same harmony a different feel.',
        harp:'<b>Arpeggiated patterns are the harp’s mother tongue.</b> Learn a handful of left-hand broken-chord shapes (root–fifth–octave–third…) and you can accompany any progression. Try them over a drone in the meditation tool.',
        action:{label:'Try patterns over a drone →', view:'meditation'} },
      { h:'Grooves & bass lines', body:'Rhythm-driven textures like the Latin <b>3-2 clave</b> and <b>distinctive bass lines</b> (walking bass, riffs, pedals) can define a song as much as its melody. The bass carries both roots and groove.',
        harp:'Your <b>left hand on the long low strings</b> is the groove. A repeating bass riff or walking line gives a harp arrangement spine; let those low strings ring for depth, or damp them for a tighter, rhythmic pulse.' },
    ]},
    { n:15, title:'Creating Contrast Between Sections', quiz:[
        {q:'Name four “elements of music” you can change to create contrast.', a:'Any of: melody, harmony, rhythm, texture, register, dynamics, articulation, timbre, tempo.'},
        {q:'How does a chorus often contrast with a verse?', a:'Frequently by rising in register and dynamics, and thickening the texture.'},
        {q:'Give two harp-specific ways to create contrast between sections.', a:'Shift register (move the same idea up/down the strings) and change timbre — e.g. play près de la table near the soundboard, or use harmonics, versus open ringing strings.'},
      ], lessons:[
      { h:'The elements of music', body:'To make a new section feel new, change one or more <b>elements</b>: melody, harmony, rhythm, <b>texture</b>, <b>register</b>, <b>dynamics</b>, articulation, timbre, tempo. A chorus that gets louder and higher than its verse is using register and dynamics.',
        harp:'The harp has its own timbral palette for contrast: play near the soundboard (<i>près de la table</i>) for a guitar-like buzz, use harmonics for a glassy shimmer, or sweep glissandi to flood a new section with colour.' },
      { h:'Contrast in practice', body:'Studying how a Mozart movement and a pop song shift these elements teaches you to shape an <b>arc</b> — tension and release across a whole piece, not just within a phrase. Contrast keeps a listener leaning in.',
        harp:'Plan one big contrast device per arrangement — a register jump, a glissando, a sudden bare-fifths texture — and save it for the moment of greatest lift. On the harp, restraint then release is everything.' },
    ]},
    { n:16, title:'Figured Bass', quiz:[
        {q:'What does a “6” under a bass note indicate?', a:'A first-inversion triad (the chord’s third is in the bass).'},
        {q:'What is a cadential six-four?', a:'A I⁶⁴ that decorates and delays the V at a cadence — its upper notes lean down into the dominant.'},
        {q:'How does inversion help a harpist realise a figured bass smoothly?', a:'Choosing inversions keeps the hands in one string region and avoids leaps, so the realisation flows.'},
      ], lessons:[
      { h:'Reading the figures', body:'<b>Figured bass</b> is a Baroque shorthand: numbers under a bass note show the intervals above it, encoding the chord and its inversion. Root position needs no figure; <b>6</b> = first inversion; <b>6/4</b> = second inversion. Performers “realized” the figures by improvising the harmony.',
        harp:'Realising figured bass is a wonderful harp skill — your right hand fills in the chord shapes the figures imply while the left plays the bass. Because the harp sustains, your realisations can be sparse and still sound full.' },
      { h:'The cadential six-four', body:'The most important figured-bass idiom is the <b>cadential six-four</b> — a I⁶⁴ that decorates and delays the V at a cadence, its two upper notes leaning down into the dominant before it resolves home.',
        harp:'Roll the cadential six-four for maximum effect: arpeggiate up to the suspended tonic chord over the dominant bass, then let the upper voices fall into the V. The harp’s ring makes that delicious delay shimmer.' },
    ]},
  ]},

  /* ===================== SEMESTER 3 — CHROMATIC HARMONY & FORM ===================== */
  { sem:3, title:'Chromatic Harmony', sub:'Colour beyond the key', chapters:[
    { n:17, title:'Secondary Dominants', quiz:[
        {q:'What is a secondary dominant?', a:'The V (or V7) of a chord other than the tonic — e.g. V/V or V7/vi — borrowing a leading tone from outside the key.'},
        {q:'What is tonicization?', a:'Briefly making a non-tonic chord feel like a temporary home, without truly changing key.'},
        {q:'What does a secondary dominant demand of a lever harpist?', a:'A lever flip to create the borrowed leading tone (a sharp outside the key) — often pre-set or flipped just before the chord.'},
      ], lessons:[
      { h:'Borrowing a dominant', body:'A <b>secondary dominant</b> is the V (or V7) of a chord other than the tonic — written “V/V,” “V7/vi.” It borrows a leading tone from outside the key to point strongly at its target chord. The most common way tonal music adds chromatic colour.',
        harp:'Here the levers earn their keep. To play V/V you must <b>raise one string</b> (the new leading tone) with its lever — often flipped a beat early with a free finger, then flipped back. Secondary dominants are where harpists plan their lever choreography.',
        action:{label:'See your levers →', view:'levers'} },
      { h:'Tonicization', body:'When a secondary dominant resolves to its target, it briefly makes that chord feel like a temporary “home” — <b>tonicization</b>. A momentary spotlight, not a true change of key.',
        harp:'Because tonicization is brief, harpists often flip <b>one lever in and straight back out</b> — a quick gesture rather than a full key reset. Choose targets whose leading tone is easy to reach.' },
      { h:'Writing & resolving them', body:'To build V/x, find the dominant of the target chord and add its leading tone. They usually resolve normally (leading tone up, 7th down) — but composers love <b>irregular resolutions</b> that surprise the ear.',
        harp:'When you arrange chromatic harmony, mark every lever change in your score with an up/down arrow. A clean secondary-dominant passage on the harp is as much about <b>lever timing</b> as about the notes.' },
    ]},
    { n:18, title:'Secondary Diminished Chords', quiz:[
        {q:'What does a vii°7/x do?', a:'It tonicizes a chord using its diminished leading-tone seventh instead of its dominant — a more chromatic, yearning approach.'},
        {q:'Why is the fully-diminished seventh so flexible?', a:'It’s symmetrical (stacked minor thirds), so it can slip toward many chords and be respelled for modulation.'},
        {q:'Why are fully-diminished sevenths demanding on a lever harp?', a:'They stack notes outside the set key, often needing two or more levers engaged at once.'},
      ], lessons:[
      { h:'Borrowing a leading-tone chord', body:'Like secondary dominants, a <b>secondary diminished</b> (vii°/x, often vii°7/x) tonicizes a chord — but using its diminished leading-tone chord instead of its dominant. The effect is more chromatic and yearning.',
        harp:'These chords usually need <b>multiple levers</b> engaged, so plan them where you have a moment to set them. The reward is one of the most expressive sounds the harp can make — a tense, glassy shimmer.' },
      { h:'A pivot in disguise', body:'Because the fully-diminished seventh is symmetrical (stacked minor thirds), it can slip toward almost any harmony — making it a slippery, powerful tool for chromatic motion and, later, for modulation.',
        harp:'On the harp this symmetry is a gift and a puzzle: the same four strings (with levers) can lead four different directions. Learn one diminished-seventh hand shape and lever set, and you can pivot almost anywhere.' },
    ]},
    { n:19, title:'Mode Mixture', quiz:[
        {q:'What is mode mixture?', a:'Borrowing chords or scale degrees from the parallel minor into a major key (or vice versa) — e.g. ♭VI, minor iv.'},
        {q:'What is a Picardy third?', a:'Ending a minor-key piece on a major tonic chord (raising the third) — a sudden brightening.'},
        {q:'How does a harpist get a Picardy third?', a:'Engage the lever on the third of the tonic chord to raise it from minor to major for that final chord.'},
      ], lessons:[
      { h:'Borrowing from the parallel minor', body:'<b>Mode mixture</b> (borrowed chords) imports chords or scale degrees from the parallel minor into a major key — or vice versa. The bittersweet <b>♭VI</b>, the minor <b>iv</b>, the <b>♭III</b> and <b>♭VII</b> darken or warm the harmony while keeping the key.',
        harp:'Borrowed <b>flats</b> are the tricky direction on a lever harp, because levers only raise. To get a lowered scale degree you must have tuned that string flat to begin with, or be in a key where that note is already lower. Plan borrowed chords into your tuning.' },
      { h:'Two famous mixtures', body:'The <b>deceptive cadence to ♭VI</b> (V→♭VI) is a goose-bump surprise. The <b>Picardy 3rd</b> ends a minor piece on a major tonic chord — a sudden sunrise after a sad journey, beloved by Bach.',
        harp:'The Picardy third is pure lever magic: minor all the way through, then at the final chord you <b>flip one lever up</b> to raise the third and the room fills with light. Practise that single, well-timed flip until it’s silent and smooth.' },
    ]},
    { n:20, title:'The Neapolitan Chord', quiz:[
        {q:'What is the Neapolitan chord?', a:'A major triad built on the lowered second scale degree (♭II), almost always in first inversion (N⁶).'},
        {q:'What function does it serve?', a:'A dramatic pre-dominant — it leans strongly toward the dominant.'},
        {q:'What makes the Neapolitan awkward on a lever harp?', a:'Its root is a lowered scale degree (♭2), a flat that levers can’t produce unless the string is tuned/reset down — so it usually requires pre-planning the tuning.'},
      ], lessons:[
      { h:'The ♭II chord', body:'The <b>Neapolitan</b> is a major chord built on the lowered second degree (♭II), almost always in first inversion (<b>N⁶</b>, with the 4th degree in the bass). A dramatic, yearning pre-dominant that leans hard toward the dominant — opera and film love its tragic colour.',
        harp:'Because the Neapolitan needs a <b>lowered</b> 2nd, lever harpists usually engineer it through key choice or tuning rather than a quick flip. When you can set it up, roll it richly in first inversion — it’s one of the most beautiful chords on the instrument.' },
    ]},
    { n:21, title:'Augmented Sixth Chords', quiz:[
        {q:'What defines an augmented-sixth chord?', a:'An augmented-sixth interval whose two notes resolve outward by half step onto the dominant.'},
        {q:'Name the three types.', a:'Italian, French, and German augmented sixths.'},
        {q:'Why does the German augmented sixth interest a modulating harpist?', a:'It sounds identical to a dominant seventh, so with the right lever respelling it can pivot to a distant key.'},
      ], lessons:[
      { h:'The augmented-sixth interval', body:'These chords are built around a striking <b>augmented sixth</b> interval (e.g. A♭ up to F♯), whose two notes pull powerfully <b>outward</b> by half step onto the dominant. Among the most intense chromatic pre-dominants in tonal music.',
        harp:'The augmented sixth combines a <b>raised</b> note (lever up) with a <b>lowered</b> note (tuned/reset down) — so it tests a lever harp the most. They reward careful tuning planning with an almost vocal, aching pull to the dominant.' },
      { h:'Italian, French & German', body:'Three flavours add a different note inside the augmented sixth: the <b>Italian</b> (sparest), the <b>French</b> (whole-tone shimmer), and the <b>German</b> (sounds exactly like a dominant 7th). They often arrive over a <b>descending chromatic bass line</b>.',
        harp:'A descending chromatic bass means a run of <b>lever flips</b> on consecutive low strings — slow, dramatic, and very playable if you choreograph it. The German type’s dominant-seventh sound makes it a favourite harp pivot for surprise key changes.' },
    ]},
    { n:22, title:'Modulation', quiz:[
        {q:'How does modulation differ from tonicization?', a:'Modulation moves the tonal home to a new key and confirms it with a cadence; tonicization is only a brief spotlight.'},
        {q:'What is a pivot chord?', a:'A chord belonging to both keys, reinterpreted to ease the ear from the old key into the new one.'},
        {q:'Why is modulation more effortful on a lever harp than a pedal harp?', a:'Each new key needs manual lever changes (no pedals), so harpists plan modulations around moments when a hand is free.'},
      ], lessons:[
      { h:'Changing key', body:'<b>Modulation</b> is moving the tonal home to a new key — deeper than a brief tonicization, and confirmed by a cadence. The most natural targets are <b>closely-related keys</b>, just one accidental away (relative minor, dominant, subdominant).',
        harp:'Closely-related keys are the harpist’s friends: they differ by just <b>one lever</b>. Modulating to the dominant or relative minor can be as simple as engaging a single string — which is why so much harp repertoire visits exactly those keys.',
        action:{label:'Explore keys on the Modes wheel →', view:'modes'} },
      { h:'The pivot chord', body:'The smoothest modulations use a <b>pivot chord</b> belonging to both keys: heard one way in the old key, reinterpreted in the new, easing the ear across the seam. Pivots can be diatonic or chromatic.',
        harp:'A pivot chord is the perfect cover for a lever change: while the shared chord rings, your free hand <b>flips the lever</b> that defines the new key. The audience hears one smooth chord; you’ve quietly retuned.' },
      { h:'Hearing a new key', body:'After a modulation your ear re-orients around a new tonic. Recognizing it — by its leading tone and cadence — is a core skill. Some modulations skip the pivot and shift by direct chromatic motion or a common tone.',
        harp:'Train your ear at the harp by modulating with deliberate lever flips and listening for the new “home” string. The physical act of changing the lever cements the new key in your ear.' },
    ]},
    { n:23, title:'Enharmonic Modulation', quiz:[
        {q:'Which two chords sound identical and let you pivot to a remote key?', a:'The dominant seventh and the German augmented sixth.'},
        {q:'Why can a fully-diminished seventh modulate four ways?', a:'It’s symmetrical, so it can be respelled with any of its notes as the leading tone of a new key.'},
        {q:'How does a harpist execute an enharmonic pivot?', a:'By respelling the chord with levers — the same strings, re-engaged differently, become the leading-tone of the new key.'},
      ], lessons:[
      { h:'Pivoting by respelling', body:'Some chords are sonic chameleons. A <b>V7 and a German augmented sixth</b> sound identical; respelling one as the other pivots to a remote key. The <b>fully-diminished seventh</b> is symmetrical — respellable four ways, opening a door to almost any key. These sudden shifts of light are the height of Romantic harmony.',
        harp:'On the harp, enharmonic modulation is a <b>lever sleight-of-hand</b>: hold a ringing diminished or dominant chord, flip the levers that re-spell it, and resolve into a key the listener never saw coming. It’s the most dramatic trick in the lever harpist’s book.' },
    ]},
    { n:24, title:'Binary & Ternary Forms', quiz:[
        {q:'How does sectional binary differ from continuous binary?', a:'Sectional binary cadences home at the end of A; continuous binary ends A in a new key, leaning forward.'},
        {q:'What defines rounded binary?', a:'The opening A material returns partway through the B section (a→b→a′).'},
        {q:'How does form guide a harpist’s lever plan in a binary dance?', a:'If section B modulates, you decide where (often at the double bar/repeat) to flip the lever(s) for the new key, then flip back for the return.'},
      ], lessons:[
      { h:'Two-part (binary) form', body:'<b>Binary</b> form has two sections, often each repeated (‖: A :‖: B :‖). <b>Sectional</b> binary cadences home at the end of A; <b>continuous</b> binary ends A in a new key, leaning forward. <b>Balanced binary</b> echoes A’s ending at the close of B.',
        harp:'The double bar between A and B is your natural <b>lever-change window</b> — if B visits a new key, flip there. Many Baroque dances harpists love (minuets, gavottes) are binary, with the repeat giving you time to reset.' },
      { h:'Rounded binary & ternary', body:'<b>Rounded binary</b> brings the opening A back partway through B (a → b → a′, tightly knit). True <b>ternary</b> (ABA) is bigger: a complete idea, a real contrasting middle, then a full return.',
        harp:'In ternary form, contrast the middle section with a harp-specific colour change — switch register, add harmonics, or move <i>près de la table</i> — then return to the open, ringing A. The form practically asks for the harp’s timbral palette.' },
    ]},
    { n:25, title:'Sonata & Rondo Forms', quiz:[
        {q:'Name the three main sections of sonata form.', a:'Exposition, development, and recapitulation.'},
        {q:'What is the key drama of sonata form?', a:'A conflict of keys: two themes in two keys in the exposition, resolved into the home key in the recapitulation.'},
        {q:'What is the shape of a rondo?', a:'A recurring refrain alternating with contrasting episodes (ABACA…).'},
      ], lessons:[
      { h:'Sonata form', body:'<b>Sonata form</b> dramatizes a conflict of keys. The <b>exposition</b> presents two theme-groups in two different keys; the <b>development</b> destabilizes and explores them; the <b>recapitulation</b> resolves everything by bringing both themes back in the home key. The grand narrative arch of the Classical era.',
        harp:'Sonata form’s key contrasts mean <b>planned lever changes</b> at each major seam. Harpists arranging Classical sonatas map every modulation in advance — the development section, full of remote keys, is where the lever choreography gets most intricate.' },
      { h:'Rondo & structural functions', body:'<b>Rondo</b> alternates a recurring refrain with contrasting episodes (ABACA…), like a chorus that keeps returning. Both forms rest on four <b>structural functions</b> — opening, transition, development and closing — the deep grammar of large pieces.',
        harp:'Each return of the rondo refrain is a chance to <b>re-orchestrate</b> on the harp — first plain, then with a richer bass, then in harmonics. The recurring tune over a fixed lever setting makes rondo a satisfying form to arrange.' },
    ]},
  ]},

  /* ===================== SEMESTER 4 — COUNTERPOINT & THE 20TH CENTURY ===================== */
  { sem:4, title:'Counterpoint & the 20th Century', sub:'Lines, jazz & new sound-worlds', chapters:[
    { n:26, title:'Voice Leading: Triads', quiz:[
        {q:'What are the two forbidden parallels?', a:'Parallel perfect fifths and parallel perfect octaves.'},
        {q:'Name two principles of smooth voice leading.', a:'Keep common tones; move other voices by the smallest step; give each voice a singable line.'},
        {q:'How does voice leading translate to harp playing?', a:'Choosing inversions that keep common tones lets your hands stay in one string region and move minimally between chords.'},
      ], lessons:[
      { h:'The art of voice leading', body:'<b>Voice leading</b> is moving each of four voices (S-A-T-B) smoothly from chord to chord: keep common tones, move others by step, give each voice a singable line, respect its range. Smooth voice leading makes a progression sound finished, not blocky.',
        harp:'Good voice leading is good harp technique: when chords share tones, your fingers can <b>stay on those strings</b> while only one or two move. Smooth voice leading literally means less hand travel and cleaner playing.' },
      { h:'The forbidden parallels', body:'The cardinal rule: avoid <b>parallel fifths</b> and <b>parallel octaves</b> — two voices moving in the same perfect interval rob them of independence and sound “empty.” Contrary and oblique motion keep the four voices alive.',
        harp:'Interestingly, parallel fifths and octaves are also a beloved <b>harp colour</b> (think Celtic and medieval styles) — the very “emptiness” classical writing avoids can sound gorgeous and ancient on the harp. Know the rule, then break it on purpose.' },
    ]},
    { n:27, title:'Voice Leading: Seventh Chords', quiz:[
        {q:'Which way does the chordal seventh almost always resolve?', a:'Down by step.'},
        {q:'In a V7→I, what do the leading tone and the seventh do?', a:'The leading tone rises to the tonic; the seventh falls a step — two tensions resolving at once.'},
        {q:'Why might a harpist omit a note from a seventh chord?', a:'To keep it to four fingers and let each remaining voice — especially the resolving seventh — lead cleanly.'},
      ], lessons:[
      { h:'Resolving the seventh', body:'The added 7th is a <b>tendency tone</b>: it almost always resolves <b>down by step</b> into the next chord. In a V7→I the leading tone rises to the tonic while the seventh falls — two tensions resolving at once, the most satisfying motion in tonal music.',
        harp:'On the harp you can <b>watch</b> the resolution: the seventh is a string that drops to its neighbor, the leading tone a string that rises. Voicing V7 as root–3rd–7th (drop the 5th) gives a clean, three-finger resolution.' },
      { h:'Chains of sevenths', body:'When seventh chords follow one another around the circle of fifths, voices alternate between <b>complete</b> and <b>incomplete</b> chord forms so every seventh can resolve down. The vii°7 has its own special resolution worth memorizing.',
        harp:'A circle-of-fifths chain of sevenths is a superb harp exercise in <b>economical motion</b> — alternating full and reduced voicings keeps your hand compact while every seventh slips down a string.' },
    ]},
    { n:28, title:'Voice Leading with Non-Chord Tones', quiz:[
        {q:'Why decorate four-part writing with non-chord tones?', a:'They add melodic life and motion to otherwise static chords.'},
        {q:'What must you watch for when adding NCTs to counterpoint?', a:'That they don’t create hidden parallel fifths or octaves.'},
        {q:'Which NCT is most idiomatic to let ring on the harp?', a:'The suspension (and pedal point) — the harp’s sustain makes the held dissonance and its resolution especially expressive.'},
      ], lessons:[
      { h:'Decorating the counterpoint', body:'Passing tones, neighbors and suspensions bring four-part writing to life — but they must never create hidden parallel fifths or octaves. This is where harmony, melody and counterpoint meet on the page, and where careful craft shows.',
        harp:'Decorated counterpoint suits the harp perfectly: stepwise NCTs are adjacent strings, and the instrument’s sustain lets suspensions hang in the air before they resolve. Add them by ear — your fingers already know the neighboring strings.' },
    ]},
    { n:29, title:'Voice Leading Chromatic Harmonies', quiz:[
        {q:'Which way do augmented-sixth notes resolve?', a:'Outward by half step onto the dominant.'},
        {q:'Where does the Neapolitan’s root tend to move?', a:'Down to the dominant (often via the leading tone).'},
        {q:'Why is idiomatic resolution of chromatic chords vital on the harp?', a:'Each chromatic note is a lever flip; resolving it correctly means flipping the lever back at the right instant so the line sounds inevitable, not clashing.'},
      ], lessons:[
      { h:'Leading the chromatic chords', body:'Every chromatic chord has tendency tones that must move correctly to sound inevitable: secondary-dominant leading tones rise, the Neapolitan’s root falls to the dominant, augmented-sixth notes spread outward, borrowed degrees resolve like their minor-key originals. Idiomatic resolution makes chromatic harmony sing.',
        harp:'On the lever harp, “resolving correctly” is also “flipping the lever back at the right moment.” Score your chromatic passages with lever arrows in and out; the music’s voice leading and your lever choreography are the same thing.',
        action:{label:'See your levers →', view:'levers'} },
    ]},
    { n:30, title:'Introduction to Counterpoint', quiz:[
        {q:'What does species counterpoint teach, step by step?', a:'Consonance, dissonance and independent motion — from note-against-note (first species) up to florid fifth species.'},
        {q:'What is a fugue subject?', a:'The main theme of a fugue, announced alone, then answered at the fifth and woven through every voice.'},
        {q:'Why is two-voice counterpoint well suited to the harp?', a:'The two hands can each carry an independent line, and the sustaining strings keep both lines audible at once.'},
      ], lessons:[
      { h:'Species counterpoint', body:'<b>Counterpoint</b> is the art of combining independent melodic lines. <b>Species counterpoint</b> trains it in five graded steps — from note-against-note (first species) up to florid, rhythmically free fifth species — teaching consonance, dissonance and independent motion one layer at a time.',
        harp:'Two-part counterpoint is a beautiful harp study: left hand one voice, right hand another, each singing on its own. Because the strings ring, both lines stay alive — you hear the conversation between the hands.' },
      { h:'Invention & fugue', body:'These skills build toward the <b>invention</b> (two interweaving voices) and the <b>fugue</b> — a single <b>subject</b> announced, answered at the fifth, woven through every voice with dazzling craft. The fugue is the summit of contrapuntal art, Bach its supreme master.',
        harp:'Bach’s two-part inventions transfer wonderfully to harp and are a rite of passage. Fugues are harder — keeping three or four independent voices clear means careful <b>damping</b> so the lines don’t blur into one ringing wash.' },
    ]},
    { n:31, title:'Introduction to Jazz Theory', quiz:[
        {q:'What is the central chord cell of jazz?', a:'The ii–V–I progression.'},
        {q:'Name two altered-dominant tensions.', a:'Any of: ♭9, ♯9, ♯11 (♭5), ♭13 (♯5).'},
        {q:'What is a chord–scale relationship? Give one example.', a:'The scale that colours a given chord — e.g. Mixolydian over a dominant 7th, Dorian over a minor ii, Lydian over a major 7th.'},
      ], lessons:[
      { h:'Jazz chords & symbols', body:'Jazz extends triads into 7ths, 9ths, 11ths and 13ths, plus <b>altered dominants</b> (♭9, ♯9, ♯11, ♭13), all named with rich chord symbols (Cmaj9, F7♯11, Dm7♭5…). The harmony is denser and more colourful than common-practice chords.',
        harp:'Extended chords are a harp gift: a rolled 9th or 13th chord uses strings you already have in the key — lush, ringing colour with no levers. For altered dominants, one lever adds the spice (a ♯11 or ♭9) to an otherwise open chord.' },
      { h:'ii–V–I, voicings & turnarounds', body:'The <b>ii–V–I</b> is the central cell of jazz. Pianists use <b>rootless voicings</b> and <b>shells</b> so harmony moves smoothly; <b>turnarounds</b> loop the end of a tune back to the top. Master ii–V–I and you hold the key to the standards.',
        harp:'Try a ii–V–I with <b>left-hand roots and right-hand shells</b> (3rd + 7th) — the harp version of rootless voicings. In one set key you can comp through a whole jazz standard, lever-free, letting the strings ring like a vibraphone.' },
      { h:'Chord–scale & bebop', body:'<b>Chord–scale relationships</b> tell you which scale colours each chord (Dorian over a ii, Mixolydian over a V, Lydian over a maj7…). The <b>bebop scales</b> add a chromatic passing tone so chord tones land on the beat — the secret to smooth, swinging lines.',
        harp:'Chord-scales connect straight to the Modes wheel: each mode is a lever setting, and improvising the right mode over each chord is pure open-string playing. The bebop passing tone is the one spot you’ll flip a lever mid-line.',
        action:{label:'Explore the modes →', view:'modes'} },
    ]},
    { n:32, title:'Impressionism & Extended Tonality', quiz:[
        {q:'How did Impressionist composers treat harmony?', a:'As colour rather than function — chords valued for their sound, not their pull to resolve.'},
        {q:'Name a non-traditional chord-building method from this era.', a:'Quartal (in fourths), quintal (in fifths), secundal (in seconds), or polychords.'},
        {q:'Why is Impressionist harmony so idiomatic to the harp?', a:'Whole-tone and pentatonic scales and quartal chords lie under the open strings and glissando beautifully — Debussy and Ravel wrote landmark harp works for exactly this reason.'},
      ], lessons:[
      { h:'New colours around 1900', body:'Debussy and his peers loosened tonality, treating harmony as <b>colour</b> rather than function. <b>Pandiatonicism</b> uses a scale’s notes freely without traditional progressions; whole-tone and pentatonic scales create a floating, weightless light.',
        harp:'This is the harp’s golden age — Debussy and Ravel prized the instrument for exactly these floating colours. A pentatonic or whole-tone <b>glissando</b> across set strings is the sound of Impressionism, and it’s yours with one lever recipe.' },
      { h:'Stacking new intervals', body:'Instead of stacking thirds, composers built chords in <b>fourths (quartal)</b>, <b>fifths (quintal)</b> and <b>seconds (secundal)</b>, and combined two chords into shimmering <b>polychords</b>. These open, ringing sonorities are wonderfully harp-friendly.',
        harp:'Quartal and quintal chords are simply a different <b>string-skipping shape</b> — skip two strings instead of one. They ring with an open, modern resonance that suits the harp’s sustain perfectly. Experiment: your hands already know the gaps.' },
    ]},
    { n:33, title:'Set Theory', quiz:[
        {q:'What is a pitch-class set?', a:'An unordered collection of pitch-classes analysed without reference to a key — the tool for atonal music.'},
        {q:'What does prime form give you?', a:'A set’s most basic, compact, comparable shape — so different-looking chords can be recognised as the same set class.'},
        {q:'What two operations relate pitch-class sets?', a:'Transposition (Tₙ) and inversion (TₙI).'},
      ], lessons:[
      { h:'Music as pitch-class sets', body:'For atonal music we drop keys and analyze collections of <b>pitch-classes</b> as <b>sets</b>. <b>Normal form</b> packs a set into its most compact ordering; <b>prime form</b> finds its most basic, comparable shape — letting us see that two different-looking chords are the same set.',
        harp:'Atonal set-theory music demands <b>many levers engaged at once</b> and frequent changes — the lever harp’s real frontier. Composers writing atonal harp music plan the lever map as carefully as the pitches; some passages are simply unplayable without retuning.' },
      { h:'Fingerprints & operations', body:'The <b>interval vector</b> counts every interval in a set — a fingerprint explaining its sound. <b>Forte numbers</b> catalogue every set class. The two operations relating sets are <b>transposition</b> (Tₙ, moving by n half steps) and <b>inversion</b> (TₙI, flipping around an axis).',
        harp:'Transposition by a half step is the hardest move on a lever harp (it can mean re-levering every string), while transposition by an octave is free — just shift to the same strings higher or lower. Set theory throws the harp’s strengths and limits into sharp relief.' },
    ]},
    { n:34, title:'Serialism', quiz:[
        {q:'What is a tone row?', a:'An ordering of all twelve pitch-classes that gives each equal weight, the basis of a twelve-tone work.'},
        {q:'Name the four basic row forms.', a:'Prime, inversion, retrograde, and retrograde-inversion (each transposable to twelve levels).'},
        {q:'What does a 12×12 matrix show?', a:'Every row form at a glance — primes across, inversions down, retrogrades read backward.'},
      ], lessons:[
      { h:'Twelve-tone technique', body:'Schoenberg’s method gives all twelve pitch-classes equal weight by ordering them into a <b>tone row</b>. From the original (<b>prime</b>) row he derives its <b>inversion</b>, <b>retrograde</b> and <b>retrograde-inversion</b>, each transposable to twelve levels — 48 forms in all.',
        harp:'Twelve-tone music uses all twelve pitches equally — the opposite of the diatonic lever harp. Playing it means levers in constant motion or strings pre-tuned chromatically; it’s where harpists most feel the instrument’s diatonic nature. Composers often give the harp only fragments of the row for this reason.' },
      { h:'The matrix', body:'A 12×12 <b>matrix</b> lays out every row form at a glance: read across for primes, down for inversions, backwards for retrogrades. Composers present these forms in melody and harmony to build a piece with no tonal center.',
        harp:'For the harpist, the matrix is also a <b>lever map</b>: each row form implies which strings must be raised when. Analysing the matrix tells you where the unplayable spots are — and where clever lever choreography makes the impossible possible.' },
    ]},
    { n:35, title:'Minimalism', quiz:[
        {q:'What is additive process?', a:'Growing a repeating pattern one note (or beat) at a time.'},
        {q:'What is phase shifting?', a:'Starting two identical loops together and letting one slide gradually out of sync (Steve Reich).'},
        {q:'Why is minimalism beautifully suited to the harp?', a:'Repeating diatonic cells sit on open strings with no lever changes, and the harp’s ring builds the hypnotic, shimmering texture minimalism seeks.'},
      ], lessons:[
      { h:'Process music', body:'<b>Minimalism</b> builds large, hypnotic works from tiny repeating cells. <b>Additive</b> process grows a pattern one note at a time; <b>phase shifting</b> (Steve Reich) starts two identical loops together and lets one slide slowly out of sync, generating ever-changing patterns from the same material — a meditative, mesmerizing close to the journey.',
        harp:'Minimalism may be the harp’s most natural modern home: a single set key, a small repeating cell on open strings, and the instrument’s long sustain layering the pattern into a shimmer. No levers, no key changes — just flow. Sit with a drone and build your own repeating cell.',
        action:{label:'Sit with a drone →', view:'meditation'} },
    ]},
  ]},

  /* ===================== FOUNDATIONS — THE SCIENCE OF SOUND (Schmidt-Jones) ===================== */
  { sem:5, kicker:'Foundations', title:'The Science of Sound', sub:'Why your harp sounds the way it does',
    src:'From “Understanding Basic Music Theory” by Catherine Schmidt-Jones (CC BY-SA 4.0).', chapters:[
    { n:36, title:'Sound, Pitch & Loudness', quiz:[
        {q:'What is the difference between noise and a musical tone?', a:'Noise is a random jumble of sound waves; a tone is a regular, evenly-spaced wave — which the ear hears as a definite pitch.'},
        {q:'What two physical properties correspond to loudness and to pitch?', a:'Amplitude (the size of the wave) = loudness; frequency / wavelength = pitch.'},
        {q:'Where does a harp’s loudness come from, physically?', a:'The size of the pluck — a bigger displacement of the string makes a larger-amplitude wave, which we hear as louder.'},
      ], lessons:[
      { h:'Music is organized sound waves', body:'At its most basic, music is <b>organized sound waves</b>. A random jumble of waves is heard as <b>noise</b>; a regular, evenly-spaced wave is heard as a <b>tone</b> — a sound with a clear pitch. Sound itself is a <b>longitudinal wave</b>: a vibrating object squeezes the air into evenly-spaced ripples that travel to your ear.',
        harp:'Pluck a string and it vibrates back and forth in a steady, regular rhythm — so you hear a clean <b>tone</b>. Knock the soundboard and you get an irregular jumble — <b>noise</b>. Everything musical the harp does begins with setting a string into that regular vibration.' },
      { h:'Loudness — amplitude & dynamics', body:'The <b>amplitude</b> of a wave is how big it is — how far the air is displaced. Bigger amplitude = louder. Scientists measure it in <b>decibels</b>; musicians call loudness the <b>dynamic level</b> — <i>forte</i> (loud), <i>piano</i> (soft), and everything between.',
        harp:'Your dynamics live entirely in <b>how you pluck</b>. A firm pluck near the middle of the string moves it further — bigger amplitude, louder note. A gentle pluck high up gives a soft, sweet <i>piano</i>. No pedals or breath — just the size and place of the pluck.' },
      { h:'Pitch — wavelength & frequency', body:'The spacing of the waves sets the <b>pitch</b>. Closer-together waves (shorter <b>wavelength</b>) reach your ear more often — a higher <b>frequency</b>, measured in <b>hertz</b> (Hz) — and sound higher. The tuning reference is <b>A = 440 Hz</b>; humans hear roughly 20 to 17,000 Hz.',
        harp:'Look at your harp: the <b>short, thin treble strings</b> vibrate fast — high frequency, high pitch. The <b>long, thick bass strings</b> vibrate slowly — low pitch. The instrument is a frequency ladder you can see, longest-and-lowest to shortest-and-highest.',
        action:{label:'Tune to A440 →', view:'tuner'} },
    ]},
    { n:37, title:'Standing Waves on a String', quiz:[
        {q:'What is a standing wave, and why do instruments use them?', a:'A wave “trapped” bouncing back and forth in a container of just the right size, so it reinforces itself into a steady tone instead of spreading out and fading.'},
        {q:'What are nodes and antinodes?', a:'Nodes are points of no motion; antinodes are the points of greatest motion. A string fixed at both ends must have a node at each end.'},
        {q:'Name the three things that set a harp string’s pitch.', a:'Its length, its tension, and its thickness (mass) — long, loose, thick strings sound low; short, tight, thin strings sound high.'},
      ], lessons:[
      { h:'Trapped waves & standing waves', body:'A wave normally spreads out and fades. But trap it bouncing between two fixed ends of just the right length and it reinforces itself into a steady <b>standing wave</b> — the basis of every musical tone. The longest wave that fits is the <b>fundamental</b> (the <b>first harmonic</b>); it gives the note its pitch.',
        harp:'A harp string is a textbook standing-wave container — a thin string held tight at both ends. Pluck it and a standing wave springs up between the two anchor points. Instruments that make sound this way are called <b>chordophones</b>; your harp is one.' },
      { h:'Nodes, antinodes & what sets the pitch', body:'A standing wave has <b>nodes</b> (points that don’t move) and <b>antinodes</b> (points of biggest motion). A string fixed at both ends must have a node at each end. Its pitch depends on <b>length, tension and thickness</b>: shorten the vibrating length, tighten it, or thin it, and the pitch rises.',
        harp:'This is why your bass strings are <b>long and thick</b> and your treble strings <b>short and thin</b> — the maker is tuning the physics. When you turn a tuning pin you change the <b>tension</b> to raise or lower the pitch; a lever shortens the vibrating length a touch to raise it a half step.' },
    ]},
    { n:38, title:'The Harmonic Series & Timbre', quiz:[
        {q:'Where does an instrument’s timbre (tone colour) come from?', a:'From its harmonics — a string vibrates as a whole AND in halves, thirds, fourths… all at once; the blend of those overtones gives the note its colour.'},
        {q:'What is the frequency ratio of an octave?', a:'2 : 1 — the second harmonic has exactly twice the frequency (and half the wavelength) of the fundamental.'},
        {q:'Why does a harp sound different from a flute playing the same note?', a:'They share the same harmonic series but emphasise different harmonics, so the tone colour differs.'},
      ], lessons:[
      { h:'Harmonics — why a harp sounds like a harp', body:'A plucked string vibrates as a whole (the fundamental) <b>and</b>, at the same time, in halves, thirds, fourths and beyond. Each fraction adds a higher <b>harmonic</b> (overtone). You don’t hear them as separate notes — blended, they give the note its <b>timbre</b>, its colour. A single pure frequency, by contrast, sounds dull and mechanical, like an alarm.',
        harp:'Those overtones, amplified by the soundboard, are the harp’s shimmering, bell-like <b>colour</b>. A flute and a harp can play the very same pitch yet sound utterly different because each emphasises a different mix of harmonics — the harp leaning on the bright, ringing ones.' },
      { h:'The harmonic series', body:'The harmonics line up in a fixed pattern called the <b>harmonic series</b>. The 2nd harmonic has <b>twice</b> the frequency of the fundamental — exactly one <b>octave</b> higher (a 2:1 ratio). The 3rd is three times (an octave + a fifth), the 4th four times (two octaves), and so on. These simple whole-number ratios are the physical root of octaves, fifths, and all of consonance.',
        staff:{clef:'treble', key:'C', notes:'C4/h, C5/h'},
        harp:'Every octave on your harp is that pure 2:1 — the C5 string vibrates exactly twice as fast as the C4 string. The whole layout of strings is the harmonic series made visible, which is why octaves and fifths feel so settled and “at home” under your hands.' },
    ]},
    { n:39, title:'Harp Harmonics', quiz:[
        {q:'How do you sound a harmonic an octave above a string’s pitch?', a:'Lightly touch the string at its exact midpoint (forcing a node there) and pluck — the fundamental is silenced and the 2nd harmonic, an octave higher, rings out.'},
        {q:'Why does touching the midpoint give the octave specifically?', a:'It forces a node in the middle, which only the even harmonics (starting with the 2nd = the octave) allow; the fundamental, which needs motion there, is cancelled.'},
        {q:'What does a harp harmonic sound like?', a:'Pure, soft, glassy and flute-like — fewer overtones than a normal pluck, like a bell.'},
      ], lessons:[
      { h:'Playing the octave harmonic', body:'Because a string can only make standing waves with a node at certain points, lightly touching it at a chosen spot lets only the harmonics that already have a node there survive. Touch the <b>exact midpoint</b> and pluck: the fundamental (which needs to move there) is silenced, and you hear the <b>2nd harmonic — an octave higher</b>, pure and flute-like.',
        harp:'This is the harp’s beloved <b>harmonics</b> technique. Rest the side of your palm or a knuckle lightly at the string’s centre, pluck below it with the thumb, then release — out floats a soft, glassy octave. It’s the same physics, made into one of the harp’s most magical sounds.' },
      { h:'Other harmonics & the bell tones', body:'Touch the string a <b>third</b> of the way along and you get the 3rd harmonic — an octave plus a fifth above. Quarters give two octaves up, and so on. Each spot reveals a different member of the harmonic series, with fewer overtones than a full pluck — which is exactly why harmonics ring so pure and bell-clear.',
        harp:'Composers prize harp harmonics for that crystalline, music-box colour — Debussy and Ravel especially. Used sparingly over a soft chord, a few harmonics turn the harp into something otherworldly. Try the midpoint first; it’s the easiest and sweetest.' },
    ]},
    { n:40, title:'Tuning Systems & Beats', quiz:[
        {q:'In equal temperament, how is the octave divided, and which interval is the only pure one?', a:'Into twelve equal half steps (each the 12th root of 2); only the octave is a pure ratio (2:1).'},
        {q:'What is a “beat” in tuning?', a:'A regular pulsing in the sound when two notes are slightly off a pure interval — their waves drift in and out of step. Tuners listen for the beats to slow and stop.'},
        {q:'Why do harps use equal temperament rather than just intonation?', a:'Just intonation needs tiny retunings for every key; a harp (like a piano) can’t adjust pitch on the fly, so equal temperament lets it play in many keys without retuning.'},
      ], lessons:[
      { h:'Why tuning is a choice', body:'Before musicians can play together they must agree on exactly which frequency is an “A.” Every tuning system is built from the physics of the <b>harmonic series</b> — the <b>pure intervals</b> with simple ratios: the octave (2:1), the perfect fifth (3:2), the major third (5:4). The catch: you cannot make all of them pure at once.',
        harp:'Tuning isn’t just a chore before you play — it’s a tiny act of music theory. The “A” you tune to and the system you use shape how every chord on the harp will sound.' },
      { h:'The historical systems', body:'<b>Pythagorean</b> tuning stacks pure fifths — glorious fifths, but thirds come out too wide, and the fifths never quite close the octave (the leftover “wolf” fifth). <b>Mean-tone</b> flips this, making the thirds pure for sweet Renaissance harmony. <b>Just intonation</b> makes both thirds and fifths pure and sounds gorgeous — but you must <b>retune for every key</b>.',
        harp:'That last point is the harpist’s reality: just intonation is, in the book’s words, “unworkable for pianos, harps, and other instruments that cannot make small tuning adjustments quickly.” You can’t nudge a harp string mid-phrase, so a fixed, flexible system wins.' },
      { h:'Equal temperament & beats', body:'Modern <b>equal temperament</b> divides the octave into <b>twelve identical half steps</b> (each the 12th root of 2). Only the octave stays pure; every other interval is nudged slightly, so you can play in <b>any key without retuning</b>. Fine differences are measured in <b>cents</b> (1/100 of a half step). When two notes are slightly off, their waves create audible <b>beats</b> — a steady pulsing.',
        harp:'This is exactly how you tune your harp by ear: play two strings and listen for the <b>beats</b> — a wah-wah-wah pulse — then adjust the pin until the beating <b>slows and disappears</b>. No beats = in tune. Piano and harp tuners tune by timing those beats, not by hearing pure intervals.',
        action:{label:'Tune by ear →', view:'tuner'} },
    ]},
    { n:41, title:'Beyond Major & Minor', quiz:[
        {q:'How many notes are in a pentatonic scale, and what does it avoid?', a:'Five — and it avoids half steps, so no two notes clash; that’s why it sounds open and consonant.'},
        {q:'Why are pentatonic scales perfect for the harp?', a:'Set the levers for a pentatonic and every glissando sweeps only consonant notes — so any sweep across the open strings sounds beautiful.'},
        {q:'Name two ways music divides the octave other than major and minor.', a:'Any of: pentatonic scales, the blues scale, the modes, ragas, whole-tone, or other “exotic” scales.'},
      ], lessons:[
      { h:'Pentatonic & blues scales', body:'Major and minor are only two of countless ways to carve up the octave. The <b>pentatonic</b> scale uses just five notes and contains <b>no half steps</b>, so nothing clashes — it appears in folk music the world over. Add one chromatic “blue note” and you get the soulful <b>blues scale</b>.',
        staff:{clef:'treble', key:'C', notes:'C4/8, D4, E4, G4, A4, C5, D5, E5'},
        harp:'The pentatonic is the <b>harp’s glissando scale</b>. Set your levers so the open strings spell a pentatonic and every sweep of your hand — up or down — pours out only consonant notes. This is the secret behind those cascading, dreamlike harp glissandi.' },
      { h:'Modes & the world’s scales', body:'Beyond pentatonic lie the <b>modes</b> (Dorian, Phrygian, Lydian…), the <b>ragas</b> of Indian classical music, whole-tone scales, and many “exotic” scales. Each divides the octave its own way and carries its own mood — proof that the major/minor system is one tradition among many.',
        harp:'Each mode is simply a different <b>lever recipe</b> on your harp — set the levers, and the open strings sing in that mode. Explore them on the Modes wheel: the harp makes modal playing as easy as changing a few levers.',
        action:{label:'Explore the modes →', view:'modes'} },
    ]},
    { n:42, title:'Transposition — Changing Key', quiz:[
        {q:'Name the four steps of transposing music.', a:'1) Choose your transposition; 2) write the new key signature; 3) move every note the same interval; 4) take care with accidentals.'},
        {q:'On the circle of fifths, which way do you move to transpose higher?', a:'Clockwise (toward more sharps) raises the key; counter-clockwise (toward more flats) lowers it.'},
        {q:'Why does a lever harpist most often transpose?', a:'To move a piece into a key the levers can actually reach (the E♭-tuning arc E♭–B♭–F–C–G–D–A–E) — or to suit a singer’s range.'},
      ], lessons:[
      { h:'Why transpose, and the four steps', body:'<b>Transposing</b> means moving a whole piece to a new key — it then sounds higher or lower, but every relationship between the notes stays the same. Musicians transpose to fit a <b>singer’s range</b>, to land in a <b>key that’s easier to play</b>, or to write for transposing instruments. The method has four steps: <b>1)</b> choose your transposition, <b>2)</b> write the new key signature, <b>3)</b> move every note the same interval, <b>4)</b> mind the accidentals.',
        harp:'For a lever harpist, transposing is mostly about reaching a <b>playable key</b>. A piece written in A♭ or D♭ sits outside the E♭-tuning lever range — transpose it into C, G, or E♭ and suddenly the whole thing falls under your hands with no retuning.' },
      { h:'Finding the new key', body:'Step two and three are pure circle-of-fifths thinking. To transpose <b>up</b>, move <b>clockwise</b> (toward sharps); to transpose <b>down</b>, move <b>counter-clockwise</b> (toward flats). Change the key signature by the chosen interval, then shift <b>every note</b> the same number of lines and spaces. Do that consistently and the melody arrives intact in its new home.',
        staff:{clef:'treble', key:'C', notes:'(D4 F#4 A4)/h, (E4 G#4 B4)/h'},
        harp:'Use the app’s Circle of Fifths as your transposing map: pick your starting key, count round to the new one, and read off the new lever recipe. The same tool that shows you the key shows you exactly which levers the transposed key needs.',
        action:{label:'Open the Circle of Fifths →', view:'circle'} },
      { h:'Choosing a harp-friendly key', body:'Before transposing, decide <b>which</b> new key. For a singer, find the one that fits their range. For yourself, choose a key your instrument plays well — and, the book notes, harpists (like pianists) “cannot make small tuning adjustments quickly,” so the key must be one your <b>levers can set</b>. Watch accidentals too: a borrowed sharp or flat may need re-spelling in the new key.',
        harp:'Your safe harbour is the eight-key arc from the Circle of Fifths — <b>E♭ B♭ F C G D A E</b>. If a piece lives outside it, transpose into the nearest key on the arc. You keep the music and gain a setting your levers can actually play.',
        action:{label:'Train your ear →', view:'eartraining'} },
    ]},
  ]},

  /* ===================== THEORY IN THE REAL WORLD (Open Music Theory v.2) ===================== */
  { sem:6, kicker:'Real-world', title:'Theory in the Real World', sub:'Pop, groove, blues & the living tradition',
    src:'Adapted from “Open Music Theory,” v.2 — ed. Mark Gotham, Kyle Gullings, Chelsey Hamm, Bryn Hughes, Brian Jarvis, Megan Lavengood & John Peterson (CC BY-SA 4.0). Pop chapters draw on Drew Nobile’s work; galant schemas follow Robert Gjerdingen; the Tonnetz chapter follows neo-Riemannian theory.', chapters:[
    { n:43, title:'The Pop Loops & Schemas', quiz:[
        {q:'Name the four chords of the “Axis” progression.', a:'I–V–vi–IV — the “four chords” behind hundreds of hits. Its rotations vi–IV–I–V and IV–I–V–vi are just the same loop started in a different place.'},
        {q:'What makes the doo-wop (’50s) progression I–vi–IV–V feel nostalgic?', a:'The vi and IV cushion the trip from home to the dominant, giving a gentle, rocking descent that a generation of ballads made iconic.'},
        {q:'Why are these loops a lever-harpist’s dream?', a:'A loop stays in one key, so once the levers are set you never touch them again — you just cycle four left-hand root shapes and improvise above.'},
      ], lessons:[
      { h:'Why loops rule pop', body:'Where classical music <b>modulates and develops</b>, most popular music <b>loops</b>: a short chord cycle repeats under changing melody and lyrics. The loop is a <b>schema</b> — a stock pattern listeners already know in their bones. Master a handful and you can play along with an enormous slice of recorded music.',
        harp:'A loop is the harp’s natural habitat. Because it never leaves the key, you set your levers once and the whole song plays lever-free. Learn the four root positions as <b>hand-spans</b> and the loop becomes muscle memory.' },
      { h:'The famous four', body:'The <b>Axis</b> loop <b>I–V–vi–IV</b> (and its rotations) underpins hundreds of songs. The <b>doo-wop / ’50s</b> loop <b>I–vi–IV–V</b> rocks nostalgically. The <b>lament / Andalusian</b> descent <b>i–VII–VI–V</b> falls darkly step by step. The <b>plagal “Puff” loop</b> and the <b>“stepwise-down” pop-Romanesca</b> round out the core vocabulary.',
        harp:'Set C or G and try the Axis loop rolled: <b>C–G–Am–F</b>, each chord a warm broken arpeggio. Then switch to the Andalusian in A minor — <b>Am–G–F–E</b> — and feel how the same instrument turns from sunlight to shadow with no lever change.' },
      { h:'Rotations & the “sensitive” loop', body:'Because a loop has no beginning, <b>where you start it</b> changes its colour. Start the Axis on vi (<b>vi–IV–I–V</b>) and you get the “sensitive female” loop — the same four chords heard as yearning rather than triumphant. This is why one progression can feel like ten different songs.',
        harp:'Experiment: play the same four strings-worth of chords but <b>begin the phrase on a different one</b>. Damp the bass to reset the ear each time. You’ll hear the “home” shift under your hands — a free composition lesson built into the loop.',
        action:{label:'Hear functions over a drone →', view:'meditation'} },
    ]},
    { n:44, title:'Fragile, Absent & Emergent Tonics', quiz:[
        {q:'What is a “fragile” tonic?', a:'A tonic that IS present but weakened — never in root position, never on a downbeat, or passed through so quickly the ear never fully rests on it.'},
        {q:'How can a song have an “absent” tonic?', a:'The loop circles the key but never actually sounds the I chord — the tonic is implied by the other chords yet never arrives, keeping the music suspended.'},
        {q:'What is an “emergent” tonic?', a:'A tonic withheld through the verse and only revealed at the chorus or drop — the arrival of home becomes the song’s big payoff.'},
      ], lessons:[
      { h:'When home won’t sit still', body:'Classical theory assumes a strong, obvious tonic. Modern pop often <b>destabilises</b> it on purpose (an idea from Drew Nobile’s work in OMT). A <b>fragile tonic</b> is there but weak — always inverted, always off the beat. The song has a home, but you’re never quite allowed to rest in it.',
        harp:'To voice a fragile tonic, <b>avoid the low root</b>. Play the I chord in first inversion (third in the bass) or let it ring only briefly before moving on. The harp’s sustain makes this delicious — the home chord glows, then slips away.' },
      { h:'The absent tonic', body:'Some loops <b>never play the tonic at all</b>. A progression like <b>IV–V–vi</b> repeated implies a key of I, yet I is never sounded — the ear leans toward a home that never comes. The effect is floating, restless, endlessly “about to arrive.”',
        harp:'You can <b>hint</b> at the absent tonic with a <b>pedal string</b>: let the low tonic ring quietly underneath while the chords above avoid it. The harp lets you imply the home key with a drone even as your hands refuse to land there.' },
      { h:'The emergent tonic', body:'The most dramatic option: <b>withhold the tonic until the chorus</b>. The verse wanders through pre-dominants and dominants; then the chorus finally <b>lands on I</b> and the whole song blooms. The tonic “emerges” as the emotional peak.',
        harp:'Arrange this with <b>texture</b>: keep the verse thin and high, deliberately dodging the low tonic string. When the chorus hits, <b>roll a full low tonic chord</b> — the sudden weight of home under your hands is the payoff the whole verse set up.',
        action:{label:'Feel the pull of home →', view:'meditation'} },
    ]},
    { n:45, title:'Pop Song Form', quiz:[
        {q:'What do the letters SRDC stand for?', a:'Statement, Restatement, Departure, Conclusion — a four-part phrase model that shapes countless verses and choruses.'},
        {q:'What is the job of a pre-chorus?', a:'To build tension and momentum between verse and chorus — often by rising, thinning the texture, or leaning on the dominant so the chorus lands harder.'},
        {q:'What is a “terminal climax”?', a:'A final section (often a last chorus, lifted or re-textured) that tops everything before it — the song’s highest emotional point saved for the end.'},
      ], lessons:[
      { h:'The building blocks', body:'Pop songs are assembled from labelled <b>sections</b>: <b>intro, verse, pre-chorus, chorus, bridge, outro</b>. The <b>verse</b> tells the story (new lyrics each time); the <b>chorus</b> is the fixed emotional centre; the <b>bridge</b> provides contrast before the last chorus. Recognising sections is the first step to arranging any song.',
        harp:'Give each section its own <b>harp texture</b>: sparse single notes for the verse, fuller rolled chords for the chorus, a change of register for the bridge. The listener feels the form even without the lyrics.' },
      { h:'SRDC — the shape inside a section', body:'Many verses and choruses follow <b>SRDC</b>: a <b>Statement</b>, a <b>Restatement</b> (often varied), a <b>Departure</b> (new material, rising tension), and a <b>Conclusion</b> (cadence home). It’s the pop cousin of the classical <b>sentence</b> — a satisfying miniature journey.',
        harp:'Play SRDC as a dynamic arc: state gently, restate a touch fuller, <b>build through the departure</b> (climb the strings, quicken the arpeggio), then settle at the conclusion. Your hands trace the emotional shape of the phrase.' },
      { h:'Tension architecture', body:'Great pop <b>engineers arrival</b>. The <b>pre-chorus</b> lifts you; the <b>chorus</b> pays off; the <b>bridge</b> resets so the final chorus feels new; a <b>terminal climax</b> — a lifted last chorus, key change, or thickened texture — saves the biggest moment for last.',
        harp:'For a terminal climax, <b>transpose the last chorus up</b> (Circle of Fifths thinking) or move it an octave higher on the harp and roll every chord. Even a solo harp can deliver that “final-chorus lift” that makes a room hold its breath.',
        action:{label:'Plan a key-lift on the circle →', view:'circle'} },
    ]},
    { n:46, title:'The Galant Schemas', quiz:[
        {q:'What is the “Rule of the Octave”?', a:'A stock harmonisation of the ascending and descending scale in the bass — each scale degree gets its conventional chord, giving a ready-made way to harmonise any bass line.'},
        {q:'What does a Prinner schema do?', a:'It answers an opening phrase with a stepwise descent (scale degrees 6–5–4–3 in the melody over a falling bass) — the classic “response” gesture of galant music.'},
        {q:'Why are schemas useful to a harpist?', a:'They’re pre-built two-hand patterns: learn the shape once and you can harmonise, improvise, or ornament in period style without working out every chord from scratch.'},
      ], lessons:[
      { h:'Music’s stock phrases', body:'Eighteenth-century composers built music from shared <b>schemas</b> — conventional voice-leading patterns (catalogued by Robert Gjerdingen). They’re the “stock phrases” of galant style: an opening gambit, a response, a cadence. Knowing them lets you hear Mozart’s grammar and improvise in it.',
        harp:'Schemas are gifts to the harpist because each is a <b>fixed shape</b> for two hands. Learn the pattern in one key and, with your levers set, the same finger-shape works — you’re improvising in Classical style by muscle memory.' },
      { h:'The core cast', body:'The <b>Romanesca</b> opens with a descending-bass pattern (think Pachelbel). The <b>Prinner</b> answers it with a 6–5–4–3 descent. The <b>Fonte</b> sinks by step (a “falling” sequence), the <b>Monte</b> climbs, and the <b>Ponte</b> holds on the dominant as a “bridge.” Chained together they build whole phrases.',
        harp:'Try a <b>Romanesca</b> in C: a stepwise-descending bass — <b>C–B–A–G–F–E–D–G</b> — with triads above. It’s the same descent behind “Canon in D” and a hundred pop ballads; on the harp it’s a gorgeous, lever-free walking bass.' },
      { h:'The Rule of the Octave', body:'The <b>Rule of the Octave</b> gives every bass scale-degree its default chord, so you can harmonise <b>any</b> rising or falling bass line instantly. It’s the practical engine behind figured-bass playing — a look-up table for “what chord goes here.”',
        harp:'Internalise the Rule and you can <b>harmonise a bass line on sight</b>: walk the low strings up or down and let your right hand place the conventional chord over each. It turns the harp into a continuo instrument.',
        action:{label:'Review figured bass →', view:'learn'} },
    ]},
    { n:47, title:'The Tonnetz & Smooth Chord Moves', quiz:[
        {q:'What are the three neo-Riemannian moves P, L, and R?', a:'P (Parallel): major↔minor on the same root. L (Leading-tone exchange): move one voice a semitone to swap e.g. C major↔E minor. R (Relative): major↔its relative minor (C↔Am).'},
        {q:'What do P, L, and R all have in common?', a:'Each changes only ONE note (by a semitone or a whole tone) and keeps the other two — maximally smooth voice leading between triads.'},
        {q:'Why does minimal voice-leading matter on a lever harp?', a:'The fewer notes that change, the fewer strings and levers you disturb — smooth voice leading literally means an easier, quieter hand.'},
      ], lessons:[
      { h:'A map made of thirds', body:'The <b>Tonnetz</b> (“tone-network”) is a lattice where notes are connected by thirds and fifths, and every triangle is a triad. It reveals relationships the circle of fifths hides — especially how <b>chromatic</b> chords far apart in key can sit right next to each other.',
        harp:'Think of the Tonnetz as a <b>map of nearby chords</b>. When you want a surprising but smooth change, look for the triad that shares two strings with your current one — it’s the neighbouring triangle on the map.' },
      { h:'P, L, and R', body:'<b>Neo-Riemannian</b> theory names three tiny moves. <b>P</b> (parallel) flips major↔minor on the same root (C↔Cm). <b>L</b> (leading-tone exchange) slides one voice a semitone (C↔Em). <b>R</b> (relative) swaps a chord for its relative (C↔Am). Each changes <b>only one note</b> — the smoothest possible chord change.',
        harp:'These are the harpist’s secret to <b>lush changes with lazy hands</b>. To go C→Am (an R move), you keep C and E ringing and just move G→A — one string. Chain P, L, R and you glide through far-flung chords barely moving your fingers.' },
      { h:'Chromatic magic', body:'Composers from Wagner to film scorers use PLR chains to <b>drift through distant keys</b> without a jolt, because each step is nearly motionless. The music feels like it’s <b>floating</b> between tonal centres — the sound of wonder and mystery.',
        harp:'For a cinematic drift, pick a triad and apply <b>L then R then L…</b>, moving one string at a time. On the harp this becomes a slow, glowing progression where each chord melts into the next — ideal for meditative or “space” textures.',
        action:{label:'Explore the Circle of Fifths →', view:'circle'} },
    ]},
    { n:48, title:'Groove, the Backbeat & the Drum Kit', quiz:[
        {q:'Where does the “backbeat” fall in 4/4?', a:'On beats 2 and 4 — usually the snare drum. The kick anchors 1 (and often 3); the backbeat on 2 and 4 gives rock and pop their drive.'},
        {q:'On a drum-set staff, roughly where do kick, snare, and hi-hat sit?', a:'Kick (bass drum) in the lowest space, snare in the middle, and hi-hat/cymbals as x-noteheads up top — a three-layer picture of the groove.'},
        {q:'How can a solo harp imply a drum groove?', a:'Put the bass note on 1 and 3, a chord “stab” on 2 and 4, and use palm-damping for a percussive, snare-like attack — the harp becomes its own rhythm section.'},
      ], lessons:[
      { h:'Feel is theory too', body:'Harmony gets the glory, but <b>groove</b> carries popular music. A groove is a repeating pattern of <b>kick, snare, and hi-hat</b> that defines the feel. Reading and feeling it is as much “theory” as any chord — and it’s where a lot of harpists are weakest.',
        harp:'The harp is secretly percussive. Every pluck has an <b>attack</b> you can sharpen or soften, and your palm can <b>damp</b> instantly. Treat the low strings as your kick and a mid chord as your snare, and you’ll groove without a drummer.' },
      { h:'Reading the kit', body:'Drum-set notation stacks the kit on one staff: <b>bass drum</b> low, <b>snare</b> middle, <b>hi-hat/cymbals</b> as ✗ noteheads on top. The classic “money beat” is <b>kick on 1 & 3, snare on 2 & 4, hats on every eighth</b>. Once you see that picture you can read most pop grooves.',
        harp:'Map the kit onto the harp: a <b>low string on 1 and 3</b> (kick), a <b>bright chord-stab on 2 and 4</b> (snare), and a light, steady <b>eighth-note arpeggio</b> up top (hi-hat). Three simple layers and the groove appears.' },
      { h:'The backbeat & the pocket', body:'The <b>backbeat</b> — emphasis on 2 and 4 — is the engine of rock, pop, gospel and soul. Sitting exactly in time (or a hair behind) is playing “in the <b>pocket</b>.” The pocket is felt, not calculated: it’s the difference between correct and <b>alive</b>.',
        harp:'Practise the pocket with the app’s rhythm tool: lock a bass-and-backbeat pattern, then let it <b>breathe</b> a touch behind the click. A harp that grooves is rare and unforgettable — this is how you get there.',
        action:{label:'Train your timing →', view:'eartraining'} },
    ]},
    { n:49, title:'The Blues', quiz:[
        {q:'Give the chords of a standard 12-bar blues in I.', a:'I–I–I–I · IV–IV–I–I · V–IV–I–V — twelve bars of I, IV and V, the backbone of blues, rock and roll, and jazz.'},
        {q:'What are the “blue notes”?', a:'Lowered/bent versions of the 3rd, 5th, and 7th scale degrees — pitches that live between the piano’s keys and give the blues its ache.'},
        {q:'How does a lever harpist reach blue notes?', a:'By flipping a lever mid-piece to lower a note (e.g. ♮→♭ for a flat 7th), or by voicing the blues/minor-pentatonic scale that the current lever setting already provides.'},
      ], lessons:[
      { h:'Twelve bars that built modern music', body:'The <b>12-bar blues</b> is a fixed 12-measure loop of <b>I, IV, and V</b> that underlies blues, R&B, rock and roll, and much of jazz. Over it, a singer or soloist uses <b>call and response</b> — a phrase, then an answer. It is arguably the most influential form of the last century.',
        harp:'Set the harp to a blues-friendly key and the whole 12-bar loop plays with three left-hand roots. Roll each chord or “walk” the bass; the harp gives the blues a shimmering, unexpected voice.' },
      { h:'Blue notes & the blues scale', body:'The soul of the blues is its <b>blue notes</b> — the flattened 3rd, 5th, and 7th, often <b>bent</b> between pitches. The <b>blues scale</b> (minor pentatonic plus the flat-5 “blue note”) is your improvising palette: 1–♭3–4–♭5–5–♭7.',
        harp:'A diatonic harp can’t bend, but the <b>levers</b> can give you the flats. Set a minor-pentatonic-friendly tuning and the blue notes are already under your fingers; flip a single lever mid-tune to darken a 7th on cue.' },
      { h:'Call, response & repetition', body:'Blues lyrics famously follow <b>AAB</b>: a line, the same line repeated, then a rhyming punchline — mirrored by the music’s call-and-response. This <b>repetition-with-variation</b> is the emotional engine, wringing meaning from a tiny amount of material.',
        harp:'Play call-and-response with <b>yourself</b>: a melodic “call” high on the strings, a chordal “response” low. The harp’s two registers let one player be both voices — a whole blues conversation from a single instrument.',
        action:{label:'Hear it over a drone →', view:'meditation'} },
    ]},
    { n:50, title:'Orchestration & Arranging for Harp', quiz:[
        {q:'What is “orchestration”?', a:'The art of choosing which instruments play what — assigning register, doubling, and texture so each line sits in its ideal colour and range.'},
        {q:'Name three idioms only the harp does well.', a:'Any of: sweeping glissandos, ringing harmonics, rolled (arpeggiated) chords, près-de-la-table metallic tones, and long natural sustain/pedal points.'},
        {q:'When arranging a lead sheet for solo harp, how do you split the hands?', a:'Bass and harmony in the left hand (root plus chord tones), melody in the right — leaving strings ringing to fill the texture between.'},
      ], lessons:[
      { h:'The right colour for each line', body:'<b>Orchestration</b> is deciding <b>who plays what</b>. Every instrument has a <b>range</b> and changing <b>timbre</b> across it (dark and rich low, bright and thin high). Good arranging places each line in its sweet spot and uses <b>doubling</b> and <b>register</b> to build a texture that breathes.',
        harp:'Know your harp’s zones: the <b>low strings</b> are warm and slow to speak, the <b>middle</b> sings, the <b>top</b> sparkles and decays fast. Put the melody where it glows and the bass where it grounds — that’s orchestration on one instrument.' },
      { h:'What only the harp can do', body:'Arrange <b>to the instrument’s strengths</b>. The harp owns effects no piano or guitar can match: the <b>glissando</b> sweep, ringing <b>harmonics</b>, the <b>rolled chord</b>, the metallic <b>près de la table</b>, and endless <b>sustain</b>. A great harp arrangement isn’t a piano part — it’s written for these idioms.',
        harp:'When you arrange a song, ask “where does a <b>gliss</b> belong? where a <b>harmonic</b>? where should I let a chord <b>ring untouched</b>?” Build the arrangement around those signature gestures and it will sound native to the harp.' },
      { h:'From lead sheet to harp arrangement', body:'A <b>lead sheet</b> gives melody + chord symbols. To arrange it: put the <b>bass and harmony in the left hand</b>, the <b>melody in the right</b>, and let the harp’s sustain fill the middle. Choose a <b>texture</b> (block chords, arpeggios, alternating bass) that fits the song’s feel.',
        harp:'Start simple: <b>left-hand root on the beat, right-hand melody</b>, and one broken-chord pattern for the whole verse. Add rolls and a gliss at the chorus. This four-step recipe turns any lead sheet into a playable, beautiful harp piece.',
        action:{label:'Find a song’s chords first →', view:'circle'} },
    ]},
    { n:51, title:'Sight-Singing & Solfège', quiz:[
        {q:'In moveable-do solfège, what syllable is always the tonic?', a:'Do — moveable-do assigns Do to the key’s tonic, so the same syllables map onto scale degrees in any key (Do-Re-Mi-Fa-Sol-La-Ti-Do).'},
        {q:'What is “audiation”?', a:'Hearing music in your mind before (or without) playing it — the inner ear. It’s the skill sight-singing trains, and the foundation of playing by ear.'},
        {q:'How does the harp help sight-singing?', a:'Its strings are a visible solfège ladder — you can see the scale degrees, sing a line, then check yourself instantly by plucking the string.'},
      ], lessons:[
      { h:'The inner ear', body:'<b>Sight-singing</b> means singing music you’ve never heard, from the page. It trains <b>audiation</b> — hearing music in your mind — which is the real engine behind <b>playing by ear</b>, improvising, and memorising. Even if you never “sing well,” the skill transforms your musicianship.',
        harp:'The harp is the perfect sight-singing partner: <b>sing a note, then pluck the string to check</b>. Because the strings are laid out like a ladder, you can <b>see</b> the interval you’re about to sing — the instrument makes the abstract visible.' },
      { h:'Solfège & scale degrees', body:'<b>Moveable-do solfège</b> gives each scale degree a syllable — <b>Do-Re-Mi-Fa-Sol-La-Ti</b> — with <b>Do always the tonic</b>. Learn how each degree <b>feels</b> (Ti aches up to Do; Fa leans to Mi; Sol is stable) and you can name and sing any melody by ear, in any key.',
        harp:'Set your levers, then label the strings <b>Do-Re-Mi…</b> from the tonic. Play and sing the syllables together. Soon you’ll <b>hear a melody and know its solfège</b> — which means you can find it on the strings without sheet music.' },
      { h:'A daily practice', body:'Build the ear with a simple routine: sing <b>scales</b> in solfège, then <b>arpeggios</b> (Do-Mi-Sol), then short <b>stepwise melodies</b>, always checking against the instrument. A few minutes a day compounds into the ability to <b>play what you hear</b> — the goal behind every other chapter in this course.',
        harp:'Use the app’s ear-training tool as your check: sing an interval, name it in solfège, then confirm. Pair it with the harp and you close the loop — <b>ear, voice, and hand all speaking the same language</b>.',
        action:{label:'Open ear training →', view:'eartraining'} },
    ]},
  ]},

  /* ===================== JAZZ — THE LIVING LANGUAGE (Open Music Theory v.2) ===================== */
  { sem:7, kicker:'The living language', title:'Jazz', sub:'Swing, chords with colour, and the freedom to improvise',
    src:'Adapted from “Open Music Theory,” v.2 (CC BY-SA 4.0) — the Jazz unit by the OMT team (M. Gotham, K. Gullings, C. Hamm, B. Hughes, B. Jarvis, M. Lavengood & J. Peterson). Taught here in our own words and mapped to the lever harp.', chapters:[

    { n:52, title:'Swing & the Jazz Feel', quiz:[
        {q:'In swing, how are two written eighth notes actually played?', a:'Unevenly — long-then-short, roughly a 2:1 “lope,” like saying “hum-pty, hum-pty.” They’re written even but felt with a bounce.'},
        {q:'Which beats carry the emphasis in jazz?', a:'Beats 2 and 4 — the “backbeat.” Snap your fingers there and you’re already feeling jazz.'},
        {q:'How can a solo harpist suggest swing?', a:'Hold the first note of each pair a touch longer and let the off-beat note arrive late — the delay IS the swing; and lean gently on 2 and 4.'},
      ], lessons:[
      { h:'Let’s start with the feel', body:'Before a single chord, jazz is a <b>feeling in the time</b>. Take two eighth notes — the kind you’d normally play evenly, “ti-ti.” In jazz you don’t. You stretch the first and clip the second into a gentle lope: <b>long-short, long-short</b>. Say “<i>hum</i>-pty, <i>hum</i>-pty” out loud — that uneven bounce is <b>swing</b>. It’s written as plain eighths on the page, but everyone knows to “swing” them.',
        harp:'You can absolutely swing on a harp. Play a pair of notes and simply <b>hold the first a little longer</b>, letting the second slip in late. Try it on two adjacent strings, slowly, until the lope feels natural — then speed up. Your hands are learning jazz time.' },
      { h:'Where the pulse lives: 2 and 4', body:'In a march, you feel <b>1</b> and 3 — “LEFT, right, LEFT, right.” Jazz flips it. The emphasis moves to beats <b>2 and 4</b>, the <b>backbeat</b> (it’s where a drummer’s hi-hat snaps shut). Put on any swing tune and <b>snap your fingers on 2 and 4</b> — instantly it feels like jazz, not a march.',
        harp:'Give your two hands the two jobs: <b>left hand on 1 and 3</b> (a low root, grounding the beat), <b>a light chord on 2 and 4</b> up top. That simple split — bass, then a soft “chink” on the backbeat — is the seed of a swing groove under your fingers.' },
      { h:'Landing off the beat: syncopation', body:'Jazz loves notes that <b>don’t land squarely on the beat</b>. A melody note arrives a hair <i>early</i> (a “push”) or hangs over into the next beat (an anticipation). This is <b>syncopation</b> — accenting the spaces between the pulses — and it’s what gives jazz its restless, conversational lilt. It sounds like speech, not a clock.',
        harp:'Take a plain scale fragment and try <b>anticipating</b> the top note — play it just before the beat, then let it ring. That tiny displacement turns a mechanical run into a phrase that <i>talks</i>. Small shift, huge difference.' },
      { h:'Feel beats the metronome', body:'Here’s the secret nobody can fully notate: swing lives in <b>micro-timing</b> — the exact, human amount you push and drag. Play it perfectly on the grid and it sounds stiff; let it breathe a little behind the beat and it sits in “<b>the pocket</b>.” (This is the same soul we chase in Jacob’s Universe — the reason J Dilla turned quantise <i>off</i>.)',
        harp:'Loop a small two-bar pattern with the app’s Rhythm tool, lock it in, then deliberately let it <b>relax a touch behind the click</b>. When it starts to feel good rather than correct, you’ve found the pocket — the real home of swing.',
        action:{label:'Find the pocket →', view:'rhythm'} },
    ]},

    { n:53, title:'Chord Symbols & Extensions', quiz:[
        {q:'What three things does a chord symbol like “Cmaj7” tell you?', a:'The root (C), the quality (major), and the extra note (a major 7th on top). Read it as root + quality + number.'},
        {q:'What makes a dominant 7th chord (like G7) feel restless?', a:'It contains a tritone (in G7, the B–F) — an unstable interval that “wants” to resolve, usually down a fifth to the tonic.'},
        {q:'What is an “extension,” in plain terms?', a:'A colour-note stacked more than an octave above the root — the 9th, 11th or 13th. It doesn’t change the chord’s job, it just adds spice.'},
      ], lessons:[
      { h:'A shorthand for chords', body:'Classical theory names chords by their <b>job</b> in a key (Roman numerals: I, ii, V). Jazz names the <b>actual chord</b> with a letter symbol, so you can read it instantly and play a tune in any key. The recipe is always the same: <b>root + quality + number</b>. So <b>Cmaj7</b> = a C major triad with a major 7th on top (C–E–G–B). <b>Dm7</b> = D minor with a 7th (D–F–A–C). <b>G7</b> = G with a plain (“dominant”) 7th (G–B–D–F).',
        harp:'Read a symbol left to right and build it on the strings: the <b>letter</b> is your bass string, then stack the thirds above. Practise turning “Am7,” “Fmaj7,” “E7” into strings under your fingers — this is jazz literacy, and it comes fast.' },
      { h:'The four seventh-chord families', body:'Almost all of jazz harmony is built from four flavours of seventh chord. <b>Major 7</b> (Cmaj7) — bright, dreamy, at rest. <b>Minor 7</b> (Dm7) — soft, mellow, gentle. <b>Dominant 7</b> (G7) — the tense one, full of forward pull. <b>Half-diminished</b> (Bm7♭5, also written “ø7”) — dark and yearning. Learn to <b>hear</b> the difference between these four and you can hear the emotion of any jazz chord.',
        harp:'Set a key and roll each of the four in turn — maj7, m7, 7, m7♭5 — on the same root, and just <b>listen</b>. Name the feeling out loud (“bright… mellow… restless… aching”). Ear first, label second, exactly as in Jacob’s Universe.' },
      { h:'Extensions: 9ths, 11ths, 13ths', body:'Keep stacking thirds above the seventh and you reach the <b>extensions</b> — the 9th, 11th and 13th. These are the <b>spice notes</b>: they don’t change what the chord <i>does</i>, they change how it <i>glows</i>. <b>Cmaj9</b> is a Cmaj7 with a shimmer on top; <b>G13</b> is a lush, full dominant. Think of the seventh chord as the meal and the extensions as the seasoning.',
        harp:'You can’t comfortably grab seven notes on a harp — and you don’t need to. Pick the <b>tastiest four</b>: often the root, third, seventh and one juicy extension (say the 9th). We’ll turn this “choosing” into an art in the next chapter on voicings.' },
      { h:'Alterations, add, and sus', body:'Two more markings finish the vocabulary. <b>Alterations</b> sharpen or flatten an extension to crank up tension — G7♭9, G7♯11 — most often on dominant chords about to resolve (the famous “<b>Hendrix chord</b>” is a 7♯9). <b>sus</b> replaces the third with the fourth for an open, unresolved hang (Gsus). And <b>add</b> tacks on a note without the notes beneath it (add9 = a 9th but no 7th).',
        harp:'Try a <b>sus</b> chord and let it ring, then resolve the 4th down to the 3rd — you’ll hear the “question, then answer.” That single move, on your own strings, is one of the sweetest sounds in all of harmony.' },
      { h:'Symbols vs. Roman numerals', body:'So why two systems? <b>Roman numerals</b> tell you a chord’s <i>function</i> in a key (the “V” is the tension chord no matter what key you’re in). <b>Chord symbols</b> name the <i>absolute</i> chord (“G7” is G7 anywhere). Jazz leans on symbols because a standard gets played in whatever key suits the singer — you read the symbols and transpose on the fly. Fluent musicians hear both at once.',
        harp:'This is where the Circle of Fifths becomes your friend: it turns a symbol into a lever recipe and a transposition map in one glance. Symbol → key → levers → strings.',
        action:{label:'Open the Circle of Fifths →', view:'circle'} },
    ]},

    { n:54, title:'Jazz Voicings', quiz:[
        {q:'Which two notes most define a chord’s quality, and what are they called?', a:'The 3rd and the 7th — the “guide tones.” They tell you major vs minor and where the chord wants to go; the root and fifth are comparatively optional.'},
        {q:'What is a “rootless” voicing and why does it work?', a:'A voicing that leaves out the root — because in a group the bass plays it. Dropping the root frees your hands to voice richer, higher colours.'},
        {q:'What’s the golden rule of smooth voice leading?', a:'Move as little as possible between chords — often the 7th of one chord slides down a step to become the 3rd of the next.'},
      ], lessons:[
      { h:'The art of leaving notes out', body:'A full Cmaj9 is five notes; a G13 is six. Two hands can’t always grab them all — and here’s the liberating truth: <b>you shouldn’t try</b>. A jazz <b>voicing</b> is a deliberate choice of <i>which</i> notes to play and <i>where</i> to place them. Great jazz harmony is as much about the notes you <b>leave out</b> as the ones you keep.',
        harp:'This is wonderful news for the harp, an instrument that sings most beautifully when it isn’t cluttered. Fewer, well-chosen strings ring clearer and change faster. Let’s learn which ones to choose.' },
      { h:'Shell voicings: just the 3rd & 7th', body:'Two notes carry a chord’s identity: the <b>3rd</b> (is it major or minor?) and the <b>7th</b> (what kind of seventh?). Together they’re the <b>guide tones</b>. Play just the <b>root + 3rd + 7th</b> — a “<b>shell</b>” — and you’ve captured the whole chord in three notes. For G7, that’s <b>G, B, F</b>. Sparse, but unmistakably G7.',
        harp:'Shells are made for the harp. Put the <b>root low in the left hand</b> and the <b>3rd and 7th</b> as a little two-string shape above. Now walk a whole progression using only shells — it’s efficient, elegant, and it swings.' },
      { h:'Rootless voicings — let the bass have the root', body:'When you play with others, the bassist covers the root — so you can <b>drop it</b> and spend those fingers on colour instead. A <b>rootless voicing</b> stacks the 3rd, 7th, 9th (and maybe 13th) higher up, and it <b>floats</b> — richer and more modern than a root-heavy chord.',
        harp:'Try voicing Dm7 as just <b>F–A–C–E</b> (3-5-7-9), no low D. Against a droning low D (an open string, or your left thumb) it glows. The harp’s long sustain makes rootless voicings shimmer.' },
      { h:'Smooth voice leading — the lazy hand wins', body:'The secret to making chords <b>flow</b> is to move as little as possible. Watch the guide tones: over <b>Dm7 → G7 → Cmaj7</b>, the 7th of Dm7 (C) slides <b>down a step</b> to the 3rd of G7 (B), which slides down to the 3rd… wait — it holds, and the line resolves. One smooth descending thread ties three chords together. Musicians call this the <b>guide-tone line</b>.',
        harp:'On a lever harp, minimal motion means <b>minimal lever changes</b> — a gift. Find voicings where only one or two strings move between chords and the whole progression becomes easy <i>and</i> gorgeous. Lazy hands, beautiful music.' },
    ]},

    { n:55, title:'The ii–V–I', quiz:[
        {q:'Spell a ii–V–I in the key of C, with sevenths.', a:'Dm7 – G7 – Cmaj7. Predominant (ii) → dominant (V) → tonic (I): departure, tension, home.'},
        {q:'What is an “applied” (or secondary) ii–V?', a:'A ii–V that briefly points at a chord other than the home tonic — a mini “ii–V of” the next target, treating it as a temporary home.'},
        {q:'What is a turnaround?', a:'A short progression (classically I–vi–ii–V) at the end of a phrase that loops you back to the top — so you can vamp or take another chorus.'},
      ], lessons:[
      { h:'The heartbeat of jazz', body:'If you learn one progression, learn this one. Play <b>Dm7, then G7, then Cmaj7</b> and listen closely: you <b>leave home</b> (the gentle ii), you <b>lean forward</b> (the tense V), you <b>arrive</b> (the restful I). That departure-tension-home is the <b>ii–V–I</b>, and it is the beating heart of a thousand jazz standards. Once your ear catches it, you’ll hear it <i>everywhere</i>.',
        harp:'Set your harp in C and play the three roots in your left hand — <b>D, G, C</b> — with simple shells above. Loop it slowly. You are now speaking the mother tongue of jazz, in your own two hands.' },
      { h:'The thread that ties it together', body:'Why does ii–V–I sound so <b>inevitable</b>? Because of a single smooth line hiding inside it — the <b>guide tones</b>. The 7th of Dm7 (C) falls to the 3rd of G7 (B), and the 7th of G7 (F) falls to the 3rd of Cmaj7 (E). Two little half/whole-step slides, and three chords melt into one gesture. That thread is what your ear is really following.',
        harp:'Play <i>only</i> that line — C→B, then F→E — as your right hand, with the roots underneath. Hear how the melody itself pulls you home. On the harp these are tiny, satisfying string-to-string steps.' },
      { h:'Applied ii–Vs: a home away from home', body:'Here’s the move that unlocks whole tunes: you can put a <b>mini ii–V in front of almost any chord</b>, treating it as a temporary tonic. Want to arrive somewhere special? Approach it with <i>its own</i> ii–V. This “<b>applied</b>” (or secondary) ii–V is how jazz keeps sliding through fresh keys without ever losing the thread.',
        harp:'Pick any chord in your tune and sneak a two-chord ii–V in front of it. Suddenly the arrival feels earned and glamorous. It’s the same “borrowing a dominant” idea as secondary dominants — just with the predominant along for the ride.' },
      { h:'Turnarounds — the endless loop', body:'At the end of a phrase you need a way <b>back to the top</b>. That’s a <b>turnaround</b>, classically <b>I–vi–ii–V</b> (in C: Cmaj7–Am7–Dm7–G7). It’s a tiny spiral that keeps handing you back to bar one, so you can vamp forever or launch another chorus. It’s also the “1950s progression” you already know from doo-wop.',
        harp:'Loop <b>C–Am7–Dm7–G7</b> as four gentle rolled chords and just keep going — improvise a melody on the open strings above. No lever changes, endless music. This single loop is a lifetime of practice and joy.' },
    ]},

    { n:56, title:'Substitution & Reharmonization', quiz:[
        {q:'What is reharmonization?', a:'Keeping a melody but changing the chords underneath it — re-colouring a familiar tune with new harmony.'},
        {q:'How does the tritone substitution work, and why?', a:'Replace a dominant with the dominant a tritone away (D♭7 for G7). They share the same tritone/guide tones, so it resolves the same way — and the bass slides chromatically into the tonic.'},
        {q:'Name one everyday source of “new” chords for a reharmonization.', a:'Mode mixture — borrowing a chord from the parallel minor (or major) — or inserting an applied ii–V or a passing chord.'},
      ], lessons:[
      { h:'Same road, new scenery', body:'<b>Reharmonization</b> is one of jazz’s great pleasures: you keep the <b>melody</b> exactly as it is, but you <b>change the chords beneath it</b>. The tune is still recognisable, yet it feels utterly new — wistful where it was bright, or lush where it was plain. It’s the same instinct we explored with Jacob Collier: change the <i>context</i>, not the note.',
        harp:'Take a melody you know cold (“Twinkle,” “Amazing Grace”) and hold each melody note while you try a <b>different</b> chord under it. Your ear will light up when it finds a fresh one. The harp’s sustain lets you audition each colour slowly.' },
      { h:'The tritone substitution', body:'Here is the most famous jazz sleight-of-hand. Any dominant 7th can be swapped for the dominant a <b>tritone away</b>: play <b>D♭7 instead of G7</b>. It works because both chords contain the <i>same</i> tension interval — the tritone B–F — so they resolve to C just as convincingly. The bonus: the bass now slides <b>chromatically</b>, D♭ → C, a buttery half-step into home.',
        harp:'Try your ii–V–I but replace G7 with <b>D♭7</b>: Dm7 – D♭7 – Cmaj7. Feel the bass ooze down by a half-step into C. That single substitution instantly sounds “jazz.” Set your levers so D♭ is available and it’s yours.' },
      { h:'Borrowing colour: applied chords & mixture', body:'Beyond the tritone sub, jazz freely <b>borrows</b>. Slip in a chord from the <b>parallel minor</b> (mode mixture) for a sudden shadow. Drop an <b>applied ii–V</b> in front of a chord to glamorise its arrival. Add a <b>passing chord</b> to bridge two others by step. Each is a small window opening onto a neighbouring key.',
        harp:'Reharmonizing on a lever harp is a real craft: some borrowed chords need a lever flip mid-tune. Start with borrowings that <b>stay inside your set key</b>, then graduate to one deliberate flip. The Reharm Lab in Jacob’s Universe is a perfect playground for this.' },
      { h:'Reharmonizing a lead sheet', body:'Put it together on a real tune. Take a simple lead sheet (melody + basic chords) and, phrase by phrase, ask: could a <b>ii–V</b> lead into this chord? Would a <b>tritone sub</b> smooth the bass? Does a <b>borrowed</b> chord add the exact feeling I want here? Reharmonization is just these small, tasteful choices, one after another.',
        harp:'Do it slowly, at the harp, letting each new chord ring before you decide. Trust your ear over any rule — if it moves you, it’s right. That instinct, not a formula, is what makes a jazz musician.' },
    ]},

    { n:57, title:'Chord–Scale Theory', quiz:[
        {q:'What scale would you draw from over a Dm7 in the key of C, and over the G7?', a:'D Dorian over Dm7, G Mixolydian over G7 — the same seven notes of C major, each started on a different degree.'},
        {q:'Over an ALTERED dominant (G7♭9♯9♯11♭13), which scale fits?', a:'The altered scale (the 7th mode of melodic minor) — it supplies exactly those tensions.'},
        {q:'What’s the honest limitation of chord-scale theory?', a:'It’s a palette, not a melody. Running a scale per chord sounds like exercises; real lines follow the ear and target chord tones, using the scale only as passing colour.'},
      ], lessons:[
      { h:'A scale for every chord', body:'When it’s time to <b>improvise</b>, chord-scale theory offers a simple starting map: <b>each chord suggests a scale</b> to draw your notes from. Over <b>Dm7</b>, play <b>D Dorian</b>; over <b>G7</b>, play <b>G Mixolydian</b>; over <b>Cmaj7</b>, play <b>C major (Ionian)</b>. Here’s the lovely secret in a plain ii–V–I: those are all the <b>same seven white notes</b> — just started from a different home each time.',
        harp:'This is the harp’s superpower. In one set key, the strings <i>already are</i> your chord-scales — you just shift which note feels like “home” as the chords change. Play C-major strings over the whole ii–V–I and simply lean on different notes.' },
      { h:'The dominant’s many colours', body:'The dominant chord is where the palette gets rich. Over a plain <b>G7</b>, use <b>Mixolydian</b> (bright, bluesy). Over an <b>altered</b> G7 — one dressed in ♭9, ♯9, ♯11, ♭13 — use the <b>altered scale</b>, which hands you exactly those tensions. Want the sound of a floating, Lydian-tinged dominant? Try <b>Lydian ♭7</b>. Different scale, different shade of tension.',
        harp:'You can’t bend into these live on a lever harp, but you <b>can</b> pre-set a scale before a piece and live inside its colour. Choose one dominant flavour, set the levers for it, and improvise — the harp becomes a single, gorgeous mood.' },
      { h:'Use it like a painter, not a runner', body:'The trap is obvious once named: if you just <b>run the scale</b> up and down for each chord, it sounds like <i>exercises</i>, not music. The fix: land <b>chord tones on the strong beats</b> (the notes that spell the chord), and let the rest of the scale be <b>passing colour</b> between them. Aim for the guide tones; decorate the way there.',
        harp:'Practise this directly: play a chord’s <b>arpeggio</b> first (its skeleton), then fill the gaps with neighbouring strings as passing tones. You’ll hear melody emerge instead of scale-running. The harp’s clear attack makes each target note ring.' },
      { h:'The honest limits', body:'OMT is refreshingly candid here, and so are we: chord-scale theory is <b>training wheels</b>. It gets you improvising quickly, but the greatest solos aren’t built by looking up a scale for each chord — they’re built by <b>ear</b>, following the guide-tone thread and the shape of the melody. Learn the map, then trust your ear off the map.',
        harp:'The fastest way past the training wheels is our Ear Training tool: the more chords and colours your ear <i>knows</i>, the less you’ll need to think. Then your hands just play what you already hear.',
        action:{label:'Train your ear →', view:'eartraining'} },
    ]},

    { n:58, title:'Jazz Blues & the Bebop Language', quiz:[
        {q:'How does a “jazz blues” differ from a plain 12-bar blues?', a:'It keeps the 12-bar I–IV–V skeleton but weaves in ii–Vs, turnarounds and passing chords — the same form, richly reharmonized.'},
        {q:'Spell the blues scale and name its “blue notes.”', a:'1–♭3–4–♭5–5–♭7; the ♭3, ♭5 and ♭7 are the bent, aching “blue notes.”'},
        {q:'What is “trading fours”?', a:'A conversation where soloists (or a soloist and the drummer) take turns improvising four bars each — call and response, live.'},
      ], lessons:[
      { h:'The 12-bar blues, jazzed', body:'The <b>12-bar blues</b> is a fixed loop of I, IV and V that underlies blues, rock and jazz alike (we met it in the Real-World unit). Jazz musicians took that plain frame and <b>filled it with colour</b>: ii–Vs leading into the IV and the turnaround, a passing chord here, a substitution there. Same 12 bars, same three-chord bones — but dressed for the evening. That’s the “<b>jazz blues</b>.”',
        harp:'Set a blues-friendly key and play the bare I–IV–V blues first, rolled and easy. Then add just <b>one</b> ii–V into the final turnaround. Hear how a single touch of jazz harmony transforms the whole 12 bars — without losing the blues.' },
      { h:'Blue notes & the blues scale', body:'The soul of the blues is its <b>blue notes</b> — the flattened <b>3rd, 5th and 7th</b>, notes that live in the cracks between “happy” and “sad.” Gather them and you get the <b>blues scale</b>: <b>1 – ♭3 – 4 – ♭5 – 5 – ♭7</b>. It’s your whole improvising palette over a blues, and it sounds right over every chord in the form.',
        harp:'A lever harp can’t bend a note the way a voice or guitar does — but it <i>can</i> give you the flats. Set a minor-pentatonic-friendly tuning and the blue notes sit right under your fingers; flip a single lever mid-tune to darken a 7th exactly when the phrase wants it.' },
      { h:'Call, response, and trading fours', body:'Blues and jazz are <b>conversations</b>. A blues lyric is famously <b>A-A-B</b> — a line, the same line again, then a rhyming punchline — mirrored by the music’s call-and-response. In a jazz group, players “<b>trade fours</b>”: four bars of one soloist, four of the next, back and forth — a live musical dialogue.',
        harp:'Play both voices yourself: a “call” high on the strings, a “response” low — the harp’s two registers let one player hold a whole conversation. Then trade fours with the app’s Rhythm engine as your bandmate.' },
      { h:'Comping & the bebop feel', body:'Behind a soloist, jazz players “<b>comp</b>” (from <i>accompany</i>): light, <b>syncopated chord stabs</b> that leave space and answer the melody, rather than a steady thump. And when lines get fast and beboppy, players use the <b>bebop scale</b> — an ordinary major or dominant scale with one extra passing note — so the chord tones keep landing neatly on the beat.',
        harp:'Comping suits the harp beautifully: a rootless voicing, plucked softly and off the beat, leaves the melody room to breathe. Practise stabbing a shell voicing on the “<b>and</b>” of beats 2 and 4 — sparse, springy, and instantly jazz.' },
    ]},
  ]},

  { sem:8, kicker:'Line against line', title:'Counterpoint & the Galant Style', sub:'Weaving independent melodies, from Fux to Mozart',
  src:'Adapted from “Open Music Theory,” v.2 (CC BY-SA 4.0) — the Counterpoint & Galant Schemas unit by the OMT team. Taught here in our own words and mapped to the lever harp.', chapters:[

  { n:59, title:'What Counterpoint Is', quiz:[
    {q:'In plain words, what is counterpoint?', a:'The art of combining two or more independent melodies so that each sounds good on its own yet they also fit together as harmony.'},
    {q:'Name the four types of two-part motion.', a:'Contrary (opposite directions), similar (same direction, different distances), parallel (same direction, same distance), and oblique (one voice holds, the other moves).'},
    {q:'What is a cantus firmus?', a:'A single, plain, well-shaped melody in even notes — the “fixed voice” — against which you write your counterpoint.'}
  ], lessons:[
    { h:'Two melodies at once', body:'The word <b>counterpoint</b> comes from the Latin <i>punctus contra punctum</i> — “point against point,” or note against note. It simply means the craft of sounding two or more melodies together so that each one is a satisfying tune in its own right, and yet the way they overlap creates pleasing harmony. Think of a round like <i>Row, Row, Row Your Boat</i>: every singer has the same good melody, but because they enter at different times the lines lean against each other and make chords. Counterpoint is the disciplined study of how to make those leanings sound beautiful on purpose.', harp:'On the lever harp your two hands are your two voices. The left hand might hold a slow lower line while the right weaves a faster one above — two independent melodies from ten fingers, the essence of counterpoint made physical.' },
    { h:'Consonance and dissonance', body:'A <b>consonance</b> is an interval that sounds stable and at rest; a <b>dissonance</b> is one that sounds tense and wants to move. In counterpoint we sort them carefully: the <b>perfect consonances</b> are the unison, the fifth, and the octave (open, hollow, very stable); the <b>imperfect consonances</b> are the major and minor thirds and sixths (sweet and full but still restful); and the <b>dissonances</b> are all the seconds, sevenths, and the diminished and augmented intervals. For example, two harp strings a third apart glow warmly together, while two a second apart grind and beg to resolve.', harp:'Pluck E♭ and G together — a major third, mellow and settled. Now pluck E♭ and F — a second, and you hear the rub instantly. The harp’s long sustain lets a dissonance hang in the air, which is exactly why resolving it feels so satisfying.' },
    { h:'The four kinds of motion', body:'When two voices move, they relate in one of four ways. In <b>contrary motion</b> they head in opposite directions — one up, one down — which is prized because it keeps the lines feeling independent. In <b>similar motion</b> both move the same way but by different distances. In <b>parallel motion</b> both move the same way by the same distance, so the interval between them stays the same (parallel thirds, for instance). And in <b>oblique motion</b> one voice holds still while the other moves around it. Contrary and oblique motion are the counterpoint writer’s best friends because they preserve independence.', harp:'Let your left hand climb E♭–F–G while your right hand descends the other way: that is contrary motion, and on the harp it feels like the two hands are opening apart like a fan — the clearest way to keep both lines singing.' },
    { h:'The cantus firmus', body:'Before you write two voices you start with one given melody called the <b>cantus firmus</b>, Latin for “fixed voice” or “fixed song” (plural <i>cantus firmi</i>). It is a plain line of equal, unhurried notes — usually eight to sixteen of them — that begins and ends on the tonic, moves mostly by step with just a few small leaps, and rises to a single clear high point before settling home. Its plainness is the point: because it is so steady and well-shaped, it gives your added counterpoint something solid to lean against. For example, a C-major cantus might simply walk C–D–E–D–F–E–D–C.', harp:'Set a cantus firmus in your left hand as slow, even whole-note plucks — one string per bar, all in the harp’s natural key so no levers move. That rock-steady bass frees your right hand to do the expressive counterpoint above it.' }
  ]},

  { n:60, title:'First-Species Counterpoint', quiz:[
    {q:'What does “first species” mean rhythmically?', a:'One note in your added voice for every one note of the cantus firmus — pure note-against-note.'},
    {q:'Which intervals are allowed between the two voices in first species?', a:'Only consonances: unisons, fifths, octaves, thirds, and sixths — never a dissonance.'},
    {q:'Why avoid parallel fifths and octaves?', a:'Because moving in parallel perfect intervals fuses the two lines into one and destroys their independence.'}
  ], lessons:[
    { h:'One note against one', body:'<b>First species</b> is the simplest exercise: you place exactly one note in your new voice above (or below) each note of the cantus firmus. Because every note lines up vertically, you are only ever asking one question — “what interval do these two notes make, and is it a good one?” This trains your ear to hear every sonority as a deliberate choice. For example, if the cantus sounds a C, you might set an E above it, making a sweet major third.', harp:'Play the cantus as steady whole notes in the left hand and answer each one with a single plucked note in the right, letting both ring for the full beat. The harp’s clarity means every interval stands naked and honest — perfect for this note-against-note discipline.' },
    { h:'Only consonances allowed', body:'In first species every vertical interval must be a <b>consonance</b> — a third, a sixth, a fifth, an octave, or a unison — and never a dissonance, because with nothing but strong beats a dissonance would have no gentle way to resolve. We especially favour the <b>imperfect consonances</b>, the thirds and sixths, because their fullness keeps the music warm and the lines distinct; perfect fifths and octaves are used more sparingly since their hollow openness can make two voices sound like one. For instance, a whole passage in thirds and sixths sounds rich, while too many bare fifths sounds thin and medieval.', harp:'Fill your first-species line mostly with thirds and sixths above the cantus — on the harp these ring as glowing, resonant pairs. Save the open fifths and octaves for special colour, the way you would use pedal points sparingly.' },
    { h:'Beginning and ending', body:'A first-species exercise has framing rules that give it shape. It should <b>begin</b> on a perfect consonance — a unison, fifth, or octave — so the two voices set out from stable ground, and it must <b>end</b> on a perfect consonance too, almost always a unison or octave, so the piece feels fully closed. The approach to that final note is special: the counterpoint typically steps into the ending from the <b>leading tone</b> (the note a semitone below the tonic) up to the tonic, giving that satisfying “coming home” pull. For example, in C the top line might step B–C over a cantus that moves D–C beneath it.', harp:'For the final cadence, make sure your leading tone is available — in some keys that means a lever must already be flipped so the seventh degree sits a semitone below the tonic. Set that lever before you begin so the ending resolves cleanly without a scramble mid-phrase.' },
    { h:'Keeping the lines independent', body:'The whole art is to make two lines that never collapse into one, which is why the rule against <b>parallel fifths and octaves</b> matters so much: if both voices leap the same perfect interval in the same direction, the ear stops hearing two singers and hears a single doubled one. Reach your perfect consonances by <b>contrary</b> or <b>oblique</b> motion instead, so they arrive as a fresh event rather than a slide. And give your added voice its own good melodic shape — mostly stepwise, one clear high point — so it could stand alone as a tune.', harp:'Because parallel motion is so easy to fall into when both hands move together, deliberately send your hands in opposite directions at cadences. On the harp, contrary motion also feels more natural to the arms and keeps the two lines audibly separate.' }
  ]},

  { n:61, title:'Second & Third Species', quiz:[
    {q:'What is the note ratio in second species? In third?', a:'Second species puts two notes against each cantus note; third species puts four against each.'},
    {q:'What is a passing tone?', a:'A dissonant note that fills the gap between two consonances by stepping smoothly through it — down or up by step.'},
    {q:'Where may a dissonance appear in second and third species?', a:'Only on a weak beat, and only if it is approached and left by step; the strong beat must stay consonant.'}
  ], lessons:[
    { h:'More notes against one', body:'Once note-against-note feels easy, we add motion. <b>Second species</b> places two notes in your voice against each single note of the cantus, and <b>third species</b> places four. Suddenly your line has some notes that fall on the <b>strong beat</b> (the downbeat, where the cantus changes) and some on a <b>weak beat</b> (the offbeats in between). This split is what finally lets us use dissonance safely, because a weak-beat note can pass through tension and be gone before it disturbs the harmony.', harp:'In third species your right hand plays four quicker plucks for every slow left-hand whole note — a gentle rippling four-against-one. The harp’s sustain blurs those four into a shimmer over the steady bass, which is a lovely idiomatic sound.' },
    { h:'The passing tone', body:'The first bit of freedom is the <b>passing tone</b>: a dissonant note that simply fills the space between two consonances a third apart by stepping through the note in the middle. If you are consonant on C and want to reach a consonant E, you pass through D on a weak beat — D is dissonant against the cantus, but because it is stepped into and stepped out of in the same direction, the ear reads it as smooth connective tissue rather than a clash. It is the most natural way to add motion to a line.', harp:'A passing tone on the harp is just the string between the two you are connecting — plucked lightly and left quickly. Its brief dissonance melts into the ongoing ring, so the line sounds like a fluid run rather than a bump.' },
    { h:'The neighbour tone', body:'The second freedom is the <b>neighbour tone</b>: a dissonant note that steps away from a consonance and then steps right back to the same note, like a little decoration. From a consonant E you might dip down to D and return to E (a lower neighbour) or rise to F and return (an upper neighbour). The neighbour never goes anywhere new — it leaves home and comes straight back — so its momentary dissonance is heard as ornament, not as a real harmonic event. It adds gentle wiggle and life to a line.', harp:'Neighbour tones give a harp line that graceful “turn” shimmer. Because the string you decorate is still ringing, the neighbour brushes against it and folds back in — an effortless ornament that costs no lever changes since it stays within the scale.' },
    { h:'Strong beats stay pure', body:'The governing rule across both species is simple: the <b>strong beat must be consonant</b>, and any dissonance is confined to a <b>weak beat</b> where it is approached and quit by step. This is why passing and neighbour tones are legal but a dissonant leap is not — a leap onto or off a dissonance leaves it exposed and jarring. Keeping the downbeats clean means the underlying harmony always sounds solid, while the weak-beat dissonances supply the flow and interest on top. For example, strong-beat thirds and sixths with passing tones threaded between them give a singing, connected melody.', harp:'Aim your downbeat plucks at consonant strings and let the in-between notes carry the passing colour. On the harp, landing every strong beat on a third or sixth keeps the harmony luminous while the weak-beat passers add momentum.' }
  ]},

  { n:62, title:'Fourth Species & Suspensions', quiz:[
    {q:'What are the three stages of a suspension?', a:'Preparation (the note is a consonance), suspension (it is held as the other voice moves, becoming a dissonance), and resolution (it steps down to a consonance).'},
    {q:'What rhythmic device defines fourth species?', a:'Syncopation — the added voice’s notes are tied across the beat so they sound off the cantus’s rhythm.'},
    {q:'Which direction does a suspension normally resolve?', a:'Downward by step, into the nearest consonance.'}
  ], lessons:[
    { h:'Syncopation against the cantus', body:'<b>Fourth species</b> introduces <b>syncopation</b> — deliberately shifting your notes off the beat so they no longer line up with the cantus. Practically, you tie each note over the barline so that it is struck on the weak part of one bar and held into the strong part of the next. This offsetting is what sets up the star of this species, the suspension, because your held note is still sounding when the cantus moves underneath it and turns a former consonance into a dissonance. The whole species is really a workshop for one gorgeous device.', harp:'Syncopation is a joy on the harp precisely because strings keep ringing after you pluck them — you strike a note on the offbeat and it naturally sustains across into the next bar with no effort. The instrument does the “holding” for you, which is exactly what a suspension needs.' },
    { h:'The suspension in three stages', body:'A <b>suspension</b> unfolds in three tidy steps. First the <b>preparation</b>: your note is struck as a plain consonance. Then the <b>suspension</b> proper: you hold that note while the other voice moves to a new note, and suddenly your held note has become a dissonance against it — a moment of expressive ache. Finally the <b>resolution</b>: your held note steps down by step into a consonance, releasing the tension. For example, hold a G over a bass that moves to A (now you have a dissonant seventh), then let the G fall to F — sigh and relief in a single gesture.', harp:'This is where the harp is most beautiful: pluck the preparation, let it ring, and the sustaining string becomes the suspension automatically as the left hand moves beneath it. The resolution is just letting the ear follow that ringing string one step down — the instrument practically performs the suspension by itself.' },
    { h:'Why suspensions move us', body:'Suspensions are the emotional heart of counterpoint because they create a tiny drama of tension and release exactly on the strong beat, where the ear is paying most attention. A well-placed suspension delays the expected consonance for a heartbeat, and that delay is what makes the arrival feel earned and tender. Composers chain them together to build long, aching descents — one voice seeming to lag behind and repeatedly catch up. The famous “7–6” and “4–3” suspensions are just labels for which dissonant interval hangs before it resolves down to the sixth or third.', harp:'Try a chain of suspensions on the harp and let each ringing resolution overlap the next preparation — the sustained strings pile into a shimmering, weeping cascade. Few instruments render a suspension chain as meltingly as a harp does, because nothing cuts the resonance short.' },
    { h:'When the chain must break', body:'Sometimes a suspension cannot happen — there is no consonant note a step above the resolution to prepare, or a suspension would create forbidden parallels. In fourth species you are allowed to <b>break the syncopation</b> at those moments, dropping back to plain note-against-note motion for a bar before resuming the tied chain. This keeps the exercise honest rather than forcing an ugly clash. Think of it as taking a breath: the syncopated flow pauses, resets, and picks the thread back up when a fresh suspension becomes available.', harp:'When you break the chain, simply return to plucking on the beat with both hands aligned for a bar. On the harp this momentary “landing” gives the ear a clear resting point before the ringing, syncopated tension resumes.' }
  ]},

  { n:63, title:'Fifth Species & the Fugue', quiz:[
    {q:'Why is fifth species called “florid” counterpoint?', a:'Because it freely mixes all the earlier species — passing tones, neighbours, suspensions, varied rhythms — into one flowing, ornamented line.'},
    {q:'In a fugue, what are the subject and the answer?', a:'The subject is the main theme stated alone at the start; the answer is that same theme restated by a second voice, transposed to the dominant.'},
    {q:'What is an episode in a fugue?', a:'A connecting passage between full statements of the subject, usually spun from fragments of it, that modulates and keeps the music moving.'}
  ], lessons:[
    { h:'Florid counterpoint', body:'<b>Fifth species</b>, often called <b>florid counterpoint</b>, is the graduation exercise where all the previous freedoms combine. In a single line you may now mix whole notes, halves, and quarters, thread in passing tones and neighbours, and tie notes over for suspensions — all in service of one supple, singing melody. The word “florid” means flowery or ornamented, and that is the goal: a line that flowers naturally out of the strict rules you have learned. For example, a bar might glide down with a passing tone, hang on a suspension, and skip up to a fresh consonance, all feeling inevitable.', harp:'Fifth species is the closest thing to real harp writing among the exercises, because it moves the way an idiomatic harp line moves — flowing, rhythmically varied, and full of ringing suspensions. Practising it teaches your right hand to spin a genuinely musical melody over any bass.' },
    { h:'From counterpoint to fugue', body:'Strict counterpoint was really training for writing real polyphonic music, and the crown of that tradition is the <b>fugue</b> — a piece built by stacking entries of a single memorable theme in independent voices. A fugue opens with an <b>exposition</b>, the section where each voice enters one at a time announcing the theme. Everything you learned about consonance, motion, and suspensions is now put to work keeping three or four lines independent and beautiful at once. Bach is the acknowledged master, but the machinery is graspable in plain terms.', harp:'A two- or three-voice fugal texture is very playable on the harp: each hand takes a voice, and the middle voice is shared between the thumbs. Because the strings sustain, earlier entries keep ringing as new ones join — the harp naturally reveals the layered lines of a fugue.' },
    { h:'Subject, answer, countersubject', body:'The theme itself is the <b>subject</b> — the tune stated alone by the first voice at the very start. When a second voice enters, it plays the <b>answer</b>: the same theme moved up to the key of the dominant (a fifth higher), so the two keys converse. Meanwhile the first voice does not fall silent; it continues with a <b>countersubject</b>, a complementary melody designed to fit neatly against the answer. So the moment of the second entry already gives you two coordinated lines — subject-turned-countersubject on top, answer beneath, exactly the two-voice counterpoint you have been practising.', harp:'When the answer enters in your left hand, keep the countersubject flowing in your right so both hands stay busy and independent. Choose a countersubject that stays mostly in the harp’s open strings so you are not flipping levers while both voices are in motion.' },
    { h:'Episodes and the shape of a fugue', body:'A fugue does not simply restate the theme over and over; between full statements it inserts <b>episodes</b>, connective passages usually spun from little fragments of the subject or countersubject. Episodes are where the music modulates to new keys and builds momentum, so that each return of the subject arrives freshly relocated. The overall shape is a conversation: exposition, then alternating episodes and subject-entries wandering through related keys, before a final return home. Understanding this pattern lets you follow any fugue by ear, tracking where the theme surfaces and where the music is merely travelling between statements.', harp:'On the harp, use episodes to make your lever changes — since the subject is momentarily absent, you have a safe window to flip a lever and modulate to the new key. Then the subject can re-enter cleanly in its fresh key with all strings correctly set.' }
  ]},

  { n:64, title:'Galant Schemas', quiz:[
    {q:'What is a galant schema?', a:'A stock, ready-made voice-leading pattern of the Classical style — a short template of a melody-and-bass pairing that composers reused as building blocks.'},
    {q:'Which two schemas form a classic question-and-answer pair?', a:'The Meyer (or opening gambit) poses the phrase and the Prinner answers it, like a musical sentence and its reply.'},
    {q:'What do the Fonte and Monte schemas do?', a:'They are sequence patterns: the Fonte descends by step through two keys, the Monte climbs upward — ways to move the music to a new area.'}
  ], lessons:[
    { h:'Music made from stock patterns', body:'In the <b>galant style</b> of the mid-1700s — the elegant, tuneful manner of the young Mozart and his contemporaries — composers did not invent every phrase from scratch. They drew on a shared toolbox of <b>schemas</b>: short, well-worn templates that pair a typical melody with a typical bass and a typical set of scale-degrees. A schema is like a stock chord progression a songwriter reaches for, except it specifies both hands at once. Learning a handful of them lets you improvise convincing Classical-sounding music by snapping these ready-made shapes together.', harp:'Treat each schema as a two-hand shape for the harp: a fixed little pattern of which strings the left hand walks and which the right hand sings. Memorising them as physical hand-shapes means you can drop a whole idiomatic phrase under your fingers at once.' },
    { h:'The opening pair: Meyer and Prinner', body:'Many galant phrases open with a <b>Meyer</b> (also called the opening gambit): a four-note melodic frame over the tonic that poses the phrase, typically outlining scale-degrees 1–7 … 4–3. It is very often answered by a <b>Prinner</b>, a descending response where the melody falls 6–5–4–3 over a bass that walks 4–3–2–1. Together they behave exactly like a spoken sentence and its reply — the Meyer asks, the Prinner answers and rounds things off. Recognising this pair lets you hear the “sentence structure” of countless Classical themes.', harp:'The Prinner is gorgeous on the harp: a stepwise descent in both hands that you can play almost entirely on open strings. Practise the Meyer-then-Prinner pair as a single flowing gesture and you have an instant, authentic-sounding phrase-and-answer.' },
    { h:'Going somewhere: Fonte, Monte, Ponte', body:'Three schemas move the music to new ground. The <b>Fonte</b> (“fountain”) is a downward sequence: a two-bar idea stated once, then repeated a step lower, sliding the music down through a pair of keys. The <b>Monte</b> (“mountain”) is the opposite, climbing upward step by step to build tension. The <b>Ponte</b> (“bridge”) is a holding pattern that sits on the dominant, marking time before a return — a musical bridge that prolongs expectation. These are the galant composer’s ways of travelling between the stable stock phrases.', harp:'The Monte’s upward climb may require a lever flip as you rise into a sharper key — plan it into the sequence. The Ponte, sitting on a single dominant harmony, is a natural spot to let the harp ring on a sustained bass while you set levers for what comes next.' },
    { h:'The grand opening: the Romanesca', body:'The <b>Romanesca</b> is one of the oldest and grandest schemas, a stately descending bass pattern (often 1–5–6–3–4–1–4–5) that lends a noble, processional feel — you hear it opening many slow movements and hymns. Because its bass falls in a memorable, repeating shape, it is easy to recognise and easy to harmonise once you know it. Alongside the pairs and sequences above, the Romanesca gives you a ready-made way to begin a piece with weight and dignity. Collect a few of these schemas and you have the vocabulary to speak fluent galant.', harp:'The Romanesca’s slow, striding bass is tailor-made for the harp: pluck it as resonant, spaced-out left-hand notes and let each ring under a simple right-hand melody. Kept in the harp’s home key it needs no lever changes, so its stately descent flows uninterrupted.' }
  ]},

  { n:65, title:'The Rule of the Octave & Harmonizing a Scale', quiz:[
    {q:'What is the Rule of the Octave?', a:'A default recipe assigning the “right” chord to each note of the bass scale as it rises and falls through an octave, so any bass line can be harmonized on sight.'},
    {q:'Which bass degrees get root-position chords, and which get inversions?', a:'The stable degrees 1 and 5 take root-position chords; the passing degrees in between mostly take first-inversion (sixth) chords.'},
    {q:'Why was the Rule of the Octave so useful to musicians?', a:'It let a keyboardist or continuo player harmonize an unfigured bass instantly, and it gave students a reliable default for every scale degree.'}
  ], lessons:[
    { h:'A chord for every bass note', body:'The <b>Rule of the Octave</b> is a beautifully practical piece of galant knowledge: it hands you a default chord for each note of the scale in the bass, both going up and coming down. Instead of agonising over the harmony for every note, you learn one standard answer — “when the bass is on degree 3, put this chord over it” — for all seven degrees. Master it once and you can harmonize any rising-or-falling bass line at sight, which is exactly what Classical keyboardists needed to accompany from a bare bass part. It is less a rule to obey than a reliable starting point.', harp:'On the harp, the Rule of the Octave becomes a set of right-hand chord shapes keyed to which left-hand string you are on. Learn the shape for each scale degree and you can improvise a full accompaniment simply by watching where your bass hand walks.' },
    { h:'Stable degrees versus passing degrees', body:'The logic behind the rule is that some scale degrees are pillars and others are merely passing through. The tonic (degree 1) and the dominant (degree 5) are the stable pillars, so they take solid <b>root-position</b> chords — the chord’s root sitting in the bass. The degrees in between (2, 3, 4, 6, 7) are passing steps, so they usually take <b>first-inversion</b> chords, also called <b>sixth chords</b>, which sound lighter and lean forward toward the next pillar. This is why a scale harmonized by the rule feels like it strides firmly on 1 and 5 and glides gracefully across everything else.', harp:'Play degrees 1 and 5 as full, grounded chords in the harp’s open key, and voice the passing degrees more lightly as sixth chords. The contrast between planted pillars and gliding steps gives your harp accompaniment a natural, breathing shape.' },
    { h:'The leading tone leans home', body:'The rule is especially careful around the <b>leading tone</b>, degree 7, the note a semitone below the tonic that yearns to rise. When the bass touches degree 7 the rule gives it a chord built to pull straight up to the tonic — usually a first-inversion dominant sonority — so the ear feels the resolution coming. Likewise degree 4 tends to be harmonized so it can fall toward degree 3. In this way the rule does not just label chords; it wires in the natural tendencies of the scale, so that harmonizing a bass line automatically produces satisfying voice-leading.', harp:'Make sure the leading tone is actually available as a semitone below your tonic — in some keys that means presetting a lever. With that string in place, the degree-7 harmony resolves upward on the harp exactly as the rule intends, ringing straight into the tonic.' },
    { h:'Harmonizing anything on sight', body:'Put it all together and the Rule of the Octave is a superpower: hand it any bass line and it tells you, note by note, a sensible chord to play, complete with built-in voice-leading. Combined with the galant schemas from the previous chapter, it means you can sit down and accompany or improvise Classical-sounding music with confidence, because you always have a default and a set of stock phrases to reach for. It is the practical payoff of the whole counterpoint unit — the point where strict training turns into fluent, spontaneous music-making.', harp:'This is where the lever harp becomes a real improvising instrument: with the Rule of the Octave under your fingers you can harmonize a hymn tune or a folk bass on sight, all within a single lever setting. Set your levers for the key, then let the rule and your ear carry you through the whole piece.' }
  ]}

]},

  { sem:9, kicker:'How music is shaped', title:'Musical Form', sub:'Phrases, sentences, and the great architectures',
  src:'Adapted from “Open Music Theory,” v.2 (CC BY-SA 4.0) — the Form unit by the OMT team. Taught here in our own words and mapped to the lever harp.', chapters:[
  { n:66, title:'Phrases, Motives & Segmentation', quiz:[
    {q:'What is a motive?',a:'The smallest recurring idea in a piece — a short snippet of melody or rhythm, usually smaller than a full musical “idea,” that recurs and gets transformed as the music unfolds.'},
    {q:'What makes a passage a phrase rather than just a motive?',a:'A phrase is a relatively complete musical thought with a beginning, middle, and end that travels toward a goal and arrives at closure — most often a cadence. A motive is far too short to feel complete on its own.'},
    {q:'How do we begin a segmentation analysis?',a:'We first find the points of closure (usually cadences), which tell us where phrases end. Then we divide each phrase into its smaller units — the ideas — that make it up.'} ], lessons:[
    { h:'Music is built in nested layers', body:'One of the most freeing ideas in all of music theory is that a piece is not one long undifferentiated stream — it is <b>built in layers</b>, small units nesting inside larger ones. A whole piece contains movements, a movement contains sections, a section contains phrases, and a phrase contains still-smaller ideas and motives. We call this the <b>hierarchy of form</b>, and once you hear it, you can never un-hear it. Think of it like a sentence made of clauses made of words made of syllables — the music works the very same way.', harp:'Sit at your lever harp and simply play a short tune you know — even a hymn. Notice how it naturally falls into breath-sized chunks with little resting points between them. Those resting points are the seams of the hierarchy; your hands already feel the layers before you can name them.' },
    { h:'The motive — the smallest idea', body:'A <b>motive</b> is the tiniest recurring unit of music, a little snippet — often just a few notes or a single rhythmic gesture — that keeps coming back. The four-note “short-short-short-long” opening of Beethoven’s Fifth is the most famous motive in the world, and it is <i>tiny</i> on purpose. A common beginner’s mistake is to point at a whole melody and call it a motive; if it feels like a complete thought, it is already too big. Motives are meant to be small enough to be tossed around, repeated, and transformed.', harp:'Choose a three-note motive in C major on your harp — say C–D–E, a gentle rise. Play it, then play it starting on G (G–A–B): same shape, new home. That is <b>transposition</b>, one of the classic ways a motive is transformed, and your levers are not even needed since both live in the white-lever key of C.' },
    { h:'How a motive is transformed', body:'A motive rarely returns unchanged — composers keep it recognizable while dressing it in new clothes. It can be <b>inverted</b> (flipped upside down, so a rise becomes a fall), stated in <b>retrograde</b> (backward), <b>augmented</b> (stretched into longer notes) or <b>diminished</b> (squeezed into shorter ones), and <i>embellished</i> with extra decorating notes. Spotting these disguises is the real pleasure of motivic listening. The motive is the seed; the whole piece can grow from it.', harp:'Take your rising C–D–E and <b>invert</b> it into a falling E–D–C — same three notes, opposite direction. Then <b>augment</b> it: play C–D–E slowly, one note per two beats, so it feels grand. The harp makes these transformations physical, because your hand literally reverses direction or slows down.' },
    { h:'The phrase — a complete thought', body:'A <b>phrase</b> is a relatively complete musical thought that shows clear <i>trajectory toward a goal</i> and arrives at a sense of closure. “Relatively complete” means it has a beginning, a middle, and an end — like a spoken sentence that finally lands on its full stop. In tonal music, that full stop is almost always a <b>cadence</b>, the harmonic gesture that signals arrival. Phrases of 4, 8, or 16 measures are especially common, but a phrase can be any length.', harp:'Play a four-bar tune on your harp and lean, ever so slightly, into its final note — let it ring and settle. That settling <i>is</i> the cadence, the goal your phrase was travelling toward. Shaping music with this sense of destination is exactly what turns a row of notes into a phrase.' },
    { h:'Segmentation — hearing the seams', body:'A <b>segmentation analysis</b> is simply the act of showing how a passage groups into its parts — where the phrases end and what smaller ideas fill them. We begin by finding the <b>points of closure</b>, which the cadences usually reveal, and then we divide each phrase into its smaller <b>ideas</b> (often two measures each). A helpful trick: if you were coaching someone to practise this phrase in chunks, where would you cut it? Those cuts are your segments.', harp:'Play an eight-bar melody and deliberately stop at bar four, then finish. You have just performed a segmentation by ear: the mid-point pause reveals the phrase’s inner seam. On the harp, a tiny lift of the hands at that seam makes the structure audible to a listener.' }
  ]},
  { n:67, title:'The Sentence', quiz:[
    {q:'What are the two halves of a sentence?',a:'The presentation (the first half, which states a basic idea and then repeats it) and the continuation (the second half, which builds momentum and drives to a cadence).'},
    {q:'What is fragmentation?',a:'Making the units shorter than they were before — for example, if the basic ideas were each two bars long, the continuation might move in one-bar fragments. It refers to the length of the units, not their melodic content.'},
    {q:'How does a sentence end?',a:'The continuation always drives toward a cadence — perfect authentic, imperfect authentic, or half — giving the sentence its point of closure.'} ], lessons:[
    { h:'The sentence — a special kind of phrase', body:'The <b>sentence</b> is one of the most common ways to build a single phrase, and it has a beautifully clear two-part shape: a <b>presentation</b> followed by a <b>continuation</b>. The presentation states an idea and repeats it, giving us something solid to hold onto; the continuation then breaks that material into smaller pieces and rushes toward a cadence. The classic proportions are 4 + 4 (an eight-bar sentence), though the continuation is often longer, rarely shorter. Once you know the shape, you hear sentences everywhere in Classical music.', harp:'Set your harp to C major and plan an eight-bar sentence: bars 1–4 will be the presentation, bars 5–8 the continuation. Even before choosing notes, feel the architecture — a stable opening half answered by a busier, goal-driven second half.' },
    { h:'The presentation — basic idea plus repetition', body:'The <b>presentation</b> is the first half of the sentence, and it is built from a <b>basic idea</b> (often two bars long) followed by its <b>repetition</b>. That repetition may be exact, or it may be varied — transposed, re-harmonized, or lightly decorated — but its job is to establish the material firmly in our ears. Presentations usually begin on the tonic harmony and stay fairly stable, because stability is precisely what the continuation will later disturb. Think of it as “here is my idea… and here it is again.”', harp:'Play a two-bar basic idea in C — say a little arc C–E–G–E. Then play it again, this time starting on G (G–B–D–B): a transposed repetition. No levers change, since C major lives entirely on your natural strings; the repetition alone makes the presentation feel solid and deliberate.' },
    { h:'The continuation — fragmentation and acceleration', body:'The <b>continuation</b> is where the energy gathers. Its signature trait is <b>fragmentation</b> — the units get shorter than before, so two-bar ideas might break into one-bar or even half-bar pieces. It often adds <i>increased harmonic rhythm</i> (chords changing more often), faster note values, and rising <b>sequences</b>. All of this creates a feeling of acceleration and forward drive, as though the music is gathering itself for arrival. Not every continuation shows all these traits, but fragmentation is the most reliable sign.', harp:'Take your two-bar idea and fragment it: play just its first half, then that half again a step higher, then again higher still — short, quickening gestures climbing the strings. Your hands moving in ever-smaller, ever-faster arcs is fragmentation made visible on the harp.' },
    { h:'The cadence — arrival', body:'Every sentence drives toward a <b>cadence</b>, the harmonic goal that gives the phrase its closure. In Classical music that cadence can be a <b>perfect authentic cadence</b> (PAC) for strong, conclusive arrival, an <b>imperfect authentic cadence</b> (IAC) for a softer landing, or a <b>half cadence</b> (HC) that pauses expectantly on the dominant. The whole shape of the sentence — stable presentation, accelerating continuation — exists to make this arrival feel earned. The cadence is the reward at the end of the journey.', harp:'End your C-major sentence with a G–C bass motion under a melody landing on C: that is your perfect authentic cadence, the fullest sense of “home.” Let the final C ring unhurried — the ringing is the harp’s way of confirming the goal was reached.' },
    { h:'A sentence, start to finish', body:'Let us assemble the whole shape in one breath. The <b>presentation</b> states a basic idea and repeats it (stable, tonic-rooted); the <b>continuation</b> fragments that material and accelerates; and the phrase lands on a <b>cadence</b>. Remember that real music bends the archetype — many phrases are merely <i>sentential</i>, showing some traits but not all — and at minimum, a sentence just needs a presentation and a continuation. Hearing this arc is one of the most useful skills a musician can own.', harp:'Play your complete eight-bar sentence in C on the harp: two bars of idea, two of repetition, then a fragmenting, quickening continuation into a ringing PAC. You have now performed a textbook sentence entirely on natural strings — the form itself, made audible under your fingers.' }
  ]},
  { n:68, title:'The Period', quiz:[
    {q:'What two phrases make up a period?',a:'The antecedent (the first phrase, which asks a “question” and ends on a weaker cadence, often a half cadence) and the consequent (the second phrase, which “answers” and ends on a stronger cadence, most often a perfect authentic cadence).'},
    {q:'Which cadence is stronger, and where does it fall?',a:'The stronger cadence falls at the end of the consequent — typically a perfect authentic cadence — while the antecedent ends more weakly. This weak-then-strong pairing is the heart of the period.'},
    {q:'What is the difference between a parallel and a contrasting period?',a:'In a parallel period the consequent begins with the same basic idea as the antecedent; in a contrasting period it begins with different material. Parallel periods are far more common.'} ], lessons:[
    { h:'The period — a question and its answer', body:'Where a sentence is a <i>single</i> phrase, a <b>period</b> is a pairing of <b>two</b> phrases that together make one satisfying statement. The first phrase, the <b>antecedent</b>, poses a kind of musical question and ends on a weaker cadence, leaving us hanging. The second, the <b>consequent</b>, answers that question and closes with a stronger cadence, resolving the tension. It is the most conversational of forms — a call and its reply.', harp:'On your harp, play a four-bar phrase and end it hanging on the note D (the fifth of C major) — it will sound unfinished, questioning. That unresolved feeling is the antecedent inviting an answer; your ear leans forward, waiting.' },
    { h:'The antecedent — asking the question', body:'The <b>antecedent</b> is the opening phrase of the period, and its defining feature is that it ends with a <i>weaker</i> cadence — most often a <b>half cadence</b> (HC), which pauses on the dominant chord and feels open, like a raised eyebrow. It typically begins on the tonic and usually stays within the home key. Because it ends unresolved, the antecedent makes an “incomplete statement” that the consequent will complete. Its whole character is one of anticipation.', harp:'Play four bars in C major and finish on a G-major chord (G–B–D) rather than a C chord — that half cadence leaves the door open. On the harp, let that G chord ring without resolving; the unfinished tension is exactly what the antecedent is meant to create.' },
    { h:'The consequent — giving the answer', body:'The <b>consequent</b> is the answering phrase, and it usually <i>begins</i> just like the antecedent — same basic idea — but <i>ends</i> differently, closing with a stronger cadence, most often a <b>perfect authentic cadence</b> (PAC). That shared opening plus a firmer ending is what gives the period its satisfying symmetry: we recognize where we are, then finally arrive home. The consequent may be the same length as the antecedent or a little longer; it is rare for it to be shorter.', harp:'Replay your opening four bars, but this time steer the ending to a solid C: a G–C bass under a melody landing on C, a perfect authentic cadence. Hearing the same beginning resolve to a firm home is the whole magic of the period, and your harp delivers it with a single change of destination.' },
    { h:'Parallel vs contrasting periods', body:'When the consequent <i>begins</i> with the same basic idea as the antecedent, we call it a <b>parallel period</b> — by far the most common type, and the one people usually mean by “period.” When the consequent instead begins with <i>new</i> material, it is a <b>contrasting period</b>, which is comparatively rare. The word “parallel” refers only to how the two phrases <i>start</i>, not to how they end — remember, the endings must differ, since the second cadence has to be stronger.', harp:'Play a parallel period on the harp: the antecedent and consequent share the same first two bars, diverging only at the cadence. Then try a contrasting version, giving the consequent a fresh opening melody. Feel how the parallel version reassures the ear while the contrasting one surprises it.' },
    { h:'Why the period feels balanced', body:'The genius of the period is its <b>weak-then-strong</b> cadential design: an open antecedent followed by a closed consequent. This asymmetry of <i>closure</i> — question then answer — is what makes two phrases feel like one complete thought rather than two separate ones. Sentences and periods are the two great phrase archetypes, and much of the music you love is built by combining and varying them. Learn to hear both, and you hold a map to Classical form.', harp:'Play the whole period once through on your harp — four bars ending on a hanging half cadence, then four bars resolving to a ringing PAC. Listen to how the second cadence <i>outweighs</i> the first; that balance of tension and release is the period breathing as one unit.' }
  ]},
  { n:69, title:'Hybrids, Repeated Phrases & Phrase Expansion', quiz:[
    {q:'What is a hybrid phrase?',a:'A phrase that mixes ingredients from both the sentence and the period — for example, an antecedent (period-like opening) followed by a continuation (sentence-like second half) — rather than being a pure sentence or a pure period.'},
    {q:'What is the difference between internal and external expansion?',a:'An internal expansion stretches material within the phrase (repeating or prolonging a unit inside it), while an external expansion adds material at the phrase’s edges — such as a lead-in before it or an extension after the cadence.'},
    {q:'What is phrase contraction?',a:'The opposite of expansion — a phrase that arrives at its cadence sooner than expected, feeling compressed or cut short relative to the norm.'} ], lessons:[
    { h:'Hybrids — mixing the archetypes', body:'Real music does not always obey the tidy categories, and the <b>hybrid phrase</b> is proof: it borrows ingredients from <i>both</i> the sentence and the period. A common hybrid opens with an <b>antecedent</b> (that period-like question ending in a half cadence) but then, instead of a matching consequent, follows with a <b>continuation</b> (that sentence-like fragmenting drive to a cadence). The archetypes are best thought of as flexible tools a composer combines, not rigid boxes.', harp:'On the harp, play an antecedent that hangs on a half cadence, then answer it not with a symmetrical consequent but with a fragmenting, accelerating continuation. You are splicing the front of a period onto the back of a sentence — a hybrid you can hear taking shape under your hands.' },
    { h:'The repeated phrase', body:'The simplest way to make more music from less is the <b>repeated phrase</b>: a phrase followed by a written-out repeat of itself, often lightly varied the second time. This differs from a period, because both statements end with the <i>same</i> kind of cadence — there is no weak-then-strong question-and-answer, just “here it is, and here it is once more.” Composers use repetition to let an idea sink in, or to vary it with new ornamentation.', harp:'Play a complete four-bar phrase, then play it again — but the second time, add a few decorating notes or shift it up an octave for colour. That is a repeated phrase. The harp’s wide register makes the octave-lifted repeat especially easy and lovely.' },
    { h:'Internal expansion — stretching from within', body:'A phrase can be <b>expanded</b> — made longer than its “default” size — and one way is <b>internal expansion</b>, which stretches material <i>inside</i> the phrase. A unit might be repeated, a harmony prolonged, or a sequence spun out an extra time, delaying the cadence and heightening anticipation. The effect is like a speaker dwelling on a point for emphasis: the goal is still coming, but we are made to wait a little longer for it.', harp:'Take a phrase heading for its cadence and, just before the final chord, repeat the penultimate bar once more on the harp — prolonging the tension. That inserted repeat is an internal expansion; you can feel the cadence being politely postponed under your fingers.' },
    { h:'External expansion — adding at the edges', body:'<b>External expansion</b> adds material at the <i>edges</i> of a phrase rather than inside it. A <b>lead-in</b> can be tacked on before the phrase begins, easing us in; or an <b>extension</b> can follow the cadence, prolonging the arrival after the goal is technically reached — think of a tune that keeps echoing “home… home… home” after it has already landed. These additions frame the phrase without disturbing its inner logic.', harp:'After your phrase lands on its final C-major cadence, add a two-bar extension on the harp that simply rocks between C and G, echoing the arrival. That tail hanging off the end of the phrase is an external expansion — the harp gently refusing to let the moment go.' },
    { h:'Contraction — arriving early', body:'The mirror image of expansion is <b>contraction</b>: a phrase that reaches its cadence <i>sooner</i> than we expect, feeling compressed or clipped. Where expansion makes us wait, contraction surprises us by arriving early, which can feel urgent, breathless, or witty. Together, expansion and contraction are the composer’s way of bending the elastic length of a phrase — stretching or squeezing it against the norm the listener quietly expects.', harp:'Play a phrase you know well, then play it again but cut a bar so the cadence lands one measure early. On the harp, that clipped arrival feels almost like a friendly interruption — the phrase getting to the point ahead of schedule.' }
  ]},
  { n:70, title:'Formal Sections & Binary Form', quiz:[
    {q:'Name two formal-section functions besides the main theme.',a:'Common functions include the introduction (before the main material), the transition (which connects sections and often modulates), and the coda (a closing section after the final cadence). Others include retransition and codetta.'},
    {q:'What is the difference between simple and rounded binary form?',a:'In simple (or “balanced”) binary, the opening material does not return within the second section; in rounded binary, the opening idea comes back partway through the B section, “rounding off” the form.'},
    {q:'What harmonic move typically ends the A section of a binary form in a major key?',a:'The A section usually moves away from the tonic to close in the dominant key (or, in a minor key, often the relative major), creating harmonic tension that the B section will resolve back home.'} ], lessons:[
    { h:'Formal sections and their jobs', body:'When we zoom out from phrases to whole pieces, we find larger <b>formal sections</b>, each with a job to do. Besides the main <b>theme</b> (the central material), a piece may have an <b>introduction</b> that sets the stage, a <b>transition</b> that connects sections and often <i>modulates</i> to a new key, and a <b>coda</b> that provides a sense of closing after the last main cadence. Recognizing these functions is like reading the signposts of a musical journey.', harp:'Before launching your main tune on the harp, improvise a short introduction — a few rolled chords or a rising flourish — to set the mood. Then play the theme. Simply framing the tune with an intro teaches your ear how a formal section announces itself.' },
    { h:'Binary form — two halves', body:'<b>Binary form</b> is one of the oldest and most useful architectures: a piece in <i>two</i> sections, an <b>A</b> and a <b>B</b>, each usually repeated. Its defining feature is harmonic: the A section travels <i>away</i> from home, typically ending in the <b>dominant</b> key (or, in minor, the relative major), and the B section works its way back to close in the <b>tonic</b>. The two halves are a departure and a return — tension created, then resolved.', harp:'Play an A section in C major that ends leaning toward G (the dominant), then a B section that finds its way back to close firmly in C. On the harp you can hear the whole form as a round trip: leaving home, then coming back to it.' },
    { h:'The power of the repeat', body:'Binary sections are almost always <b>repeated</b>, giving the familiar shape ||: A :||: B :||. These repeats are not mere filler — they let the ear absorb each section and, in performance, invite tasteful variation the second time through. The repeat structure is so fundamental that it survives right up into the sonata, whose exposition is often repeated for exactly the same reason: to let the material settle before the drama continues.', harp:'Because C major uses no levers, you can loop your A section as a seamless, <b>lever-free repeat</b> — play it, then play it again, perhaps adding ornaments the second time. The harp makes the binary repeat almost effortless, and the added decoration keeps it alive.' },
    { h:'Simple vs rounded binary', body:'Binary forms come in two main flavours. In <b>simple binary</b>, the opening material does <i>not</i> return within the B section — B carries on with related but new material. In <b>rounded binary</b>, the opening idea <i>comes back</i> partway through B, “rounding off” the form and giving a satisfying sense of homecoming — sketched as A · B · A′ within just two repeated halves. Rounded binary is a direct ancestor of the larger ternary and sonata forms.', harp:'Play a rounded binary on the harp: after your B section wanders, bring back the very opening melody of A to close. That return of the first tune — the “rounding” — is a small thrill you can create with a single reprise of your first phrase.' },
    { h:'Hearing the harmonic story', body:'The real engine of binary form is its <b>harmonic expectation</b>. The moment the A section closes in the dominant, an experienced listener feels a pull, an unfinished business, that only a return to the tonic can settle — and the B section exists to deliver that settling. Understanding this tonal tension-and-release is the key that unlocks not just binary form, but ternary, sonata, and rondo as well.', harp:'Deliberately end your A section on a bright G-major chord and pause. Feel how badly your ear wants C. Then let the B section carry you home to a ringing C-major cadence — on the harp, that release is almost physical, the whole point of the form landing in your hands.' }
  ]},
  { n:71, title:'Ternary Form', quiz:[
    {q:'What is the basic shape of ternary form?',a:'ABA — a first section, a contrasting middle section, and a return of the first section. Unlike rounded binary, each of these is a full, self-contained section rather than a subsection of a repeated half.'},
    {q:'How does the B section usually relate to the A section?',a:'The B section provides contrast — often a different key, texture, mood, or theme — setting it apart from A so that A’s return feels like a genuine homecoming.'},
    {q:'What does “da capo” mean and how does it relate to ternary form?',a:'“Da capo” means “from the head” — an instruction to return to the beginning. In a da capo aria, after the contrasting B section the performer repeats A from the top, producing an ABA ternary form.'} ], lessons:[
    { h:'Ternary form — statement, contrast, return', body:'<b>Ternary form</b> is the clean three-part shape <b>ABA</b>: a complete opening section, a contrasting middle, and a full return of the opening. Unlike rounded binary — where the reprise is just a fragment tucked inside a repeated half — each part of a ternary form is a <i>self-contained section</i> that could nearly stand on its own. It is the architecture of countless songs, minuets, and marches: say something, say something different, then say the first thing again.', harp:'Plan three sections on your harp: an A tune in C major, a B tune that feels different, and then A again. Even sketching the three blocks in your mind before playing gives you the satisfying symmetry of ternary form — a journey out and a return.' },
    { h:'The A section — a complete statement', body:'The first <b>A</b> section of a ternary form is a complete, closed musical statement — it typically ends with a solid cadence in the tonic, so it feels <i>finished</i> in its own right. This self-sufficiency is what distinguishes ternary from binary: in binary, the first section leans away to the dominant and feels incomplete, but in ternary the A section stands whole, and the B section is a genuine departure from something already settled.', harp:'Play an A section in C that closes firmly at home on a full C-major cadence — no leaning away, no loose ends. On the harp, let that closure be real and complete; the more finished A feels, the more the coming B section will register as a true change of scene.' },
    { h:'The B section — genuine contrast', body:'The middle <b>B</b> section exists to provide <b>contrast</b>, and it can differ from A in almost any way: a new <i>key</i>, a new <i>theme</i>, a new <i>texture</i>, a shift from loud to soft, or from smooth to detached. The greater the contrast, the more vividly A’s eventual return will shine. Often B moves to a related key — the dominant, or in a major-key piece sometimes the parallel or relative minor — to colour the middle with a different harmonic light.', harp:'Here your levers earn their keep: flip the levers to move your B section into a contrasting key — say A minor or F major — so the middle genuinely <i>sounds</i> different. Changing register too, playing B lower or higher than A, deepens the contrast the harp can paint.' },
    { h:'The return of A — homecoming', body:'When the opening <b>A</b> returns, it delivers the emotional payoff of the whole form: recognition and homecoming. The return may be an exact repeat, or it may be varied and embellished — in a <b>da capo aria</b>, singers traditionally added their own ornaments to the reprise, so the same music returned newly decorated. Either way, the listener’s pleasure comes from meeting a familiar friend again after the excursion of B.', harp:'Reset your levers to C major and bring back your A tune — but this time ornament it, adding rolls or passing notes as a da-capo singer would. The harp reprise, dressed in fresh decoration, turns a simple repeat into an expressive homecoming.' },
    { h:'Da capo — “from the head”', body:'The phrase <b>da capo</b> (Italian for “from the head”) is the instruction that literally creates many ternary forms: after the B section, the score simply says <i>D.C.</i>, telling the performer to go back and play A from the beginning. This is why the <b>da capo aria</b> is a textbook ternary form — its ABA shape is produced not by writing A out twice, but by a single instruction to return. Form and notation, elegantly, are one and the same here.', harp:'Treat your own piece as a da capo: play A, play B, then — without new music — simply return to the top and play A again. On the harp, obeying your own “D.C.” is a lovely way to feel how a single instruction can build an entire three-part form.' }
  ]},
  { n:72, title:'Sonata & Rondo', quiz:[
    {q:'What are the three main sections of sonata form?',a:'The exposition (which presents two contrasting themes in two different keys), the development (which fragments and transforms that material through unstable, modulating passages), and the recapitulation (which restates the themes, now with both in the home key).'},
    {q:'What is the key drama at the heart of sonata form?',a:'In the exposition, the second theme appears in a foreign key (the dominant, or relative major in minor), creating tonal tension; in the recapitulation that theme returns in the tonic, resolving the tension. The form is a journey away from home and back.'},
    {q:'What is the defining feature of rondo form?',a:'A recurring refrain (A) that keeps returning between contrasting episodes, giving shapes like ABACA — the main theme comes back again and again like a chorus.'} ], lessons:[
    { h:'Sonata form — the grand drama', body:'<b>Sonata form</b> is the towering architecture of the Classical era, and at heart it is an expansion of rounded binary into a three-part drama: <b>exposition</b>, <b>development</b>, and <b>recapitulation</b>. The exposition sets up a conflict between two themes in two keys; the development throws that material into turbulence; and the recapitulation resolves everything by bringing the themes home. It is storytelling in sound — tension proposed, intensified, and finally released.', harp:'Think of your harp piece as a three-act play: Act I introduces two contrasting tunes, Act II unsettles them, Act III brings them home reconciled. Even holding this map in mind as you improvise gives your playing the narrative arc that sonata form is built to create.' },
    { h:'The exposition — two themes, two keys', body:'The <b>exposition</b> lays out the raw material. It presents a <b>first theme</b> in the home key, then, via a modulating <b>transition</b>, a contrasting <b>second theme</b> in a <i>different</i> key — the <b>dominant</b> in a major-key sonata, or the relative major in a minor-key one. This <i>tonal conflict</i> between the two key areas is the engine of the entire form; the whole drama exists to eventually reconcile it. The exposition is often repeated, a legacy of its binary ancestry.', harp:'Play a first theme in C major, then use your levers to shift into G major for a contrasting second theme. That lever-flip to the dominant is the harp physically enacting the tonal conflict — two tunes, two homes, tension you can hear and feel in your hands.' },
    { h:'The development — turbulence and transformation', body:'The <b>development</b> is the stormy middle, where the composer takes the exposition’s themes and <i>transforms</i> them — fragmenting motives, spinning them through rapid modulations, and passing them through many keys without settling in any. It is deliberately <b>unstable</b>, building suspense and making us long for stability. It usually ends on the dominant of the home key — a great held breath — preparing the triumphant return of the opening.', harp:'Take a motive from your first theme and put it through the wringer on the harp: play it, flip levers to a new key, play it again, keep moving restlessly. That refusal to settle, tumbling through key after key, is the developmental turbulence your levers make possible.' },
    { h:'The recapitulation — resolution at home', body:'The <b>recapitulation</b> is the homecoming that resolves the drama. It restates the themes from the exposition, but with one crucial change: the <b>second theme</b>, which first appeared in a foreign key, now returns <i>in the tonic</i>. This is the whole point of the form — the tonal conflict set up at the start is finally dissolved by pulling everything into the home key. What began as tension between two keys ends as unity in one.', harp:'Replay your first and second themes on the harp — but this time, keep the second theme in C major too, resolving the levers back home. Hearing the once-foreign second tune sing in the home key is the deep satisfaction of the recapitulation, delivered by simply not flipping the lever this time.' },
    { h:'Rondo — the returning refrain', body:'<b>Rondo form</b> works on a wonderfully simple principle: a main theme, the <b>refrain</b> (A), keeps coming <i>back</i> between contrasting <b>episodes</b>, giving patterns like <b>ABACA</b> — and often longer, such as ABACABA. The refrain acts like a chorus you keep returning to, while each episode (B, C…) offers fresh material and often a new key. Its recurring-theme charm made the rondo a favourite for lively final movements.', harp:'Play a catchy A refrain in C major on the harp and commit it to memory. Then play a B episode, return to A, play a C episode, and return to A once more — ABACA. Because the refrain always comes home to C, your levers rest for it and move only for the episodes, letting the refrain feel like a familiar homecoming every time.' }
  ]}
]},

  { sem:10, kicker:'Colour beyond the key', title:'Advanced Chromaticism', sub:'The lush harmonies of late-Romantic and beyond',
  src:'Adapted from “Open Music Theory,” v.2 (CC BY-SA 4.0) — the Chromaticism unit by the OMT team. Taught here in our own words and mapped to the lever harp.', chapters:[
  { n:73, title:'Chromatic Sequences', quiz:[
    {q:'What is a sequence, in one sentence?',a:'A short musical pattern that repeats immediately at a different pitch level, usually stepping up or down by a consistent interval each time.'},
    {q:'In a descending-fifths sequence made chromatic, what turns each chord into a mini-dominant of the next?',a:'Adding a raised third (an applied, or “secondary,” dominant) so that every chord leans onto the one a fifth below it, like a chain of V–I motions.'},
    {q:'Why does a repeating pattern let you get away with notes outside the key?',a:'Because the ear latches onto the pattern itself; once it hears the shape repeating, it accepts the chromatic notes as part of that shape rather than as mistakes.'}
  ], lessons:[
    { h:'What a sequence is', body:'A <b>sequence</b> is a small musical idea — a couple of chords or a melodic snippet — that repeats straight away, transposed to a new pitch each time. Think of walking down a staircase: the same step shape, just lower and lower. Composers love sequences because they give music a feeling of purposeful travel, and because a repeating shape is so satisfying to the ear that it will happily carry unusual notes along for the ride. The whole of this chapter rests on that one idea: <i>pattern first, chromaticism second</i>.', harp:'On the lever harp a diatonic sequence is a joy — you just move the same finger shape down the strings, no levers at all. A stepwise descending pattern in C major stays entirely on open strings. Feel that repeating hand-shape first; it is the anchor everything chromatic will hang from.' },
    { h:'The descending-fifths sequence with applied chords', body:'The most famous engine in tonal music is the <b>descending-fifths sequence</b>: chords whose roots fall by a fifth each time (C to F to B to E…), a chain that eventually circles all the way home. Make it <i>chromatic</i> by turning each chord into an <b>applied dominant</b> — a chord borrowed to act as the “V of” the next chord — by raising its third. Now instead of a plain C chord going to F, you get a C7 that genuinely pulls to F, then an F7 that pulls to B♭, and so on. Each link is a tiny, urgent V–I, and the ear reads the whole glittering chain as one smooth descent.', harp:'This is where the lever harp asks for honesty: each applied dominant needs a raised third, so a true chromatic circle-of-fifths means flipping levers as you go. In practice harpists pre-set the levers for one or two key applied chords they will pass through, or arpeggiate the pattern slowly enough to flip a single lever between chords. One raised string per link is realistic; a full chromatic cascade at speed is not — choose your two or three richest links and let the rest stay diatonic.' },
    { h:'Ascending and descending 5–6 sequences', body:'Another workhorse is the <b>5–6 sequence</b>, named for the voice that wiggles between a fifth and a sixth above the bass to avoid clashing parallel fifths as the pattern climbs or falls. In its <b>ascending</b> form the music rises step by step with a gentle lift on every beat; in its <b>descending</b> form it eases downward. Chromaticism sneaks in beautifully here, because that little 5–6 motion can be spiced with raised or lowered notes without disturbing the pattern the ear is tracking. It is one of the smoothest ways to drift toward far-off harmonic colours.', harp:'The 5–6 wiggle is lovely on harp because it is a single moving voice over a held bass — set the bass string ringing, then rock one finger between two adjacent strings for the 5 and the 6. If the sequence stays diatonic you need no levers at all; when you want a chromatic tint, flip only the one string that carries the 5–6 motion and leave the rest of the hand shape untouched.' },
    { h:'Why the pattern licenses the colour', body:'Here is the secret worth memorising: <i>a sequence buys you chromatic freedom</i>. On its own, a strange chord can sound like a wrong turn, but slot that same chord into a clearly repeating pattern and the ear forgives it instantly, hearing it as “the next rung of the ladder.” This is why late-Romantic composers reach for sequences the moment they want to wander far from the key — the pattern is a passport. Once the sequence ends, the music can arrive somewhere surprisingly distant, having felt logical the whole way.', harp:'Practise this as a mindset, not just fingering: pick a two-chord shape, lock it into your hand, and repeat it down three or four positions, flipping the minimum levers the pattern demands. Because your hand is doing the “same” thing each time, the lever flips feel like part of the choreography rather than interruptions — the very trick that lets the harp, a diatonic instrument, sound convincingly chromatic.' }
  ]},
  { n:74, title:'Common-Tone Chords', quiz:[
    {q:'What holds still in a common-tone chord while everything else moves?',a:'A single pitch — the “common tone” — is sustained in one voice while the surrounding notes slide chromatically away and back to it.'},
    {q:'What does a CT°7 typically decorate, and where does it resolve?',a:'It usually embellishes a single chord (often the tonic or the dominant), colouring it with neighbouring notes and then resolving straight back to that same chord.'},
    {q:'Why is a common-tone chord ideal for the lever harp?',a:'Because one string stays ringing the whole time, so at most you flip the levers on the few strings that move — the held note needs no change.'}
  ], lessons:[
    { h:'The idea of a held note', body:'A <b>common-tone chord</b> is built around one note that refuses to move. While that single pitch rings on, the other voices drift outward by half steps into a colourful chord and then slide right back, as if the music took a breath and returned. Because the held note ties the two moments together, the ear never loses its bearings — the excursion feels like decoration, not departure. This is chromaticism at its most elegant and least threatening.', harp:'This is the lever harp’s favourite kind of chromatic chord. Sound the common tone and let that string ring untouched; you now only have to worry about the two or three neighbours that move. On a lever instrument, “the string that never changes” is a gift — it does all the work of keeping you oriented while you flip a lever or two around it.' },
    { h:'The common-tone diminished seventh (CT°7)', body:'The star of the family is the <b>common-tone diminished seventh</b>, written <b>CT°7</b>. You take a chord — say, the tonic — keep one of its notes, and wrap a fully diminished seventh chord around that held note using upper and lower chromatic neighbours. It shimmers for a beat, then every neighbour resolves by step back into the original chord. A classic use is to decorate the tonic at the start of a phrase, giving it a sudden sparkle before it settles. Crucially, the CT°7 does <i>not</i> function as a dominant; it is pure colour, resolving to the very chord it grew out of.', harp:'Set your tonic ringing, keep its root string open, and build the diminished neighbours around it — typically this means raising or lowering two or three strings by a lever each. Because the diminished seventh is symmetrical, the flips are often a tidy pair. Sound the shimmer, then let the levers (or your fingers on already-set strings) fall back so the tonic re-emerges clean. One held string, two moving levers: entirely achievable.' },
    { h:'The common-tone augmented sixth (CT+6)', body:'Its cousin is the <b>common-tone augmented sixth</b> (<b>CT+6</b>), which does the same held-note trick but wraps an augmented-sixth-flavoured chord around the sustained pitch instead of a diminished seventh. It has a warmer, more yearning colour, and like its sibling it resolves neighbour-by-neighbour back to the chord it decorated — most often the tonic or the dominant. Composers reach for it when they want that ache of chromatic tension without actually going anywhere. Think of it as a sigh over a held pedal note.', harp:'Again the recipe is a ringing common tone plus a small cluster of moving neighbours. The augmented-sixth colour asks for one raised and one lowered string around the held pitch, so plan two lever flips and leave everything else alone. Because the held note anchors the harmony, you can take a moment to set those levers — the sustained string covers you musically while your hand works.' },
    { h:'When and why to use them', body:'Common-tone chords are the polite chromatic guests: they add a flash of far-away colour, then tidy up after themselves by resolving home. You will meet them prolonging a tonic at the start or end of a phrase, or dressing up a dominant before a cadence. Because they never truly modulate, they are a wonderful first taste of “deep” chromaticism — all the lushness of a strange chord with none of the risk of getting lost. Learn to hear the held note and you will spot them everywhere in Romantic music.', harp:'Make these part of your expressive vocabulary: a CT°7 over a ringing tonic is a beautiful way to open or close a piece on the harp, and it costs you only a couple of lever changes over a sustained string. Because the anchor tone never moves, these are among the very few genuinely chromatic chords the lever harp can voice cleanly and repeatedly — treasure them.' }
  ]},
  { n:75, title:'Harmonic Elision and Chromatic Modulation', quiz:[
    {q:'What is a harmonic elision?',a:'When an expected resolution is skipped: a dominant or diminished chord resolves not to the chord you predicted, but to a similar-sounding one that takes its place, sidestepping the expectation.'},
    {q:'What is a pivot chord in modulation?',a:'A chord that belongs to both the old key and the new key, so it can be reinterpreted mid-stream to swing the music smoothly from one key to the other.'},
    {q:'How does a chromatic slide reach a distant key?',a:'By moving one or more voices by half step into a chord of the new key, rather than relying on a shared diatonic chord — a direct, colourful shortcut to far-off tonalities.'}
  ], lessons:[
    { h:'Setting up an expectation', body:'Tonal music constantly makes promises: a dominant seventh promises to land on its tonic, a diminished seventh promises a particular resolution. <b>Harmonic elision</b> is the art of breaking that promise on purpose. The chord you expected is “elided” — skipped over — and in its place comes a different chord that resolves the tension in a similar but subtly wrong direction. The delicious result is a surprise that still feels like an answer, just not the one you predicted.', harp:'To hear this on the harp, play a strong V7 and deliberately resolve it somewhere unexpected — not to the tonic your ear wants, but a step or a lever away. Notice how one changed string can redirect the whole gesture. Elision on a lever instrument often costs just a single flip: the same shape, resolved to a neighbour rather than the goal.' },
    { h:'How elision works', body:'The trick relies on the fact that certain chords sound alike — a dominant seventh and a chord a half step away can share a similar pull. When the music resolves a dominant, it can slip to that near-neighbour instead, suppressing the expected chord entirely. Because the substitute is functionally close, the ear accepts it; because it is not what was promised, the moment lands with a frisson. Composers use elision to keep phrases moving forward, refusing to let the music settle where you thought it would.', harp:'Practise resolving a dominant to a chord one half step off from its true tonic. On the harp this usually means flipping one lever so the “landing string” lands a semitone away from expectation. Keep the rest of your hand shape identical — the surprise comes entirely from that one redirected note, which is exactly why the effect is within reach of a diatonic instrument.' },
    { h:'Modulating by pivot', body:'The gentlest way to change key is the <b>pivot modulation</b>: find a chord the two keys share, sit on it, and then reinterpret it as belonging to the new key. The chord that was, say, chord IV in the old key becomes chord I in the new one, and the music has quietly crossed the border with no jolt at all. Pivots are how classical music travels to <i>closely</i> related keys — the shared chord is the bridge, and the listener barely feels the crossing.', harp:'Pivot modulation is the harpist’s friend because the shared chord often needs no lever change at all — it lives in both keys already. You set your levers for the new key <i>during</i> the pivot, while that common chord rings, so by the time you have arrived, your hand is ready. Plan the flip to happen on the pivot itself and the modulation will sound seamless.' },
    { h:'Chromatic slides to distant keys', body:'For bolder journeys to <i>distant</i> keys, composers skip the shared chord and simply <b>slide chromatically</b> — nudging one or two voices by half step until a chord of the far-off key appears. There is no diatonic bridge; the smoothness of the half-step motion is the bridge. This is how Romantic music lurches thrillingly from one remote colour to another, and it pairs naturally with elision and sequence, which also lean on half-step voice-leading.', harp:'This is the demanding case for a lever harp: a chromatic slide to a distant key can mean resetting several levers, which takes time. The practical solution is to slide during a sustained note or a rest, or to pre-plan a passage that only slides the one or two strings you can flip in the moment. Be honest about which distant modulations your hands can voice live, and reserve the rest for arranged, pre-set passages.' }
  ]},
  { n:76, title:'Reinterpreting the Diminished Seventh and Augmented Options', quiz:[
    {q:'Why can one diminished seventh chord lead to so many keys?',a:'Because it is symmetrical — stacked entirely in minor thirds — so it sounds the same from any of its notes, and each note can be heard as the leading tone of a different key.'},
    {q:'What makes the augmented triad harmonically ambiguous?',a:'It divides the octave into equal major thirds, so like the diminished seventh it has no single “home,” and any of its notes can act as the root, pointing toward several keys at once.'},
    {q:'What is an equal division of the octave?',a:'Splitting the octave into same-sized steps — into three major thirds (augmented triad) or four minor thirds (diminished seventh), or six whole tones — creating symmetrical, rootless colours.'}
  ], lessons:[
    { h:'The symmetrical diminished seventh', body:'A fully <b>diminished seventh</b> chord is built from nothing but stacked minor thirds, which makes it perfectly <i>symmetrical</i>: rotate it and it looks the same from every note. That symmetry is a superpower for modulation, because any of its four notes can be reinterpreted as the leading tone — the note a half step below tonic — of a different key. A single diminished seventh can therefore pivot to four (really many more, once you respell it) far-flung destinations. It is the great chameleon of chromatic harmony.', harp:'On the harp the diminished seventh is a compact, symmetrical grip that repeats up the strings every minor third, so it is easy to finger. Reinterpreting it to a new key, though, means the resolution needs whatever levers that key requires — the chord itself may be lever-free, but the destination is not. Set the arrival key’s levers while the ambiguous chord rings; its symmetry buys you a moment of harmonic stillness to prepare.' },
    { h:'One chord, many keys', body:'Because the diminished seventh can be respelled — the same sounds written with different note-names — it can act as the pivot into an astonishing range of keys, near and distant alike. Composers exploit this to make sudden, magical key changes that would be impossible with an ordinary shared chord. Hold the diminished seventh, decide which of its notes will become the leading tone, resolve accordingly, and you have teleported. It is the classic “mystery chord” of nineteenth-century opera and film underscore alike.', harp:'Treat the diminished seventh as your modulation launchpad. Because it is symmetrical, one fingering can be aimed at several keys — the choice happens in the resolution, not the chord. Practise arriving from the same held diminished grip into two or three different keys, pre-setting each destination’s levers, and you will have a versatile, genuinely chromatic tool that a lever harp can actually perform.' },
    { h:'Augmented triads and whole-tone colour', body:'The <b>augmented triad</b> — two stacked major thirds — is the diminished seventh’s cousin in ambiguity. It too divides the octave evenly, so it has no obvious root and can slip toward several keys. Pile up more of these equal steps and you get the <b>whole-tone</b> sound: a scale of nothing but whole steps, dreamlike and floating, with no leading tone to pull you home. Debussy built shimmering worlds from this colour, precisely because its symmetry dissolves the usual sense of key.', harp:'Augmented triads sit neatly under the hand as stacked major thirds and repeat every major third up the strings. The whole-tone scale, though, demands a fixed pattern of raised and lowered strings — once you set those levers, you can run the whole-tone colour freely without further changes, which makes it surprisingly harp-friendly for a whole passage. Set the levers once, then float.' },
    { h:'Equal divisions of the octave', body:'Step back and you will see a single beautiful idea: <b>equal divisions of the octave</b>. Split the octave into three equal parts and you get the augmented triad; into four, the diminished seventh; into six, the whole-tone scale. Each is symmetrical, rootless, and therefore free to move in any direction — the harmonic equivalent of a spinning compass. Late-Romantic and early-modern composers used these symmetrical structures to escape the gravity of a single key entirely.', harp:'Because these structures repeat at a fixed interval, they map onto the harp as a single hand-shape you can transpose up the strings — a real ergonomic bonus. The catch is always the levers: a symmetrical chord may be easy to grip but its chromatic notes still need setting. Learn the lever “preset” for one whole-tone collection and one diminished shape, and you unlock a large swath of this repertoire on a diatonic instrument.' }
  ]},
  { n:77, title:'Altered and Extended Dominants', quiz:[
    {q:'What does it mean to “alter” a dominant chord?',a:'To raise or lower one of its notes chromatically — commonly the fifth or ninth — sharpening the chord’s tension and its pull toward resolution.'},
    {q:'Name two common alterations to a dominant and what they add.',a:'A ♭9 adds dark bite and urgency; a ♯11 (or ♭5) adds a bright, tangy shimmer. (♯9 and ♭13 are also common, each intensifying the pull home.)'},
    {q:'What is an extended dominant?',a:'A dominant chord stacked with higher tones — the ninth, eleventh, or thirteenth — making a “taller,” richer chord that still functions as a dominant.'}
  ], lessons:[
    { h:'Taller chords', body:'So far a chord has topped out at the seventh, but you can keep stacking thirds to reach the <b>ninth</b>, <b>eleventh</b>, and <b>thirteenth</b> — the <b>extended dominants</b>. Each added storey deepens the chord’s colour without changing its job: it is still a dominant, still pulling toward home, just wearing a richer coat. These lush stacks are the sound of late-Romantic harmony and of jazz, where a bare V7 can feel almost plain by comparison. The higher you build, the more shimmer you add to the pull.', harp:'Extended dominants are a natural fit for the harp because you can simply arpeggiate up through the stack — root, third, seventh, ninth, thirteenth — as a rolling gesture across many strings. If the extensions are diatonic to your current lever setting, they cost nothing extra; the harp’s wide, resonant range makes these tall chords sound especially gorgeous. Roll them and let the overtones bloom.' },
    { h:'Altering the fifth and ninth', body:'Beyond stacking, you can <b>alter</b> the dominant — bend one of its notes by a half step. Lower or raise the fifth, or add a <b>♭9</b> or <b>♯9</b>, and the chord grows teeth. A <b>♭9</b> in particular adds a dark, almost anxious urgency, tightening the chromatic squeeze on the resolution to come. These altered tones are chromatic notes that want to resolve, so they heighten the sense that the music <i>must</i> move home. It is tension deliberately loaded into the spring.', harp:'Altered tones mean lever flips: a ♭9 or altered fifth is a chromatic string that must be set before the chord sounds. The good news is that a dominant usually resolves quickly, so you set the altered string, sound the tense chord, and flip it back as you resolve — a brief, purposeful lever move. Pick the one alteration that colours the chord most and voice that; you rarely need all of them at once.' },
    { h:'The upper alterations: ♯11 and ♭13', body:'Two more alterations round out the palette. The <b>♯11</b> (the same sound as a ♭5) casts a bright, glassy, slightly unstable glow — the “Lydian dominant” shimmer beloved of film composers. The <b>♭13</b> adds a smoky, bittersweet weight up top, leaning the chord toward its resolution with a sigh. Combine several alterations and you reach the fully “altered dominant,” a chord bristling with chromatic tension that resolves with enormous satisfaction. Each alteration is a different flavour of <i>wanting to go home</i>.', harp:'These upper alterations are, again, specific strings to flip. Because they live high in the chord, you can often add just the coloured extension as a top note over an otherwise diatonic dominant — one lever, one gleaming tension tone. That is the realistic lever-harp approach to altered dominants: not the whole bristling stack, but one well-chosen chromatic colour placed where it rings out.' },
    { h:'Why alterations heighten the pull', body:'Every alteration and extension serves one master: the return home. By packing the dominant with extra chromatic notes — each of them a step away from a note in the tonic chord — you multiply the little tensions that resolve when the music finally lands. The effect is like winding a spring tighter; the release is proportionally sweeter. This is why a richly altered dominant can make even a simple resolution feel like a grand arrival.', harp:'Use this understanding to spend your lever changes wisely. Since the payoff is the resolution, favour the one or two alterations whose resolving motion you can actually voice on the harp, and let those carry the tension. A single ♭9 flipped back to the octave as you resolve can deliver most of the “grand arrival” feeling — proof that you do not need the whole altered stack to reap its expressive reward.' }
  ]},
  { n:78, title:'Neo-Riemannian Moves and the Tonnetz', quiz:[
    {q:'What do the three basic transformations P, L, and R each do?',a:'Each moves a single voice by a small step to turn one triad into another: P (Parallel) swaps major and minor of the same root; L (Leittonwechsel) and R (Relative) each shift one note to reach a closely voiced neighbour chord.'},
    {q:'What is special about how these transformations connect chords?',a:'They link triads that share two common tones, moving only one voice by a step — so distant-sounding chords turn out to be a single small move apart.'},
    {q:'What is the Tonnetz?',a:'A grid-shaped map of all major and minor triads where neighbouring chords are a P, L, or R move apart, letting you navigate chromatic harmony as a journey across a network.'}
  ], lessons:[
    { h:'A new way to hear chords', body:'<b>Neo-Riemannian theory</b> throws out the idea that every chord must have a function (tonic, dominant, and so on) and instead asks a simpler question: how do you get from <i>this</i> triad to <i>that</i> one with the least motion? It is perfect for late-Romantic and film music, where chords glide around without obeying the old rules of key. The whole system is built from moves that change just one note at a time, which is why the harmony feels so smooth even when it wanders far. Think of it as harmony-as-choreography.', harp:'This voice-leading mindset suits the harp beautifully, because “move one note” often means flip one lever or shift one finger. Rather than thinking in keys, think in single string-changes: what is the nearest chord I can reach by altering one note? That question turns the diatonic harp into a surprisingly agile chromatic navigator.' },
    { h:'P, L, and R', body:'Three transformations do the heavy lifting. <b>P</b> (<i>Parallel</i>) turns a chord major-to-minor or back by moving the third a half step — C major becomes C minor. <b>L</b> (<i>Leittonwechsel</i>, “leading-tone exchange”) moves the root down a half step, turning C major into E minor. <b>R</b> (<i>Relative</i>) moves the fifth up a whole step, turning C major into A minor. Each one changes a single voice while two notes stay put, so the chords feel intimately connected even when their names look unrelated.', harp:'Try these on the harp as one-move gestures. P is a single lever flip on the third of the chord. L and R shift one note while two strings keep ringing — hold those common tones and move only the one that changes. Feeling P, L, and R under your hands as minimal changes is the most direct way to internalise how little motion chromatic harmony really requires.' },
    { h:'Chaining moves through distant chords', body:'The magic appears when you <b>chain</b> these moves. Apply L then P then L again and you slide, one voice at a time, into a chord that seemed a world away — yet every single step moved only one note. This is how Romantic composers reach gloriously remote harmonies while the voice-leading stays feather-smooth; the destination is distant but the path is tiny steps. A famous “L–R” chain, for instance, can cycle through a whole ring of chords with barely any motion at all.', harp:'Practise a short chain — say P then L then R — as a sequence of minimal lever-and-finger moves, holding common tones wherever you can. Because each step changes only one note, the harp can perform these chromatic journeys live, one flip at a time, in a way that a full chromatic modulation could never manage. The chain is your workaround for the harp’s diatonic limits.' },
    { h:'The Tonnetz as a map', body:'All of this is drawn on a beautiful grid called the <b>Tonnetz</b> (German for “tone network”): a lattice where every major and minor triad sits next to its P, L, and R neighbours. Navigating chromatic harmony becomes like reading a map — each move is a step to an adjacent tile, and long journeys are just paths across the network. The Tonnetz reveals that harmonies which sound impossibly far apart are often only a few tiles away, connected by the smallest of steps.', harp:'Keep a Tonnetz nearby as you compose or arrange for harp: plot your chord journey as a path across the grid, and each tile-to-tile step tells you exactly which one string to change. This turns abstract chromatic wandering into a concrete, lever-by-lever plan — arguably the single most practical bridge between deep chromatic theory and the realities of playing colourful harmony on a diatonic lever harp.' }
  ]}
]},

  { sem:11, kicker:'The modern sound-world', title:'Music Since 1900', sub:'Pitch-class sets, symmetry, and new collections',
  src:'Adapted from “Open Music Theory,” v.2 (CC BY-SA 4.0) — the 20th- & 21st-Century Techniques unit by the OMT team. Taught here in our own words and mapped to the lever harp.', chapters:[
  { n:79, title:'Pitch, Pitch-Class & Integer Notation', quiz:[
    {q:'In one sentence, what is the difference between a pitch and a pitch class?',a:'A pitch is one specific sounding tone at one specific height (like the C on your fourth-octave string), while a pitch class is the whole family of that note in every octave and every enharmonic spelling (every C, plus B♯, plus D𝄫) treated as “the same.”'},
    {q:'What integer do we give to C, and which note gets the number 6?',a:'C is 0, and we count upward by semitone from there, so C=0, C♯=1, D=2, and by the time we reach the tritone above C we arrive at F♯ (which equals G♭), which is 6.'},
    {q:'Why do we bother numbering the notes 0–11 instead of just using letter names?',a:'Because once music lets go of a home key, enharmonic spellings like A♭ and G♯ no longer mean different things — numbering the twelve pitch classes 0–11 gives us one neutral name per sound, so we can measure and compare freely without a key telling us how to spell.'}
  ], lessons:[
    { h:'Pitch versus pitch class', body:'A <b>pitch</b> is a single sounding tone at one specific height: the C on your fourth-octave harp string is a pitch, and it is <i>not</i> the same pitch as the C an octave lower. A <b>pitch class</b>, by contrast, is a whole family — every C in every octave, gathered into one idea, because we hear them as versions of “the same note.” Set theory leans on this distinction constantly, so it helps to feel the difference early: pitch is the physical string you pluck; pitch class is the note-name floating free of octave.', harp:'Play every C string up and down your harp, top to bottom. Each is a different <i>pitch</i>, but together they are one <i>pitch class</i> — octave equivalence made audible. Your harp lays this out beautifully, since the same colour of string repeats every octave.' },
    { h:'Two kinds of “sameness”', body:'Pitch classes gather notes by two kinds of equivalence at once. The first is <b>octave equivalence</b> — C4 and C5 belong together — which your ear already accepts every time you call two strings an octave apart “C.” The second is <b>enharmonic equivalence</b>: A♭ and G♯ are counted as the same pitch class because, on a piano, you would press the same key. In tonal music these spellings mattered (A♭ pulls down, G♯ pulls up), but once a home key loosens its grip, the distinction quietly falls away.', harp:'Enharmonic equivalence is the very thing your levers exploit. Raising a G string with its lever gives you G♯ — the same string that, thought of another way, could be an A♭ in a different key. One string, two spellings, one pitch class.' },
    { h:'Integer notation: numbering the twelve', body:'When A♭ and G♯ are truly “the same,” seven letter names can no longer label twelve distinct sounds cleanly. So set theory numbers the pitch classes with <b>integers</b> 0 through 11, fixing <i>C = 0</i> and counting up one semitone at a time: C♯/D♭ = 1, D = 2, and so on to B = 11. The number is deliberately neutral — 8 simply means “the pitch class we spell G♯ or A♭,” with no opinion about which. This gives us a plain, key-free vocabulary to do arithmetic with.', harp:'Try naming your open (lever-down) strings as integers in E♭ tuning: E♭=3, F=5, G=7, A♭=8, B♭=10, C=0, D=2. Notice they are not a tidy run of numbers — that gapped pattern <i>is</i> the diatonic scale seen through the post-tonal lens.' },
    { h:'The clock face', body:'The friendliest picture of the twelve pitch classes is a <b>clock face</b>: 0 sits at the top where twelve would be, and the numbers run clockwise round to 11, so the notes close back into a circle exactly as octaves do. Moving clockwise raises by semitone; moving counter-clockwise lowers. This little diagram will do an astonishing amount of work in the coming chapters — measuring intervals, packing sets tightly, and revealing symmetry all become things you can simply <i>see</i>.', harp:'Draw a twelve-point clock and mark which numbers your current lever setting can actually sound. In plain E♭ tuning you will light up seven of the twelve points; the five dark points are the notes you would need a lever change (or a retune) to reach.' }
  ]},
  { n:80, title:'Intervals in Integer Notation', quiz:[
    {q:'Why do post-tonal analysts often prefer “7 semitones” to “perfect fifth”?',a:'Because a tonal name like “perfect fifth” carries assumptions about key and spelling that atonal music has abandoned; counting semitones (7) describes the raw distance neutrally, treating G–D and G–E𝄫 as the same sound rather than as different intervals.'},
    {q:'What is an ordered pitch interval, and what does the +/– sign add?',a:'An ordered pitch interval is the exact number of semitones between two specific pitches, and the plus or minus sign records direction — +7 means up a seventh of a semitone-count, –7 means down the same distance — so it is the most concrete, most specific kind of interval.'},
    {q:'There are only six interval classes (1–6). Why can’t there be a “7”?',a:'Because interval class is the shortest distance around the clock, and once a gap reaches 7 it is quicker to travel the other way (12 − 7 = 5), so anything larger folds back: 7 becomes 5, 8 becomes 4, and 6 (the tritone) is the farthest two pitch classes can ever be.'}
  ], lessons:[
    { h:'Why measure distance without a key', body:'In tonal music the flavour of an interval depends on the key: G up to B♭ is a cosy minor third in G minor, yet respelled G to A♯ it is a spiky augmented second somewhere else — same keys on a piano, different tonal meanings. Atonal music has let go of that key, so those distinctions stop earning their keep. Instead we simply <b>count semitones</b>, which gives every interval one honest number and lets us compare freely.', harp:'Pluck two strings and count the half-steps between them rather than naming a “third” or “fifth.” On a lever harp this is refreshing, because a lever change can turn your “major third” into a “minor third” without moving your hands — the semitone count tells the truth about what actually sounds.' },
    { h:'Ordered vs. unordered pitch intervals', body:'A <b>pitch interval</b> counts semitones between two specific pitches, octaves included, so C4 up to E4 is 4, but C4 up to E5 is 16. Making it <b>ordered</b> adds a sign for direction: +16 climbs, −16 falls. Dropping the sign gives the <b>unordered</b> pitch interval — just the distance, 16, with no up-or-down — which suits harmonies where two notes simply sound together and direction is beside the point.', harp:'Play a low C then a high E: that is an ordered leap of +16 up your strings, and your hand physically travels that far. Now sound them together — the same two strings become an unordered interval of 16, a fixed harmonic colour with no direction at all.' },
    { h:'Pitch-class intervals: onto the clock', body:'When we stop caring about octaves and look only at pitch <i>classes</i>, we measure around the clock face instead. An <b>ordered pitch-class interval</b> always travels clockwise (upward): from C to E is 4, but from E back to C is 8, because you keep going clockwise the long way round. It is the same journey seen as a one-way trip around the circle, and the two directions no longer add up to a simple sign flip.', harp:'Set out your strings mentally as the clock and walk clockwise from one lever-note to another, counting points. Because your diatonic tuning only lights seven of the twelve points, some clockwise distances will “skip over” dark points — a vivid picture of the gaps in the scale.' },
    { h:'Interval classes: the six true distances', body:'The most abstract interval is the <b>interval class</b> (IC) — the <i>shortest</i> way round the clock, going whichever direction is closer. Because anything past 6 is quicker the other way, only six values survive: IC 1 through IC 6. So a pitch-class interval of 7 collapses to IC 5, an 8 to IC 4, and the tritone stays IC 6, the greatest possible separation of two pitch classes. Interval class is how we ask, at the deepest level, “how far apart are these two notes, really?”', harp:'A tritone (IC 6) on your harp — say F up to B natural — needs a lever raise to reach the B, and it sits exactly opposite on the clock, six points away in either direction. Feel how it is the one interval that sounds equally “stretched” however you spell or approach it.' }
  ]},
  { n:81, title:'Pitch-Class Sets, Normal Order & Transposition/Inversion', quiz:[
    {q:'What is a pitch-class set, and what is “normal order”?',a:'A pitch-class set is simply any group of pitch classes taken as a unit; its normal order is the most compact way to write that group in ascending order — the arrangement that squeezes the notes into the smallest span around the clock, giving us a standard name for comparison.'},
    {q:'How do you transpose a set by T5?',a:'You add 5 to every integer in the set, wrapping around at 12 (mod 12) as on a clock — so {0, 4, 7} under T5 becomes {5, 9, 0}, the whole shape slid five semitones clockwise while keeping its intervals intact.'},
    {q:'In plain terms, what does inversion (TnI) do to a set’s shape?',a:'Inversion flips the set around the clock like a mirror — each note reflects to its complement — so the intervals are preserved but their arrangement turns upside down, which is why an inverted gesture sounds related to the original yet clearly “answered” rather than merely moved.'}
  ], lessons:[
    { h:'A “set” is just a group of notes', body:'When we treat any group of pitch classes as a single unit, we call it a <b>pitch-class set</b> (often “pc set”). It need not be a chord you would recognise — any handful of notes gathered from a melody or texture can be a set, chosen because they seem to belong together. The power of the idea is that it lets us name, compare, and track a group of notes even when no key would call them a chord. Segmentation — deciding <i>which</i> notes to group — is the analyst’s real art, and we return to it later.', harp:'Choose any three or four strings and declare them a set — say C, E♭, and G ({0, 3, 7}). That is a pc set you can actually pluck. Even a “wrong-sounding” grab of strings is a legitimate set; the theory does not require it to be pretty.' },
    { h:'Normal order: packing it tight', body:'To give a set a standard name we put it in <b>normal order</b> — the most compact ascending arrangement, the rotation that fits the notes into the smallest possible span. The recipe: list the pitch classes rising within an octave, try each rotation, and keep the one whose outer notes are closest together (packed tightest to the bottom if there is a tie). On the clock face this is easy to see — you simply rotate to find the tightest cluster, then read clockwise from its lower edge.', harp:'Take C, G, and E♭ — grab them out of order across your strings, then reorder them as {0, 3, 7}, the tight packing. Playing them low-to-high in that spacing lets your ear confirm what normal order shows the eye: the most gathered-up form of the group.' },
    { h:'Transposition (Tn): sliding the shape', body:'To <b>transpose</b> a set by Tn, add <i>n</i> to every integer, wrapping around at 12. This slides the entire shape clockwise while preserving every interval inside it — the reason a transposed motive sounds like the same gesture “moved,” as when Debussy lifts a motive four semitones higher to depict a cathedral rising from the water. Transposition is both an <i>operation</i> you perform and a <i>measurement</i> of the distance between two related sets.', harp:'Play {0, 3, 7} (C, E♭, G), then T5 it to {5, 8, 0} (F, A♭, C). If your levers can voice both, you will hear the identical shape simply relocated — though be honest that a diatonic harp cannot transpose <i>every</i> set cleanly, since some targets fall on strings your current tuning cannot reach.' },
    { h:'Inversion (TnI): the mirror', body:'<b>Inversion</b> reflects a set around the clock: take each integer’s complement (its mirror across 0), which you can do by subtracting from 12, and the shape flips upside down while its intervals survive. Combined with a transposition this becomes <b>TnI</b> — invert, then slide by <i>n</i>. Inverted gestures sound kindred to the original but clearly “answered,” the intervals stacked the other way up, which composers use to echo an idea while turning it over.', harp:'Mirror a set on your strings: {0, 1, 4} inverts to {0, 11, 8}, i.e. {8, 11, 0}. Set it up as a physical reflection around your C string and pluck both forms back to back — the family resemblance is unmistakable even though the contour has flipped.' }
  ]},
  { n:82, title:'Set Class & Prime Form', quiz:[
    {q:'What is a set class?',a:'A set class is the whole family of pitch-class sets related to one another by transposition and/or inversion — every rotation, slide, and mirror-image of a given set gathered under one heading, so that sets which sound essentially “the same shape” share a single identity.'},
    {q:'What is prime form, and how is it written?',a:'Prime form is the single most compact, transposed-to-begin-on-0 representative that names an entire set class; it is written in parentheses, like (0 1 4), and is found by taking the most packed version of the set (checking its inversion too) and transposing it to start on 0.'},
    {q:'Why is grouping sets into set classes useful for analysis?',a:'Because it lets us recognise that many surface-different chords and motives are really the same underlying shape, so a piece built from, say, (0 1 6) sonorities reveals a unifying sound-world even when those sets appear transposed, inverted, and re-voiced all over the score.'}
  ], lessons:[
    { h:'From set to family', body:'Once we can transpose and invert a set, a natural question follows: which sets should count as “the same shape”? The answer is the <b>set class</b> — the family containing a set together with all its transpositions and inversions. Just as every major triad, in any key and any voicing, feels like “a major triad,” every member of a set class shares one intervallic identity. This is the move from naming individual chords to naming <i>kinds</i> of chord.', harp:'Think of the major triad you know well: C, F, G majors are different pitch sets but one family. Play a few major triads your levers allow and hear the single shared shape — that felt sameness is exactly what a set class captures, now generalised to any collection.' },
    { h:'Finding prime form', body:'To name a set class we pick one tidy representative: the <b>prime form</b>. You take the set’s most compact packing, compare it with the most compact packing of its inversion, keep whichever is squeezed tighter toward the bottom, and transpose that so it begins on 0. The result is written in parentheses, like (0 1 4) or (0 2 7). It is the set class’s “dictionary headword” — one label standing for every transposed and inverted appearance.', harp:'Take C, D♭, E ({0, 1, 4}); its prime form is already (0 1 4). Reflect and re-pack it a few ways on your strings and confirm you keep returning to the same tight three-note shape — that stubborn core, always startable from 0, is the prime form.' },
    { h:'Reading the set-class table', body:'Theorists have catalogued every possible set class into a <b>table</b>, each row giving a prime form and a <b>Forte number</b> (like 3–3 for a three-note class) plus extra data we will meet shortly. You do not memorise it; you use it, the way you use a chord chart — to look up a shape, confirm its identity, and find sets related to it. The table turns the sprawling variety of post-tonal harmony into a finite, searchable list of families.', harp:'Pick a three-note grab on your harp, work out its prime form, and locate it in a set-class table. Seeing “your” strings land at a named row makes the abstract catalogue suddenly concrete — the sound in your hands has an address in the book.' },
    { h:'A few sets with a strong character', body:'Some set classes have such a distinctive sound that composers reach for them deliberately. (0 1 6), for instance, pairs a tritone with a semitone and bites with tension; (0 2 7) is open and quartal, spacious and clean; (0 3 7) is simply our old friend the triad. Learning to hear a handful of these families gives your ear anchors in music that first seemed shapeless, letting you follow a piece by its recurring shapes rather than by key.', harp:'Voice (0 2 7) as C, D, G — a quartal, harp-friendly stack that rings openly across your strings. Contrast it with a tense (0 1 6) if your levers allow the tritone. Even diatonically, (0 2 7) sits so naturally on the harp that you can lean on it as your go-to modern-open colour.' }
  ]},
  { n:83, title:'Analyzing with Set Theory (and its limits)', quiz:[
    {q:'What is segmentation, and why is it the crucial first decision?',a:'Segmentation is choosing which notes to group together into sets before any analysis begins; it is crucial because the same passage yields completely different “results” depending on where you draw the boundaries, so the analyst’s grouping choices largely determine what the set theory will appear to reveal.'},
    {q:'Name one relationship between sets that set theory helps you spot.',a:'It helps you spot when two surface-different passages are transpositions or inversions of one another (or belong to the same set class), revealing a hidden kinship — a shared shape recurring, flipped or relocated, across a piece.'},
    {q:'What is one honest limitation of set theory?',a:'Set theory says nothing about rhythm, register, dynamics, timbre, or how a note actually functions in its moment — it measures pitch-class content only, so a “significant” shared set class can be musically irrelevant, and the method can find patterns that the ear never hears.'}
  ], lessons:[
    { h:'Segmentation: where analysis really begins', body:'Before you can label a single set you must decide which notes belong together — this is <b>segmentation</b>, and it is the heart of the whole enterprise. Do you group by beat, by phrase, by instrument, by what your ear clusters? Each choice yields different sets and therefore a different story, so honest analysis makes its segmentation explicit and defends it. The theory is only as meaningful as the groupings you feed it.', harp:'Take a short passage you play and try segmenting it two ways — by bar, then by melodic gesture — and work out the sets each gives. On the harp, hand position often suggests a natural grouping: notes taken in one placement of the hands frequently make a musical, defensible segment.' },
    { h:'Relationships the theory reveals', body:'Once segmented, sets can be <i>compared</i>, and this is where set theory earns its keep. You may discover that a later passage is the Tn or TnI of an earlier one, or that scattered chords all belong to one set class — hidden unities the ear may sense but could not name. Spotting these relationships lets you show how a piece coheres without a key, held together by recurring shapes rather than by tonic and dominant.', harp:'Find two moments in a piece that feel related and test whether their sets share a prime form. When they do, you have evidence for the kinship your ear suspected — and on the harp you can play both moments in turn to let the resemblance sound as well as compute.' },
    { h:'Being honest about the limits', body:'Set theory is a powerful lens, but a narrow one: it measures pitch-class content and <i>nothing else</i>. It is silent about rhythm, register, dynamics, timbre, and the felt function of a note in its phrase — all the things that may matter most to a listener. Worse, with enough freedom in segmentation you can “find” almost any relationship, whether or not anyone hears it. A good analysis therefore treats set theory as one voice among several, always checked against the ear.', harp:'Play a set class high and sparkling near the top of the harp, then low and thick near the soundboard: identical set, utterly different effect. That gap — everything the integers ignore — is exactly what set theory leaves out and why your ear must stay in charge.' },
    { h:'Using the tool wisely', body:'The healthiest stance is pragmatic: reach for set theory when it illuminates something — a genuine recurring shape, a transformational thread, a unifying family — and set it aside when it only generates numbers. Composers rarely thought in prime forms; the method is a listener’s and analyst’s aid, not a decoder ring for authorial intent. Used with judgement, it names patterns that deepen your hearing; used mechanically, it buries the music in labels.', harp:'Before trusting any set-theoretic “finding,” play the two passages on your harp and ask plainly: do these sound related? Let that honest hearing veto or confirm the numbers. The instrument in your lap is the final court of appeal.' }
  ]},
  { n:84, title:'Modes & New Collections', quiz:[
    {q:'How does a mode differ from a “collection” in this modern context?',a:'A mode centres one note as a tonic within a scale so it has a felt home and direction, whereas a collection is a source-set of pitches valued for its overall colour and symmetry, often with no single note claiming to be tonic — a palette rather than a key.'},
    {q:'What gives the whole-tone and octatonic collections their distinctive, “floating” quality?',a:'Their symmetry: the whole-tone scale is all whole steps (dividing the octave evenly) and the octatonic alternates half and whole steps, so both repeat their pattern under transposition and lack the leading-tone pull of a major scale, which is why they hover rather than resolve.'},
    {q:'Which of these collections sits most naturally on a lever harp, and why?',a:'The pentatonic and the diatonic modes sit most naturally, because a lever harp is a diatonic instrument tuned to seven notes per octave — pentatonic collections are reachable simply by favouring five of the open strings, and the church modes just re-centre those same diatonic pitches on a different home note.'}
  ], lessons:[
    { h:'Diatonic modes, modern context', body:'The seven <b>diatonic modes</b> — Ionian, Dorian, Phrygian, Lydian, Mixolydian, Aeolian, Locrian — are the familiar white-note scales re-centred on different home notes, and twentieth-century composers revived them precisely to escape major/minor gravity. Each mode keeps a tonic, so it still offers a home and a sense of direction, but its unusual scale degrees colour that home differently: Lydian brightens with its raised fourth, Phrygian darkens with its lowered second. They are a gentle first step from tonality into new sound-worlds.', harp:'Modes are the lever harp’s home turf. In E♭ tuning, playing the open strings from different starting notes already gives you several modes, and a single lever flip re-colours a whole passage — raise one string for Lydian shimmer, lower another for Phrygian shadow, all without leaving your diatonic strings.' },
    { h:'The whole-tone collection', body:'The <b>whole-tone collection</b> is built entirely of whole steps, six notes dividing the octave into perfectly equal parts. Because every step is identical, no note feels like a leading tone and nothing pulls toward a tonic — the music seems to <i>float</i>, weightless and dreamlike, which is why Debussy reached for it to evoke mist and water. Its symmetry means it maps onto itself under transposition, giving it a shimmering, directionless calm.', harp:'You can taste whole-tone colour on the harp by setting levers to sound a run of whole steps — for instance C, D, E, F♯, G♯, A♯ if your levers reach them. Only two whole-tone collections exist in all, so a careful lever plan can lock your harp into that floating, Impressionist haze across a whole passage.' },
    { h:'Octatonic, hexatonic and acoustic', body:'Three more symmetrical collections each carry a strong mood. The <b>octatonic</b> alternates half and whole steps through eight notes, rich and tense, beloved of Stravinsky and jazz alike; the <b>hexatonic</b> alternates half steps with minor thirds for a haunting, otherworldly glow; and the <b>acoustic</b> (or overtone) scale, like a Lydian-dominant, sounds bright and slightly tangy, echoing the natural overtone series. Each divides or colours the octave in its own way, offering the composer a ready-made atmosphere.', harp:'These fully symmetrical scales use notes outside any single diatonic tuning, so a lever harp cannot sound a complete octatonic collection cleanly — be honest about that. But you can reach fragments: a four-note slice of octatonic (a half-step-plus-whole-step cell) often falls under the hand with one lever change, enough to flavour a phrase.' },
    { h:'The pentatonic collection and choosing a colour', body:'The <b>pentatonic collection</b> — five notes per octave, with no semitones to clash — is the gentlest and most universal, ringing consonantly whatever order you play it in. In modern music it offers open, folk-tinged, or “Eastern” colour, and because it avoids the leading tone it too can hover peacefully. The lesson of this whole chapter is that each collection is a distinct <i>palette</i>: pick the one whose built-in mood matches the feeling you want, then let its symmetry or centre do the work.', harp:'Pentatonic is where the harp sings most freely: set your levers so five strings per octave form a pentatonic scale and every glissando becomes instantly beautiful, no wrong notes possible. This is the collection to lean on when you want the harp’s natural sparkle — the modern sound-world that fits your instrument like a glove.' }
  ]}
]}
];

/* ============================================================
   INTERACTIVE CIRCLE OF FIFTHS — built for the lever harp
   Adapted from "The Lever Harp: Key Signatures" & "Chords on the Scale".
   An E♭-tuned harp (B♭ E♭ A♭, all levers down) reaches a continuous
   arc of eight keys — E♭ B♭ F C G D A E — one lever bank at a time.
   ============================================================ */
const CIRCLE_INTRO = 'Built for a harp tuned to E♭ (B♭, E♭, A♭ — all levers down). From there you reach a continuous arc of eight keys, one lever bank at a time. Tap any key.';

/* pos 0 = top (C major), clockwise. accN = +sharps / −flats. lever = absolute setting from E♭ tuning. */
const CIRCLE_KEYS = [
  { pos:0,  maj:'C',  min:'Am',  acc:'no sharps or flats',     accN:0,  reach:true,  lever:'Raise the A, E and B levers — every string is now a natural.' },
  { pos:1,  maj:'G',  min:'Em',  acc:'1 sharp · F♯',           accN:1,  reach:true,  lever:'Raise A, E, B and the F levers (F♯).' },
  { pos:2,  maj:'D',  min:'Bm',  acc:'2 sharps · F♯ C♯',       accN:2,  reach:true,  lever:'Raise A, E, B, F and the C levers (F♯ C♯).' },
  { pos:3,  maj:'A',  min:'F♯m', acc:'3 sharps · F♯ C♯ G♯',    accN:3,  reach:true,  lever:'Raise A, E, B, F, C and the G levers (F♯ C♯ G♯).' },
  { pos:4,  maj:'E',  min:'C♯m', acc:'4 sharps · F♯ C♯ G♯ D♯', accN:4,  reach:true, edge:true, lever:'Raise A, E, B, F, C, G and the D levers (F♯ C♯ G♯ D♯). The far edge of the E♭ range — used sparingly.' },
  { pos:5,  maj:'B',  min:'G♯m', acc:'5 sharps · F♯ C♯ G♯ D♯ A♯',    accN:5,  reach:false, enh:'C♭', lever:'Beyond the E♭ lever range — would need retuning.' },
  { pos:6,  maj:'F♯', min:'D♯m', acc:'6 sharps · F♯ C♯ G♯ D♯ A♯ E♯', accN:6,  reach:false, enh:'G♭', lever:'Beyond the E♭ lever range — would need retuning.' },
  { pos:7,  maj:'D♭', min:'B♭m', acc:'5 flats · B♭ E♭ A♭ D♭ G♭',     accN:-5, reach:false, enh:'C♯', lever:'Beyond the E♭ lever range — would need retuning.' },
  { pos:8,  maj:'A♭', min:'Fm',  acc:'4 flats · B♭ E♭ A♭ D♭',        accN:-4, reach:false, lever:'Needs a 4-flat (A♭) tuning. Many UK harpers tune here, trading the key of E for A♭ and D♭.' },
  { pos:9,  maj:'E♭', min:'Cm',  acc:'3 flats · B♭ E♭ A♭',     accN:-3, reach:true, home:true, lever:'Home tuning — all levers down. This is where the harp rests.' },
  { pos:10, maj:'B♭', min:'Gm',  acc:'2 flats · B♭ E♭',        accN:-2, reach:true,  lever:'From E♭, raise just the A levers (A♭→A). Two flats remain: B♭, E♭.' },
  { pos:11, maj:'F',  min:'Dm',  acc:'1 flat · B♭',            accN:-1, reach:true,  lever:'Raise the A and E levers. One flat remains: B♭.' },
];

